    function actionSwapTokens() external inState(State.SwappingEnabled) {
        // Implement swapping logic
    }

    function approve(address spender, uint256 value) external inState(State.TradingOpened) {
        allowances[msg.sender][spender] = value;
        emit ApprovalEvent(msg.sender, spender, value);
    }
}

