        require(currentState == _state, "Invalid state");
        _;
    }

    constructor(string memory _baseURI) {
        baseURI = _baseURI;
        owner = msg.sender;
        currentState = State.NotStarted;
    }

    function startMinting() external onlyOwner inState(State.NotStarted) {
        currentState = State.MintingPhase;
    }

    function mintNFT() external inState(State.MintingPhase) {
        // Minting logic here
        emit Minted(msg.sender);
    }

    function buyBookToken() external inState(State.MintingPhase) {
        require(bookMinted < 100, "No more book tokens available");
        // Purchase logic here
        bookMinted++;
        emit BookMinted(msg.sender);
    }

    function buyMovieToken() external inState(State.MintingPhase) {
        require(movieMinted < 100, "No more movie tokens available");
        // Purchase logic here
        movieMinted++;
        emit MovieMinted(msg.sender);
    }

    function endMinting() external onlyOwner inState(State.MintingPhase) {
        currentState = State.MintingCompleted;
    }

    function grant(address recipient) external onlyOwner {
        // Reward granting logic here
        emit RewardReceived(recipient);
    }
}

