// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract UncensorablePostingContract {
    enum State { PostCreation, BoostingPhase, WithdrawalPhase }
    State public currentState;

    struct Post {
        uint totalPower;
        uint totalPoints;
    }

    mapping(address => uint) public balances;
    mapping(address => uint) public unclaimedAmounts;
    mapping(uint => Post) public posts;
    uint public postCount;

    event PostCreated(uint postId);
    event PostBoosted(uint postId, uint power);
    event Withdrawn(address indexed user, uint amount);

    constructor() {
        currentState = State.PostCreation;
    }

    modifier onlyInState(State expectedState) {
        require(currentState == expectedState, "Invalid state");
        _;
    }

    function mintPost() external onlyInState(State.PostCreation) {
        postCount++;
        posts[postCount] = Post(0, 0);
        emit PostCreated(postCount);
        currentState = State.BoostingPhase;
    }

    function boostPost(uint _postId, uint _power) external onlyInState(State.BoostingPhase) {
        require(_postId > 0 && _postId <= postCount, "Invalid post ID");
        posts[_postId].totalPower += _power;
        emit PostBoosted(_postId, _power);
    }

    function prepareWithdraw() external onlyInState(State.BoostingPhase) {
        currentState = State.WithdrawalPhase;
    }

    function withdrawBalance() external onlyInState(State.WithdrawalPhase) {
        uint amount = balances[msg.sender];
        require(amount > 0, "No balance to withdraw");
        balances[msg.sender] = 0;
        payable(msg.sender).transfer(amount);
        emit Withdrawn(msg.sender, amount);
        currentState = State.PostCreation;
    }

    function updateClaims() external {
        // Logic to update unclaimedAmounts can be added here
    }

    receive() external payable {
        balances[msg.sender] += msg.value;
    }
}

