pragma solidity ^0.8.9;

contract FetchInuToken {
    mapping(address => uint) private tokenBalances;
    mapping(address => mapping(address => uint)) private allowances;
    bool private tradingStatus;
    uint private transactionFees;

    enum State { preTrading, tradingEnabled, tradingRestricted }
    State public currentState;

    event Transfer(address indexed from, address indexed to, uint value);
    event Approval(address indexed owner, address indexed spender, uint value);

    constructor() {
        currentState = State.preTrading;
        tradingStatus = false;
        transactionFees = 0;
    }

    modifier onlyWhenTradingEnabled() {
        require(currentState == State.tradingEnabled, "Trading is disabled");
        _;
    }

    function enableTrading() external {
        require(currentState == State.preTrading, "Trading already enabled or restricted");
        currentState = State.tradingEnabled;
        tradingStatus = true;
    }

    function restrictTrading() external {
        require(currentState == State.tradingEnabled, "Trading is not enabled");
        currentState = State.tradingRestricted;
        tradingStatus = false;
    }

    function transfer(address to, uint amount) external onlyWhenTradingEnabled {
        require(tokenBalances[msg.sender] >= amount, "Insufficient balance");
        tokenBalances[msg.sender] -= amount;
        tokenBalances[to] += amount;
        emit Transfer(msg.sender, to, amount);
    }

    function approve(address spender, uint amount) external {
        allowances[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
    }

    function swapTokensForEth(uint amount) external onlyWhenTradingEnabled {
        // Swap logic (not implemented in this example)
    }

    // Additional functions to manage token balances, fees etc. can be added here
}

