contract NFTMintingContract {
    bool public publicSale;
    uint public nbFree;
    uint public nbFreeDone;
    string private _baseTokenURI;
    address public owner;

    enum State { PublicSaleInactive, FreeMinting, PublicSaleActive }
    State public currentState;

    modifier onlyOwner() {
        require(msg.sender == owner, "Not authorized");
        _;
    }

    constructor(uint _maxFreeMints, string memory baseTokenURI) {
        owner = msg.sender;
        nbFree = _maxFreeMints;
        _baseTokenURI = baseTokenURI;
        currentState = State.PublicSaleInactive;
    }

    function startFreeMinting() external onlyOwner {
        currentState = State.FreeMinting;
        emit StartFreeMinting();
    }

    function endFreeMinting() external onlyOwner {
        currentState = State.PublicSaleInactive;
        emit EndFreeMinting();
    }

    function startPublicSale() external onlyOwner {
        currentState = State.PublicSaleActive;
        emit StartPublicSale();
    }

    function endPublicSale() external onlyOwner {
        currentState = State.PublicSaleInactive;
        emit EndPublicSale();
    }

    function freeMint() external {
        require(currentState == State.FreeMinting, "Free minting not active");
        require(nbFreeDone < nbFree, "Free mint limit reached");
        // Logic for minting NFT goes here
        nbFreeDone++;
        emit MintFreeNFT(msg.sender);
    }

    function mint() external payable {
        require(currentState == State.PublicSaleActive, "Public sale not active");
        // Logic for checking payment and minting NFT goes here
        emit MintPublicNFT(msg.sender);
    }

    function withdrawMoney() external onlyOwner {
        payable(owner).transfer(address(this).balance);
    }

    // Events
    event StartFreeMinting();
    event EndFreeMinting();
    event StartPublicSale();
    event EndPublicSale();
    event MintFreeNFT(address indexed minter);
    event MintPublicNFT(address indexed minter);
}

