    event WithdrawAllEvent(uint256 amount);
    event ReceivedEther(uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    modifier whenActive() {
        require(state == State.Active, "Contract is not active");
        _;
    }

    constructor(address _openseaProxyRegistryAddress) {
        openseaProxyRegistryAddress = _openseaProxyRegistryAddress;
        owner = msg.sender;
        state = State.Active;
    }

    function mintTo(address to, uint256 tokenId) external whenActive {
        // Minting logic here
    }

    function burn(uint256 tokenId) external whenActive {
        // Burning logic here
    }

    function setBaseURI(string memory newBaseURI) external onlyOwner whenActive {
        baseURIString = newBaseURI;
        emit SetBaseURIEvent(newBaseURI);
    }

    function freezeContract() external onlyOwner {
        state = State.Frozen;
    }

    function unfreezeContract() external onlyOwner {
        state = State.Active;
    }

    function withdrawAll() external onlyOwner whenActive {
        uint256 balance = address(this).balance;
        payable(owner).transfer(balance);
        emit WithdrawAllEvent(balance);
    }

    receive() external payable {
        emit ReceivedEther(msg.value);
    }
}

