    event SwapAndLiquify(uint tokensSwapped, uint ethReceived, uint tokensIntoLiquidity);
    event RewardsTransferred(address indexed user, uint amount);

    constructor(address _uniswapRouter, address _uniswapPair) {
        uniswapRouter = _uniswapRouter;
        uniswapPair = _uniswapPair;
        currentState = State.MintingPhase;
    }

    modifier onlyMinter() {
        require(mintersList[msg.sender], "Not a minter");
        _;
    }

    function addMinter(address _minter) external {
        mintersList[_minter] = true;
    }

    function removeMinter(address _minter) external {
