import "@openzeppelin/contracts/access/Ownable.sol";

contract SonOfKarenToken is ERC20, Ownable {
    uint256 private _tTotal = 1000000 * 10**18;
    mapping(address => uint256) private _rOwned;
    address public marketingWallet = 0x1234567890abcdef1234567890abcdef12345678;
    address public liquidityWallet = 0xabcdef1234567890abcdef1234567890abcdef12;

    bool public tradingEnabled = false;

    event LaunchEvent();
    event EnableTradingEvent();
    event TransferEvent(address indexed from, address indexed to, uint256 value);
    event AirdropEvent(address indexed recipient, uint256 amount);
    event SwapAndLiquifyEvent(uint256 tokensSwapped, uint256 ethReceived);

    constructor() ERC20("Son Of $Karen", "KAREN") {
        _rOwned[msg.sender] = _tTotal;
        emit Transfer(address(0), msg.sender, _tTotal);
    }

    modifier tradingIsEnabled() {
        require(tradingEnabled, "Trading is not enabled yet.");
        _;
    }

    function setTradingEnabled() external onlyOwner {
        tradingEnabled = true;
        emit EnableTradingEvent();
    }

    function enableTrading() external onlyOwner {
        tradingEnabled = true;
        emit LaunchEvent();
    }

    function _transfer(address from, address to, uint256 amount) internal virtual override tradingIsEnabled {
        require(from != address(0), "ERC20: transfer from the zero address");
        require(to != address(0), "ERC20: transfer to the zero address");
        require(amount <= _rOwned[from], "ERC20: transfer amount exceeds balance");

        _rOwned[from] -= amount;
        _rOwned[to] += amount;
        emit Transfer(from, to, amount);
    }

    function airdropTokens(address[] calldata recipients, uint256 amount) external onlyOwner {
        for (uint256 i = 0; i < recipients.length; i++) {
            _transfer(msg.sender, recipients[i], amount);
            emit AirdropEvent(recipients[i], amount);
        }
    }

    function swapAndLiquify(uint256 amount) external onlyOwner {
        // Placeholder for the swap and liquify logic
        emit SwapAndLiquifyEvent(amount, amount); // Sample logging
    }
}

