// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract CakeVault {
    // State enumeration
    enum State { Active, Paused, EmergencyWithdraw }
    State public currentState;

    // Variables
    mapping(address => uint) public userInfo;
    uint public totalShares;
    uint public performanceFee = 20; // represented in basis points
    uint public callFee = 5; // represented in basis points
    uint public withdrawFee = 10; // represented in basis points

    // Events
    event Deposit(address indexed user, uint amount);
    event Withdraw(address indexed user, uint amount);
    event Harvest(address indexed user);
    event Pause();
    event Unpause();
    event RescueTokens(address indexed user, uint amount);

    constructor() {
        currentState = State.Active;
    }

    // Deposit tokens
    function depositTokens(uint amount) external {
        require(currentState == State.Active, "Contract is not active");
        userInfo[msg.sender] += amount;
        totalShares += amount;
        emit Deposit(msg.sender, amount);
    }

    // Withdraw tokens
    function withdrawTokens(uint amount) external {
        require(currentState == State.Active, "Contract is not active");
        require(userInfo[msg.sender] >= amount, "Insufficient balance");

        uint fee = calculateFee(amount);
        userInfo[msg.sender] -= amount;
        totalShares -= amount;
        emit Withdraw(msg.sender, amount);
        // Transfer amount - fee to user (implementation required)
    }

    // Harvest rewards
    function harvestRewards() external {
        require(currentState == State.Active, "Contract is not active");
        // Logic to harvest rewards from the MasterChef contract (implementation required)
        emit Harvest(msg.sender);
    }

    // Pause the contract
    function pauseContract() external {
        require(currentState == State.Active, "Contract must be active to pause");
        currentState = State.Paused;
        emit Pause();
    }

    // Unpause the contract
    function unpauseContract() external {
        require(currentState == State.Paused, "Contract must be paused to unpause");
        currentState = State.Active;
        emit Unpause();
    }

    // Emergency withdraw
    function rescueTokens(uint amount) external {
        require(currentState == State.Active || currentState == State.Paused, "Contract is not in a state for emergency withdraw");
        currentState = State.EmergencyWithdraw;
        userInfo[msg.sender] -= amount;
        emit RescueTokens(msg.sender, amount);
        // Transfer tokens to user (implementation required)
    }

    // Calculate withdrawal fee
    function calculateFee(uint amount) internal view returns (uint) {
        return (amount * withdrawFee) / 100; // Assuming withdrawFee is in basis points
    }

    // Reset state after emergency withdrawal
    function resetState() external {
        require(currentState == State.EmergencyWithdraw, "Not in emergency withdraw state");
        currentState = State.Active;
    }
}

