    uint public transactionLimit = 1000;

    event TokenTransferred(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event TransactionLimitChanged(uint256 newLimit);

    constructor(uint256 _totalSupply) {
        totalSupply = _totalSupply;
        balances[msg.sender] = _totalSupply; // Assign total supply to the contract's creator
    }

    modifier onlyWhenOpen() {
        require(tradingOpen, "Trading is closed");
        _;
    }

    function setTradingOpen() external {
        tradingOpen = true;
    }

    function setTradingClosed() external {
        tradingOpen = false;
    }

    function transferTokens(address _to, uint256 _amount) external onlyWhenOpen {
        require(_amount <= transactionLimit, "Exceeds transaction limit");
        require(balances[msg.sender] >= _amount, "Insufficient balance");

        balances[msg.sender] -= _amount;
        balances[_to] += _amount;
        emit TokenTransferred(msg.sender, _to, _amount);
    }

    function approveAllowance(address _spender, uint256 _amount) external {
        allowances[msg.sender][_spender] = _amount;
        emit Approval(msg.sender, _spender, _amount);
    }

    function swapTokens(uint256 _amount) external onlyWhenOpen {
        // Placeholder for token swap implementation
    }

    function changeTransactionLimit(uint256 _newLimit) external {
        transactionLimit = _newLimit;
        emit TransactionLimitChanged(_newLimit);
    }
}

