pragma solidity ^0.8.11;

contract TokenMintingClaimingContract {
    address public ORIGINAL_CONTRACT;
    uint public ORIGINAL_PRICE;
    uint public PRICE;

    mapping(address => uint) public TIMES_CLAIMED;

    enum State { MintingDisabled, MintingEnabled, TokenClaimed }
    State public currentState;

    modifier onlyOwner() {
        require(msg.sender == ORIGINAL_CONTRACT, "Not the owner");
        _;
    }

    event Minting();
    event ClaimingTokens(address indexed claimant);
    event ChangesToMintingParameters();

    constructor(address _originalContract, uint _originalPrice, uint _price) {
        ORIGINAL_CONTRACT = _originalContract;
        ORIGINAL_PRICE = _originalPrice;
        PRICE = _price;
        currentState = State.MintingDisabled;
    }

    function enableMinting() public onlyOwner {
        require(currentState == State.MintingDisabled, "Minting already enabled");
        currentState = State.MintingEnabled;
    }

    function disableMinting() public onlyOwner {
        require(currentState == State.MintingEnabled, "Minting already disabled");
        currentState = State.MintingDisabled;
    }

    function mint() public {
        require(currentState == State.MintingEnabled, "Minting is disabled");
        // Mint logic here
        emit Minting();
    }

    function claim() public onlyOwner {
        require(currentState == State.MintingEnabled, "Cannot claim now");
        // Claim logic here
        TIMES_CLAIMED[msg.sender]++;
        currentState = State.TokenClaimed;
        emit ClaimingTokens(msg.sender);
    }

    function claimAll() public onlyOwner {
        require(currentState == State.TokenClaimed, "No tokens to claim");
        // Logic to claim multiple tokens here
        emit ClaimingTokens(msg.sender);
    }

    function setClaimParameters(uint _newPrice) public onlyOwner {
        PRICE = _newPrice;
        emit ChangesToMintingParameters();
    }
}

