pragma solidity ^0.8.7;

contract TokenContract {
    uint[] public tokenIds;
    bool public saleStatus = false;
    uint public mintPrice = 0;
    mapping(address => uint) public mintedCountPerAddress;
    address public owner;

    event TokenMinted(address indexed to, uint tokenId);
    event SaleStatusChanged(bool newStatus);
    event MetadataRevealed(string metadata);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    modifier isSaleActive() {
        require(saleStatus, "Sale is not active");
        _;
    }

    modifier hasMintAllowance() {
        require(mintedCountPerAddress[msg.sender] < 5, "Mint limit exceeded");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function setSaleStatus(bool _status) external onlyOwner {
        saleStatus = _status;
        emit SaleStatusChanged(_status);
    }

    function mintToken() external payable isSaleActive hasMintAllowance {
        require(msg.value >= mintPrice, "Insufficient funds");
        uint tokenId = tokenIds.length;
        tokenIds.push(tokenId);
        mintedCountPerAddress[msg.sender]++;
        emit TokenMinted(msg.sender, tokenId);
    }

    function revealMetadata(string calldata _metadata) external onlyOwner {
        emit MetadataRevealed(_metadata);
    }

    function withdrawFunds() external onlyOwner {
        payable(owner).transfer(address(this).balance);
    }
}

