contract NFTMintingContract {
    uint public NFT_PRICE;
    uint public MAX_SUPPLY;
    bool public saleIsActive;
    uint public startingIndex;
    string public _baseURIExtended;

    event SaleStateChange(bool newState);
    event TokenMinted(address owner, uint tokenId);

    constructor(uint _nftPrice, uint _maxSupply, string memory baseURI) {
        NFT_PRICE = _nftPrice;
        MAX_SUPPLY = _maxSupply;
        _baseURIExtended = baseURI;
        saleIsActive = false;
        startingIndex = 0;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Caller is not the owner");
        _;
    }

    function flipSaleState() public onlyOwner {
        saleIsActive = !saleIsActive;
        emit SaleStateChange(saleIsActive);
    }

    function mint() public payable {
        require(saleIsActive, "Sale is not active");
        require(msg.value == NFT_PRICE, "Incorrect ETH amount");
        require(totalSupply() + 1 <= MAX_SUPPLY, "Max supply reached");

        // Logic to mint token
        emit TokenMinted(msg.sender, tokenId);
    }

    function mint5() public payable {
        require(saleIsActive, "Sale is not active");
        require(msg.value == NFT_PRICE * 5, "Incorrect ETH amount");
        require(totalSupply() + 5 <= MAX_SUPPLY, "Max supply reached");

        for (uint i = 0; i < 5; i++) {
            // Logic to mint token
            emit TokenMinted(msg.sender, tokenId);
        }
    }

    function reserveTokens(uint numberOfTokens) public onlyOwner {
        require(totalSupply() + numberOfTokens <= MAX_SUPPLY, "Max supply reached");
        // Logic to reserve tokens
    }

    function setBaseURI(string memory baseURI) public onlyOwner {
        _baseURIExtended = baseURI;
    }

    function totalSupply() public view returns (uint) {
        // Logic to return total supply of minted tokens
    }
}

