// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract NFTMintingContract {
    uint public constant MAX_SUPPLY = 1000;
    uint public constant COST = 0.05 ether;
    uint public TEAM_RESERVE_AVAILABLE_MINTS = 100;

    enum State { PresaleInactive, PresaleActive, SaleInactive, SaleActive }
    State public currentState;

    mapping(address => bool) public presaleWhitelist;
    mapping(address => uint) public presaleMints;

    event NFTMinted(address indexed minter);
    event PresaleStateChanged(State newState);
    event SaleStateChanged(State newState);

    constructor() {
        currentState = State.PresaleInactive;
    }

    modifier onlyOwner() {
        // Assuming there's an owner mechanism implemented
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    modifier inState(State _state) {
        require(currentState == _state, "Invalid state");
        _;
    }

    function togglePresale() external onlyOwner {
        if (currentState == State.PresaleInactive) {
            currentState = State.PresaleActive;
        } else {
            currentState = State.PresaleInactive;
        }
        emit PresaleStateChanged(currentState);
    }

    function toggleSale() external onlyOwner {
        if (currentState == State.SaleInactive) {
            currentState = State.SaleActive;
        } else {
            currentState = State.SaleInactive;
        }
        emit SaleStateChanged(currentState);
    }

    function mint() external payable inState(State.SaleActive) {
        require(msg.value == COST, "Incorrect value sent");
        // Minting logic
        emit NFTMinted(msg.sender);
    }

    function mintPresale() external payable inState(State.PresaleActive) {
        require(presaleWhitelist[msg.sender], "Not whitelisted");
        require(presaleMints[msg.sender] < 1, "Mint limit reached"); // Limit to 1 for presale
        require(msg.value == COST, "Incorrect value sent");
        presaleMints[msg.sender]++;
        // Minting logic
        emit NFTMinted(msg.sender);
    }

    function addToWhitelist(address _address) external onlyOwner {
        presaleWhitelist[_address] = true;
    }

    function withdraw() external onlyOwner {
        payable(owner).transfer(address(this).balance);
    }
}

