pragma solidity ^0.8.9;

contract DigitalMediaToken {
    enum State { MediaCreation, MediaUpdatable, MediaImmutable }
    State public currentState;

    uint public onchainId;
    uint public totalSupply;
    address public creator;
    uint public royalty;

    event DigitalMediaUpdateEvent();
    event MediaImmutableEvent();
    event MediasImmutableEvent();

    modifier onlyInState(State _state) {
        require(currentState == _state, "Invalid state for this operation.");
        _;
    }

    constructor() {
        currentState = State.MediaCreation;
    }

    function createDigitalMediaAndReleases() public onlyInState(State.MediaCreation) {
        // Logic for creating digital media and releases
        creator = msg.sender;
        totalSupply += 1; // Increment totalSupply for the new token
        onchainId = totalSupply; // Assign onchainId for the new token
        currentState = State.MediaUpdatable; // Transition to MediaUpdatable state
    }

    function updateMedia() public onlyInState(State.MediaUpdatable) {
        // Logic for updating the digital media information
        emit DigitalMediaUpdateEvent();
        // Remain in MediaUpdatable state
    }

    function makeMediaImmutable() public onlyInState(State.MediaUpdatable) {
        currentState = State.MediaImmutable; // Transition to MediaImmutable state
        emit MediaImmutableEvent();
    }

    function royaltyInfo() public view returns (uint) {
        return royalty; // Return the royalty information
    }
}

