    mapping(address => uint) public accounts;

    event Mint(address indexed to, uint256 tokenId);
    event PermanentURI(string _value, uint256 indexed _id);
    event Burn(address indexed owner, uint256 indexed tokenId);

    constructor() {
        currentState = State.PreSaleActive;
    }

    modifier onlyWhileState(State _state) {
        require(currentState == _state, "Invalid state for this action");
        _;
    }

    function mint() external payable onlyWhileState(State.PreSaleActive) {
        require(msg.value == PRESALEPRICE, "Incorrect Ether value");
        // Minting logic here
        emit Mint(msg.sender, /* tokenId */ 1); // Example tokenId
    }

    function activatePublicSale() external onlyWhileState(State.PreSaleActive) {
        currentState = State.SaleActive;
    }

    function deactivateSale() external onlyWhileState(State.SaleActive) {
        currentState = State.SaleInactive;
