    State public currentState;

    event ChangeMintableNFT(address indexed newMintableNFT);
    event UpdatePrice(uint indexed newPrice);
    event CollectETHs(address indexed collector, uint amount);

    constructor() {
        currentState = State.InitialSetup;
        roundIndex = 0;
        price = 0;
    }

    modifier onlyInState(State _state) {
        require(currentState == _state, "Invalid state for this operation.");
        _;
    }

    function setMintableNFT(address _mintableNFT) external onlyInState(State.InitialSetup) {
        mintableNFT = _mintableNFT;
        currentState = State.BuyingPhase;
        emit ChangeMintableNFT(mintableNFT);
    }

    function processPurchase() external payable onlyInState(State.BuyingPhase) {
        require(msg.value >= price, "Insufficient Ether sent.");
        // Logic to mint NFT goes here
    }

    function fUpdatePrice(uint _newPrice) external onlyInState(State.BuyingPhase) {
        price = _newPrice;
        emit UpdatePrice(price);
    }

    function logPurchases() external onlyInState(State.BuyingPhase) {
        // Logic to log purchases goes here
        currentState = State.Finalization;
    }

    function collectFunds() external onlyInState(State.Finalization) {
        uint amount = address(this).balance;
        payable(msg.sender).transfer(amount);
        emit CollectETHs(msg.sender, amount);
    }
}

