contract NFTMintingContract {
    uint public maxPerTx = 5;
    uint public cost = 1;
    uint public freeTotal = 0;
    bool public isMintActive = false;
    uint public totalAvailable = 100;

    enum State { MintingInactive, MintingActive, SoldOut }
    State public currentState = State.MintingInactive;

    event MintingSuccess(address indexed user, uint quantity);
    event ReserveSuccess(address indexed user, uint quantity);
    event StateChange(State newState);

    modifier onlyWhenMintingActive() {
        require(isMintActive, "Minting is not active.");
        _;
    }

    modifier onlyWhenSupplyAvailable(uint quantity) {
        require(totalAvailable >= quantity, "Not enough tokens available.");
        _;
    }

    function mint(uint quantity) external onlyWhenMintingActive onlyWhenSupplyAvailable(quantity) {
        require(quantity <= maxPerTx, "Exceeds max tokens per transaction.");
        totalAvailable -= quantity;
        emit MintingSuccess(msg.sender, quantity);

        // Check if supply limit reached and transition state if necessary
        if (totalAvailable == 0) {
            currentState = State.SoldOut;
            emit StateChange(currentState);
        }
    }

    function reserve(uint quantity) external {
        // Implementation for reserving tokens (not fully specified in FSM)
        emit ReserveSuccess(msg.sender, quantity);
    }

    function setCost(uint newCost) external {
        cost = newCost;
    }

    function flipMintState() external {
        if (currentState == State.MintingInactive) {
            isMintActive = true;
            currentState = State.MintingActive;
        } else if (currentState == State.MintingActive) {
            isMintActive = false;
            currentState = State.MintingInactive;
        }
        emit StateChange(currentState);
    }

    function withdraw() external {
        // Withdraw implementation (not specified in FSM)
    }
}

