// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract NFTTokenContract {
    // State variables
    uint public cost = 0;
    uint public maxSupply = 1000;
    mapping(address => bool) public whitelistedAddresses;
    mapping(address => uint) public addressMintedBalance;

    enum State { Paused, MintingOpen, Revealed }
    State public currentState;

    // Events
    event NFTMinted(address indexed user, uint indexed amount);
    event MetadataRevealed(string metadata);
    event ContractPausedOrResumed(string status);

    // Constructor
    constructor() {
        currentState = State.Paused;
    }

    // Modifier to check state
    modifier inState(State _state) {
        require(currentState == _state, "Invalid state for this action");
        _;
    }

    // Function to mint NFTs
    function mintNFT(uint amount) external payable inState(State.MintingOpen) {
        require(whitelistedAddresses[msg.sender], "You are not whitelisted");
        require(addressMintedBalance[msg.sender] + amount <= 1, "Minting limit exceeded");
        require(msg.value >= cost * amount, "Insufficient funds");

        addressMintedBalance[msg.sender] += amount;
        emit NFTMinted(msg.sender, amount);
    }

    // Function to complete minting
    function completeMinting() external inState(State.MintingOpen) {
        currentState = State.Revealed;
        emit ContractPausedOrResumed("Minting completed, NFT metadata can now be revealed");
    }

    // Function to pause minting
    function pauseMinting() external {
        currentState = State.Paused;
        emit ContractPausedOrResumed("Minting paused");
    }

    // Function to resume minting
    function resumeMinting() external {
        currentState = State.MintingOpen;
        emit ContractPausedOrResumed("Minting resumed");
    }

    // Function to reveal metadata
    function revealMetadata(string calldata metadata) external inState(State.Revealed) {
        emit MetadataRevealed(metadata);
    }
}

