// SPDX-License-Identifier: MIT
pragma solidity ^0.8.9;

contract NFTTokenContract {
    uint public constant MAX_NFTS = 10000;
    uint public constant PRICE = 0.05 ether;
    string public baseURI;
    mapping(address => uint) public usedDoods;

    enum State { MintingPhase, URISetupPhase, BurnPhase }
    State public currentState;

    event NFTMinted(address indexed to, uint tokenId);
    event URISet(string uri);
    event NFTBurned(address indexed owner, uint tokenId);

    constructor() {
        currentState = State.MintingPhase;
    }

    modifier isMinting() {
        require(currentState == State.MintingPhase, "Not in minting phase");
        _;
    }

    modifier isURISetup() {
        require(currentState == State.URISetupPhase, "Not in URI setup phase");
        _;
    }

    function mintNFT() external payable isMinting {
        require(msg.value >= PRICE, "Insufficient payment");
        // Logic to mint the NFT
        emit NFTMinted(msg.sender, /* tokenId */ 0);
    }

    function mintReserved() external isMinting {
        // Logic to mint a reserved NFT
        emit NFTMinted(msg.sender, /* tokenId */ 0);
    }

    function finalizeURI(string memory _baseURI) external isURISetup {
        baseURI = _baseURI;
        emit URISet(_baseURI);
        currentState = State.MintingPhase;
    }

    function burnMaleNFT(uint tokenId) external isMinting {
        // Logic to burn male NFT
        emit NFTBurned(msg.sender, tokenId);
        currentState = State.BurnPhase;
    }

    function createFemaleNFT() external {
        require(currentState == State.BurnPhase, "Not in burn phase");
        // Logic to create female NFT
        currentState = State.MintingPhase;
    }

    function setURI() external isMinting {
        currentState = State.URISetupPhase;
    }
}

