// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract NFTMintingContract {
    uint public cost;
    uint public maxSupply;
    mapping(address => bool) public whitelistedAddresses;
    bool public revealed;

    enum State { Paused, MintingActive, Revealed }
    State public currentState;

    event NFTMinted(address indexed sender, uint indexed tokenId);
    event StateChanged(State newState);
    event OwnershipVerified(address indexed owner);

    constructor(uint _cost, uint _maxSupply) {
        cost = _cost;
        maxSupply = _maxSupply;
        currentState = State.Paused;
    }

    modifier onlyWhitelisted() {
        require(whitelistedAddresses[msg.sender], "Not whitelisted");
        _;
    }

    modifier inState(State state) {
        require(currentState == state, "Invalid state transition");
        _;
    }

    function setMintingParameters(uint _cost, uint _maxSupply) external inState(State.Paused) {
        cost = _cost;
        maxSupply = _maxSupply;
        emit StateChanged(State.MintingActive);
        currentState = State.MintingActive;
    }

    function mintNFT() external payable inState(State.MintingActive) onlyWhitelisted {
        require(msg.value >= cost, "Insufficient funds");
        // Logic to mint NFT goes here
        emit NFTMinted(msg.sender, /* tokenId */ 0);
    }

    function revealNFTs() external inState(State.MintingActive) {
        revealed = true;
        emit StateChanged(State.Revealed);
        currentState = State.Revealed;
    }

    function pauseMinting() external inState(State.MintingActive) {
        emit StateChanged(State.Paused);
        currentState = State.Paused;
    }

    function whitelistUser(address user) external {
        whitelistedAddresses[user] = true;
    }
}

