// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract TokenContract {
    string public tokenName = "MyToken";
    string public symbol = "MTK";
    uint public totalSupply = 1000000;
    uint public taxFee = 5; // 5%
    uint public marketingFee = 3; // 3%

    mapping(address => uint) public balances;
    mapping(address => bool) public blacklisted;
    address public marketingWallet;

    enum State { Active, SwappingForETH, Blacklisted }
    State public currentState;

    event Transfer(address indexed from, address indexed to, uint value);
    event Approval(address indexed owner, address indexed spender, uint value);
    event SwapAndSendEnabledUpdated(bool enabled);

    constructor(address _marketingWallet) {
        marketingWallet = _marketingWallet;
        currentState = State.Active;
        balances[msg.sender] = totalSupply; // Assign total supply to contract creator
    }

    modifier notBlacklisted() {
        require(currentState != State.Blacklisted, "Address is blacklisted");
        _;
    }

    function transferTokens(address to, uint amount) external notBlacklisted {
        require(balances[msg.sender] >= amount, "Not enough tokens");
        uint fee = (amount * taxFee) / 100;
        balances[msg.sender] -= amount;
        balances[to] += (amount - fee);
        balances[marketingWallet] += fee; // Send fee to marketing wallet

        emit Transfer(msg.sender, to, amount);
    }

    function approve(address spender, uint amount) external {
        emit Approval(msg.sender, spender, amount);
    }

    function swapTokens() external {
        // Logic to swap tokens for ETH
        currentState = State.SwappingForETH;
    }

    function completeSwap() external {
        // Logic to complete the swap and send to marketing wallet
        currentState = State.Active;
        // send proceeds to marketingWallet
    }

    function blacklistAddress(address account) external {
        blacklisted[account] = true;
        currentState = State.Blacklisted;
    }

    function removeFromBlacklist(address account) external {
        blacklisted[account] = false;
        if (currentState == State.Blacklisted && !blacklisted[account]) {
            currentState = State.Active;
        }
    }
}

