// SPDX-License-Identifier: MIT
pragma solidity ^0.8.9;

contract TokenContract {
    uint public MINT_BATCH_SIZE = 5;
    uint public N_TOTAL = 0;
    uint public basePrice = 0;
    bool public hasPreminted = false;

    address public owner;

    enum State { Preminting, PublicMinting, TokenTransfer }
    State public currentState;

    event TokenMinted(address indexed to, uint amount);
    event TokenTransferred(address indexed from, address indexed to, uint amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    constructor() {
        owner = msg.sender;
        currentState = State.Preminting;
    }

    function setBasePrice(uint _basePrice) external onlyOwner {
        basePrice = _basePrice;
    }

    function canMint() public view returns (bool) {
        // Logic to determine if the user can mint tokens
        return currentState == State.PublicMinting && N_TOTAL + MINT_BATCH_SIZE <= 100; // Example limit
    }

    function ownerMint(uint _amount) external onlyOwner {
        require(currentState == State.Preminting, "Not in Preminting state");
        // Minting logic here
        N_TOTAL += _amount;
        hasPreminted = true;
        if (N_TOTAL > 0) {
            currentState = State.PublicMinting;
        }
        emit TokenMinted(msg.sender, _amount);
    }

    function publicMint(uint _amount) external payable {
        require(currentState == State.PublicMinting, "Not in PublicMinting state");
        require(canMint(), "Cannot mint tokens");

        // Check payment
        require(msg.value >= basePrice * _amount, "Insufficient payment");

        N_TOTAL += _amount;
        emit TokenMinted(msg.sender, _amount);
    }

    function safeTransferFromBatch(address _to, uint _amount) external {
        require(currentState == State.PublicMinting || currentState == State.TokenTransfer, "Not in transfer state");

        // Transfer logic here
        emit TokenTransferred(msg.sender, _to, _amount);
    }

    function backToMinting() external {
        require(currentState == State.TokenTransfer, "Not in TokenTransfer state");
        currentState = State.PublicMinting;
    }
}

