pragma solidity ^0.8.10;

contract NFTMintingContract {
    string public baseURI;
    uint public cost = 0;
    uint public maxSupply = 1000;

    enum State {Paused, MintingPhase, Revealed}
    State public currentState;

    mapping(address => bool) public whitelistedAddresses;
    mapping(address => uint) public addressMintedBalance;

    event NFTMinted(address indexed owner, uint quantity);
    event RevealExecuted(string newBaseURI);
    event AirdropCompleted(address indexed recipient, uint quantity);

    constructor() {
        currentState = State.Paused;
    }

    modifier onlyPaused() {
        require(currentState == State.Paused, "Contract is not paused.");
        _;
    }

    modifier onlyMintingPhase() {
        require(currentState == State.MintingPhase, "Minting phase is not active.");
        _;
    }

    modifier onlyRevealed() {
        require(currentState == State.Revealed, "Metadata is not revealed.");
        _;
    }

    function startMinting() external onlyPaused {
        currentState = State.MintingPhase;
    }

    function mintNFTPublic(uint quantity) external payable onlyMintingPhase {
        require(addressMintedBalance[msg.sender] + quantity <= maxSupply, "Exceeds max supply.");
        require(msg.value >= cost * quantity, "Ether sent is not sufficient.");

        addressMintedBalance[msg.sender] += quantity;
        emit NFTMinted(msg.sender, quantity);
    }

    function mintNFTWhitelist(uint quantity) external payable onlyMintingPhase {
        require(whitelistedAddresses[msg.sender], "Address not whitelisted.");
        require(addressMintedBalance[msg.sender] + quantity <= maxSupply, "Exceeds max supply.");
        require(msg.value >= cost * quantity, "Ether sent is not sufficient.");

        addressMintedBalance[msg.sender] += quantity;
        emit NFTMinted(msg.sender, quantity);
    }

    function revealNFTMetadata(string memory newBaseURI) external onlyMintingPhase {
        currentState = State.Revealed;
        baseURI = newBaseURI;
        emit RevealExecuted(newBaseURI);
    }

    function addToWhitelist(address[] calldata addresses) external onlyPaused {
        for (uint i = 0; i < addresses.length; i++) {
            whitelistedAddresses[addresses[i]] = true;
        }
    }

    function completeAirdrop(address recipient, uint quantity) external onlyRevealed {
        // Airdrop logic here
        emit AirdropCompleted(recipient, quantity);
    }
}

