pragma solidity ^0.8.0;

contract TokenContract {
    string public tokenBaseURI;
    mapping(uint => bool) public specials;
    uint public regularPrice;
    uint public specialPrice;

    enum State { Active, Paused }
    State public currentState;

    address public owner;

    event TokenPurchase(address indexed buyer, uint tokenId);
    event SpecialTokenMarking(uint tokenId, bool isSpecial);
    event ContractStateChange(State newState);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    modifier isActive() {
        require(currentState == State.Active, "Contract is paused");
        _;
    }

    constructor(string memory _tokenBaseURI, uint _regularPrice, uint _specialPrice) {
        tokenBaseURI = _tokenBaseURI;
        regularPrice = _regularPrice;
        specialPrice = _specialPrice;
        currentState = State.Active;
        owner = msg.sender;
    }

    function buy(uint tokenId) external payable isActive {
        require(msg.value >= regularPrice, "Insufficient funds");
        emit TokenPurchase(msg.sender, tokenId);
    }

    function changeBaseURI(string memory newBaseURI) external onlyOwner {
        tokenBaseURI = newBaseURI;
    }

    function markSpecial(uint tokenId) external onlyOwner {
        specials[tokenId] = true;
        emit SpecialTokenMarking(tokenId, true);
    }

    function unmarkSpecial(uint tokenId) external onlyOwner {
        specials[tokenId] = false;
        emit SpecialTokenMarking(tokenId, false);
    }

    function changeRegularPrice(uint newPrice) external onlyOwner {
        regularPrice = newPrice;
    }

    function changeSpecialPrice(uint newPrice) external onlyOwner {
        specialPrice = newPrice;
    }

    function pause() external onlyOwner {
        currentState = State.Paused;
        emit ContractStateChange(currentState);
    }

    function unpause() external onlyOwner {
        currentState = State.Active;
        emit ContractStateChange(currentState);
    }

    function withdraw() external onlyOwner {
        payable(owner).transfer(address(this).balance);
    }
}

