    enum State { EarlyAccessSale, PublicSale, TokenMinting }
    State public currentState;

    event TokenPurchase(address indexed buyer, uint amount);
    event WindowUpdate(string stage, uint newTime);
    event MintingComplete();

    constructor() {
        currentState = State.EarlyAccessSale;
    }

    modifier onlyOwner() {
        // Implementation of ownership check goes here
        _;
    }

    modifier validMerkleProof() {
        // Implementation of merkle proof validation goes here
        _;
    }

    modifier withinPurchaseLimit() {
        // Implementation of purchase limit check goes here
        _;
    }

    function editMerkleRoot(string calldata _merkleRoot) external onlyOwner {
        // Logic to set Merkle root
        emit WindowUpdate("MerkleRoot", block.timestamp);
    }

    function earlyAccessSale(uint amount) external validMerkleProof {
        require(currentState == State.EarlyAccessSale, "Not in early access sale phase");
        // Logic for minting tokens for early access users
        purchased[msg.sender] += amount;
        emit TokenPurchase(msg.sender, amount);
    }

    function purchase(uint amount) external withinPurchaseLimit {
        require(currentState == State.PublicSale, "Not in public sale phase");
        // Logic for purchasing tokens in public sale
        purchased[msg.sender] += amount;
        emit TokenPurchase(msg.sender, amount);
    }

    function mintingComplete() external {
        require(currentState == State.PublicSale, "Not in public sale phase");
        currentState = State.TokenMinting;
        emit MintingComplete();
    }

    function withdrawFunds() external onlyOwner {
        // Logic to withdraw funds
    }

    function updateSaleWindow() external onlyOwner {
        currentState = State.PublicSale;
        purchaseWindowOpensPublic = true;
        emit WindowUpdate("PublicSale", block.timestamp);
    }

    function resetSaleStates() external onlyOwner {
        currentState = State.EarlyAccessSale;
        delete purchased;
        purchaseWindowOpensPublic = false;
    }
}

