    constructor() ERC20("Musk Album", "MUSKALBUM") {
        _mint(msg.sender, _tTotal);
        currentState = State.TradingDisabled;
    }

    modifier whenTradingEnabled() {
        require(currentState == State.TradingEnabled, "Trading is disabled");
        _;
    }

    function allowTrading() external onlyOwner {
        currentState = State.TradingEnabled;
    }

    function excludeFromFee() external onlyOwner {
        // Implement fee adjustment logic here
    }

    function transfer(address recipient, uint256 amount) public override whenTradingEnabled returns (bool) {
        require(amount <= _maxTxAmount, "Transfer amount exceeds the maxTxAmount.");
        _transfer(_msgSender(), recipient, amount);
        emit Transfer(_msgSender(), recipient, amount);
        return true;
    }

    function approve(address spender, uint256 amount) public override whenTradingEnabled returns (bool) {
        _approve(_msgSender(), spender, amount);
        emit Approval(_msgSender(), spender, amount);
        return true;
    }

    function airdrop(address[] calldata recipients, uint256 amount) external onlyOwner {
        for (uint256 i = 0; i < recipients.length; i++) {
            _transfer(msg.sender, recipients[i], amount);
        }
    }

    function setMaxTxAmount(uint256 maxTxAmount) external onlyOwner {
        _maxTxAmount = maxTxAmount;
    }

    function adjustFees() external onlyOwner {
        // Implement fee adjustment logic here
    }

    function executeTransfer(address sender, address recipient, uint256 amount) internal {
        _transfer(sender, recipient, amount);
    }

    function executeApproval(address owner, address spender, uint256 value) internal {
        _approve(owner, spender, value);
    }

    function performAirdrop(address[] calldata recipients, uint256 amount) internal {
        for (uint256 i = 0; i < recipients.length; i++) {
            _transfer(msg.sender, recipients[i], amount);
        }
    }

    function updateMaxTxAmount(uint256 maxTxAmount) external onlyOwner {
        _maxTxAmount = maxTxAmount;
    }
}

