contract BatchClaimContract {
    address public owner;
    enum State { Active, Terminated }
    State public state;

    event ClaimExecuted(address claimant, uint256 amount);
    event ContractTerminated();

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    modifier inActiveState() {
        require(state == State.Active, "Contract is terminated");
        _;
    }

    constructor() {
        owner = msg.sender;
        state = State.Active;
    }

    function batchClaim(uint256 amount) external inActiveState {
        // Logic for batch claiming rewards
        emit ClaimExecuted(msg.sender, amount);
    }

    function kill() external onlyOwner inActiveState {
        state = State.Terminated;
        emit ContractTerminated();
    }
}

