contract Marnotaurs is ERC721Enumerable, Ownable {

    struct Partners {
        uint256 limit;
        uint256 nftMinted;
    }

    struct Upgrade {
        uint256 priceETH;
        uint256 limit;   // 0 - unlimited
        uint256 count;   // How much upgraded
        uint256 tokenIdShift; //used for gen newTokenId, add to old tokenId
        bool enabled;
    }

    struct Beneficiary {
        address bAddress;
        uint256 bPercent;
    }

    uint256 constant public MAX_TOTAL_SUPPLY = 9990;
    uint256 constant public MAX_MINT_PER_TX = 10;
    uint256 constant public MAX_BUY_PER_TX = 10;

    uint256 public mintPrice = 5e16;
    uint256 public stopMintAfter = 2775; //5*555
    uint256 public reservedForPartners;
    uint256 public enableBuyAfterTimestamp;


    mapping (address => Partners) public   partnersLimit;

    Upgrade[] public upgradeTypes;
    Beneficiary[2] public beneficiaries;

    //Event for track mint channel:
    // 1 - MagicBox - depricated
    // 2 - With Ethere
    // 3 - Partners White List
    // 4 - With ERC20 - depricated
    event MintSource(uint256 tokenId, uint8 channel);
    event PartnesChanged(address partner, uint256 limit);
    event Upgraded(address indexed holder, uint256 upgradeIndex, uint256 oldTokenId, uint256 newTokenId);

    /**
     * @dev Set _mintMagicBox to true for enable this feature 
     * 
     */
    //constructor() ERC721("MÆRⴼTΩR NFT Collection", "MÆRⴼTΩR")  {
    constructor(string memory _name, string memory _symbol) ERC721(_name, _symbol)  {    
        //1630353600 - 2021-08-30 20:00 UTC
        enableBuyAfterTimestamp = 1630353600;
        beneficiaries[0] = Beneficiary(msg.sender, 6650);
        beneficiaries[1] = Beneficiary(msg.sender, 3350);
    }


    /**
     * @dev Mint new NFTs with ether or free for partners. 
     * 
     */
    function multiMint() external payable {
        uint256 mintAmount = _availableFreeMint(msg.sender);
        if(mintAmount > 0) {
            require(msg.value == 0, "No need Ether");
            mintAmount = _multiMint(msg.sender, mintAmount, 3);
            partnersLimit[msg.sender].nftMinted += mintAmount;
            reservedForPartners -= mintAmount;
        } else {
            require(enableBuyAfterTimestamp <= block.timestamp, "To early");
            require(msg.value >= mintPrice, "Less ether for mint");
            uint256 estimateAmountForMint = msg.value / mintPrice;
            require(estimateAmountForMint <= MAX_BUY_PER_TX, "So much payable mint");
            require(stopMintAfter - reservedForPartners >= totalSupply()  +  estimateAmountForMint, "Minting is paused");
            mintAmount = _multiMint(msg.sender, estimateAmountForMint, 2);
            if  ((msg.value - mintAmount * mintPrice) > 0) {
                address payable s = payable(msg.sender);
                s.transfer(msg.value - mintAmount * mintPrice);
            }
        }
    }

    function upgradeMe(uint256 _upgradeIndex, uint256 _tokenId) external payable {
        require (_upgradeIndex < upgradeTypes.length, "Unknown upgrade");
        require(ownerOf(_tokenId) == msg.sender, "Only for token owner");
        require(upgradeTypes[_upgradeIndex].enabled, "Disabled upgrade");
        require(upgradeTypes[_upgradeIndex].priceETH <= msg.value, "Not enough ether");
        if (upgradeTypes[_upgradeIndex].limit != 0) {
            require(
                upgradeTypes[_upgradeIndex].count + 1 <= upgradeTypes[_upgradeIndex].limit, 
                "Upgrade limit exceeded"
            );
        }
        upgradeTypes[_upgradeIndex].count += 1;
        _burn(_tokenId);
        uint256 newToken = upgradeTypes[_upgradeIndex].tokenIdShift + _tokenId;
        _mint(msg.sender, newToken);
        emit Upgraded(msg.sender, _upgradeIndex, _tokenId, newToken);
        if (msg.value - upgradeTypes[_upgradeIndex].priceETH > 0 ){
             address payable s = payable(msg.sender);
             s.transfer(msg.value - upgradeTypes[_upgradeIndex].priceETH);
        }

    }



    /**
     * @dev Returns avilable for free mint NFTs for address
     * 
     */
    function availableFreeMint(address _partner) external view returns (uint256) {
        return _availableFreeMint(_partner);    
    }

    function getUpgradeType(uint256 _index) external view returns(Upgrade memory) {
        require(_index < upgradeTypes.length, "Unknown upgrade");
        return upgradeTypes[_index];

    }

    function getUpgradeTypeCount() external view returns(uint256) {
        return upgradeTypes.length;

    }

    function getBeneficiaries() external view returns(Beneficiary[2] memory) {
        return beneficiaries; 
    }


    ///////////////////////////////////////////////////////////////////
    /////  Owners Functions ///////////////////////////////////////////
    ///////////////////////////////////////////////////////////////////
    function setPartner(address _partner, uint256 _limit) external onlyOwner {
        _setPartner(_partner, _limit);
    }

    function setPartnerBatch(address[] memory _partners, uint256[] memory _limits) external onlyOwner {
        require(_partners.length == _limits.length, "Array params must have equal length");
        require(_partners.length <= 256, "Not more than 256");
        for (uint8 i; i < _partners.length; i ++) {
            _setPartner(_partners[i], _limits[i]);
        }

    } 

    function setMintPrice(uint256 _newPrice) external onlyOwner {
        mintPrice = _newPrice;
    }

    function withdrawEther() external onlyOwner {
        uint256 raised = address(this).balance;
        for (uint8 i; i < beneficiaries.length; i ++) {
            address payable o = payable(beneficiaries[i].bAddress);
            o.transfer(raised * beneficiaries[i].bPercent / 10000);
        }
    }


    function setMintPause(uint256 _newTotalSupply) external onlyOwner {
        stopMintAfter = _newTotalSupply;
    }


    function setEnableTimestamp(uint256 _newTimestamp) external onlyOwner {
        enableBuyAfterTimestamp = _newTimestamp;
    }

    function addUpgradeType(
        uint256 _priceETH, 
        uint256 _limit, 
        uint256 _tokenIdShift,
        bool _enabled
    ) external onlyOwner 
    {
        require(_tokenIdShift > MAX_TOTAL_SUPPLY, "Not Zero");
        upgradeTypes.push(Upgrade({
            priceETH: _priceETH,
            limit: _limit,
            count: 0,
            tokenIdShift: _tokenIdShift,
            enabled: _enabled
        })
        );
    }

    function updateUpType(
        uint256 _inedx, 
        uint256 _priceETH, 
        uint256 _limit, 
        bool _enabled
    ) external onlyOwner {
        upgradeTypes[_inedx].priceETH = _priceETH;
        upgradeTypes[_inedx].limit = _limit;
        upgradeTypes[_inedx].enabled = _enabled;
    }

    function setBeneficiary(uint256 _index, address _beneficiary) external onlyOwner {
        require(_beneficiary != address(0), "No Zero Address");
        beneficiaries[_index].bAddress = _beneficiary;
    }



    ///////////////////////////////////////////////////////////////////
    /////  INTERNALS      /////////////////////////////////////////////
    ///////////////////////////////////////////////////////////////////
    function _availableFreeMint(address _partner) internal view returns (uint256) {
        return partnersLimit[_partner].limit - partnersLimit[_partner].nftMinted;
    } 


    function _baseURI() internal view override returns (string memory) {
        return string(abi.encodePacked(
            //"https://dev.nftstars.app/backend/api/v1/nfts/metadata/0x",
            "https://nftstars.app/backend/api/v1/nfts/metadata/0x",
            toAsciiString(address(this)),
            "/")
        );
    }

    function _setPartner(address _partner, uint256 _limit) internal {
        require(_partner != address(0), "No zero");
        require(_limit  >= partnersLimit[_partner].nftMinted, "Cant decrease more then minted");
        if (partnersLimit[_partner].limit < _limit) {
            reservedForPartners += (_limit - partnersLimit[_partner].limit);
        } else {
            reservedForPartners -= (partnersLimit[_partner].limit - _limit);
        }
        partnersLimit[_partner].limit = _limit;
        emit PartnesChanged(_partner, _limit);
    }

    function _multiMint(address to, uint256 amount, uint8 channel) internal returns (uint256) {
        require((totalSupply() + reservedForPartners + amount) <= MAX_TOTAL_SUPPLY, "No more common heroes");
        uint256 counter;
        if (amount  > MAX_MINT_PER_TX) {
            counter = MAX_MINT_PER_TX;
        } else {
            counter = amount;
        }

        if ((totalSupply() + counter) > MAX_TOTAL_SUPPLY) {
            counter = MAX_TOTAL_SUPPLY - totalSupply();
        }
        for(uint i = 0; i < counter; i++) {
            _mint(to, totalSupply());
            emit MintSource(totalSupply()-1, channel);
        }
        return counter;
    }

    function toAsciiString(address x) internal view returns (string memory) {
        bytes memory s = new bytes(40);
        for (uint i = 0; i < 20; i++) {
            bytes1 b = bytes1(uint8(uint(uint160(x)) / (2**(8*(19 - i)))));
            bytes1 hi = bytes1(uint8(b) / 16);
            bytes1 lo = bytes1(uint8(b) - 16 * uint8(hi));
            s[2*i] = char(hi);
            s[2*i+1] = char(lo);            
        }
        return string(s);
    }

    function char(bytes1 b) internal view returns (bytes1 c) {
        if (uint8(b) < 10) return bytes1(uint8(b) + 0x30);
        else return bytes1(uint8(b) + 0x57);
    }

}

