// SPDX-License-Identifier: MIT
pragma solidity ^0.8.12;

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Enumerable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract NFTMintingContract is ERC721Enumerable, Ownable {
    uint public maxPerAddressDuringMint = 5;
    uint public amountForDevs = 0;
    uint public price = 0.05 ether;
    uint public freemintAmount = 100;
    uint public collectionSize = 1000;

    mapping(address => uint) public addressMintedCount;
    mapping(address => bool) public allowlist;

    enum State { AllowlistSetup, MintingPhase }
    State public currentState;

    event MintEvent(address indexed buyer, uint amount);
    event MintFreeEvent(address indexed buyer);
    event SeedAllowlistEvent(address indexed executor);
    event SetBaseURIEvent(string newBaseURI);
    event WithdrawFundsEvent(address indexed owner, uint amount);

    constructor() ERC721("NFTMinting", "NFTM") {
        currentState = State.AllowlistSetup;
    }

    modifier inState(State state) {
        require(currentState == state, "Invalid state for this operation");
        _;
    }

    function seedAllowlist(address[] calldata _addresses) external onlyOwner inState(State.AllowlistSetup) {
        for (uint i = 0; i < _addresses.length; i++) {
            allowlist[_addresses[i]] = true;
        }
        emit SeedAllowlistEvent(msg.sender);
        currentState = State.MintingPhase;
    }

    function mint(uint quantity) external payable inState(State.MintingPhase) {
        require(quantity > 0 && quantity <= maxPerAddressDuringMint, "Invalid mint quantity");
        require(totalSupply() + quantity <= collectionSize, "Exceeds max supply");
        require(msg.value >= quantity * price, "Insufficient funds");
        require(addressMintedCount[msg.sender] + quantity <= maxPerAddressDuringMint, "Limit exceeded");

        addressMintedCount[msg.sender] += quantity;
        for (uint i = 0; i < quantity; i++) {
            _mint(msg.sender, totalSupply() + 1);
        }
        emit MintEvent(msg.sender, quantity);
    }

    function mintFree() external inState(State.MintingPhase) {
        require(allowlist[msg.sender], "Not in allowlist");
        require(freemintAmount > 0, "No free mints available");

        freemintAmount--;
        _mint(msg.sender, totalSupply() + 1);
        emit MintFreeEvent(msg.sender);
    }

    function setBaseURI(string calldata newBaseURI) external onlyOwner inState(State.MintingPhase) {
        emit SetBaseURIEvent(newBaseURI);
        // Assuming baseURI storage and requisite implementation here
    }

    function withdrawMoney() external onlyOwner inState(State.MintingPhase) {
        uint balance = address(this).balance;
        payable(owner()).transfer(balance);
        emit WithdrawFundsEvent(owner(), balance);
