// SPDX-License-Identifier: MIT
pragma solidity ^0.8.3;

contract AlchemixLPStrategy {
    // State variables
    uint public totalShares = 0;
    uint public totalLp = 0;
    mapping(address => uint) public vaults;

    enum State { VaultRegistration, InvestmentPhase, RedemptionPhase }
    State public currentState;

    event VaultRegistered(address indexed vault);
    event InvestTriggered(uint amount);
    event RedeemTriggered(uint amount);
    event HarvestTriggered(uint amount);
    event SharesRedeemed(uint amount);

    modifier onlyInState(State _state) {
        require(currentState == _state, "Invalid state for this operation");
        _;
    }

    constructor() {
        currentState = State.VaultRegistration;
    }

    // Function to add a new vault
    function addVault() external onlyInState(State.VaultRegistration) {
        vaults[msg.sender] = 0;
        emit VaultRegistered(msg.sender);
        currentState = State.InvestmentPhase;
    }

    // Function to invest LP tokens
    function invest(uint amount) external onlyInState(State.InvestmentPhase) {
        require(amount > 0, "Amount must be greater than zero");
        totalLp += amount;
        emit InvestTriggered(amount);
    }

    // Function to redeem shares
    function redeem(uint amount) external onlyInState(State.InvestmentPhase) {
        require(amount > 0, "Amount must be greater than zero");
        currentState = State.RedemptionPhase;
        emit RedeemTriggered(amount);
    }

    // Function to harvest rewards
    function harvest(uint amount) external onlyInState(State.InvestmentPhase) {
        emit HarvestTriggered(amount);
    }

    // Function to withdraw assets after redeeming shares
    function withdrawAssets(uint amount) external onlyInState(State.RedemptionPhase) {
        require(amount <= totalLp, "Insufficient LP tokens");
        totalLp -= amount;
        totalShares -= amount; // Assuming 1:1 mapping for shares and amount
        currentState = State.InvestmentPhase;
        emit SharesRedeemed(amount);
    }
}

