        _mint(initialSupply);
        currentState = State.TokenCreated;
    }

    function _mint(uint amount) internal {
        _totalSupply += amount;
        _balances[msg.sender] += amount;
        currentState = State.Transferable;
    }

    function transfer(address to, uint amount) public {
        require(currentState == State.Transferable, "Transfer not allowed");
        require(_balances[msg.sender] >= amount, "Insufficient balance");

        uint tax = CheckTax(amount);
        _transfer(msg.sender, to, amount - tax);
        if (tax > 0) {
            _transfer(msg.sender, taxAddress, tax); // Deduct tax
        }
    }

    function _transfer(address from, address to, uint amount) internal {
        _balances[from] -= amount;
        _balances[to] += amount;
        emit Transfer(from, to, amount);
    }

    function approve(address spender, uint256 amount) public {
        _allowances[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
    }

    function CheckTax(uint amount) private view returns (uint) {
        // Implement tax calculation logic if needed, e.g., a fixed percentage
        return (amount * 5) / 100; // Example: 5% tax
    }

    function ManageTax() public {
