        balanceOf[to] += amount;

        emit TransferTokens(msg.sender, to, amount);
    }

    function manageFees(uint newTaxFee, uint newMarketingFee) external {
        taxFee = newTaxFee;
        marketingFee = newMarketingFee;
        emit UpdateFees(newTaxFee, newMarketingFee);
    }

    function transferWithFees(address to, uint amount) external {
        require(balanceOf[msg.sender] >= amount, "Insufficient balance");
        require(!blacklistedAddresses[msg.sender], "Caller is blacklisted");

        uint tax = (amount * taxFee) / 100;
        uint marketing = (amount * marketingFee) / 100;
        uint netAmount = amount - (tax + marketing);

        balanceOf[msg.sender] -= amount;
        balanceOf[to] += netAmount;

        // Handle fees (e.g., send to marketing wallet, etc.)

        emit TransferTokens(msg.sender, to, netAmount);
    }
}

