        _;
    }

    function allowTrading() external onlyOwner inState(State.TradingDisabled) {
        currentState = State.TradingEnabled;
    }

    function disableTrading() external onlyOwner inState(State.TradingEnabled) {
        currentState = State.TradingDisabled;
    }

    function setSwapAndLiquifyEnabled(bool _enabled) external onlyOwner inState(State.TradingEnabled) {
        currentState = _enabled ? State.SwappingLiquidity : State.TradingEnabled;
        emit SwapAndLiquifyEnabledUpdated(_enabled);
    }

    function disableSwapAndLiquify() external onlyOwner inState(State.SwappingLiquidity) {
        currentState = State.TradingEnabled;
    }

    function transfer(address recipient, uint amount) public override inState(State.TradingEnabled) returns (bool) {
        _transfer(msg.sender, recipient, amount);
        emit Transfer(msg.sender, recipient, amount);
        return true;
    }

