    uint256 public presaleEnd;

    mapping(address => uint) public accountMapping;

    enum State { Presale, PublicSale, AdminMinting }
    State public currentState;

    event Mint(address indexed to, uint256 tokenId);
    event PermanentURI(string value, uint256 indexed id);

    constructor() {
        currentState = State.Presale;
    }

    modifier onlyDuringPresale() {
        require(currentState == State.Presale, "Not in Presale state");
        _;
    }

    modifier onlyDuringPublicSale() {
        require(currentState == State.PublicSale, "Not in Public Sale state");
        _;
    }

    function setPresaleStart(uint256 _start, uint256 _end) external {
        presaleStart = _start;
        presaleEnd = _end;
        currentState = State.Presale;
    }

    function endPresale() external onlyDuringPresale {
        currentState = State.PublicSale;
        emit PermanentURI("Presale ended", 0);
    }

    function setPublicSaleStart() external {
        require(block.timestamp >= presaleEnd, "Presale has not ended");
        currentState = State.PublicSale;
    }

    function endPublicSale() external onlyDuringPublicSale {
        currentState = State.AdminMinting;
        emit PermanentURI("Public Sale ended", 0);
    }

    function adminMintFunction(address to, uint256 tokenId) external {
        require(currentState == State.AdminMinting, "Not in Admin Minting state");
        accountMapping[to]++;
        emit Mint(to, tokenId);
    }

    function mintWife() external payable onlyDuringPublicSale {
        require(msg.value >= DAW_PRICE, "Insufficient payment");
        // Minting logic goes here
        emit Mint(msg.sender, 0); // Replace 0 with the minted tokenId
    }

    function airDropMany(address[] calldata recipients, uint256[] calldata tokenIds) external {
        // Airdrop logic goes here
        for (uint256 i = 0; i < recipients.length; i++) {
            emit Mint(recipients[i], tokenIds[i]);
        }
    }
}

