// SPDX-License-Identifier: MIT
pragma solidity ^0.8.12;

contract NFTMintingContract {
    enum SaleStep { BeforeSale, WhitelistSale, PublicSale, SoldOut, Reveal }
    SaleStep public currentSellingStep;

    string public baseURI;
    uint public nftSupplyLimit = 1000;
    mapping(address => uint) public whitelistDetails;

    event NFTMinted(address indexed to, uint256 tokenId);
    event SalePhaseUpdated(SaleStep step);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    address public owner;

    constructor(string memory _baseURI) {
        owner = msg.sender;
        baseURI = _baseURI;
        currentSellingStep = SaleStep.BeforeSale;
    }

    function setStep(SaleStep _step) public onlyOwner {
        currentSellingStep = _step;
        emit SalePhaseUpdated(_step);
    }

    function setBaseUri(string memory _baseURI) public onlyOwner {
        baseURI = _baseURI;
    }

    function whitelistMint() public {
        require(currentSellingStep == SaleStep.WhitelistSale, "Whitelist sale is not active");
        require(whitelistDetails[msg.sender] > 0, "Not whitelisted");
        require(whitelistDetails[msg.sender] <= nftSupplyLimit, "Supply limit exceeded");

        // Minting logic here
        emit NFTMinted(msg.sender, /* tokenId */ 0);
        whitelistDetails[msg.sender]--;
    }

    function publicSaleMint() public {
        require(currentSellingStep == SaleStep.PublicSale, "Public sale is not active");
        require(nftSupplyLimit > 0, "Supply limit exceeded");

        // Minting logic here
        emit NFTMinted(msg.sender, /* tokenId */ 0);
        nftSupplyLimit--;
    }

    function gift(address to) public onlyOwner {
        // Minting logic for gifting NFTs
        emit NFTMinted(to, /* tokenId */ 0);
    }

    function checkSoldOut() internal {
        // Logic to check if all NFTs are sold out
        if (nftSupplyLimit == 0) {
            setStep(SaleStep.SoldOut);
        }
    }

    function revealNFTs() public {
        require(currentSellingStep == SaleStep.SoldOut, "Sale must be sold out to reveal");
        setStep(SaleStep.Reveal);
    }
}

