pragma solidity ^0.8.7;

contract NFTMintingContract {
    uint public constant MAX_SUPPLY = 10000;
    uint public constant MINT_PRICE = 0.05 ether;
    uint public constant MAX_NUM_MINT = 5;

    bool public salesActivated = false;
    string private _rootURI;

    enum State { SalesInactive, SalesActive, MintingInProgress }
    State public currentState;

