        require(salesActivated, "Sales are not activated");
        _;
    }

    modifier onlyWhenMinting() {
        require(currentState == State.MintingInProgress, "Not in minting state");
        _;
    }

    function toggleSalesState() external {
        salesActivated = !salesActivated;
        currentState = salesActivated ? State.SalesActive : State.SalesInactive;
        emit SalesStateToggled(salesActivated);
    }

    function mint(uint256 quantity) external payable onlyWhenSalesActive {
        require(quantity > 0 && quantity <= MAX_NUM_MINT, "Invalid mint quantity");
        require(msg.value >= MINT_PRICE * quantity, "Insufficient funds");

        currentState = State.MintingInProgress;

        for (uint256 i = 0; i < quantity; i++) {
            uint256 tokenId = // logic to generate tokenId;
            emit MintComplete(msg.sender, tokenId);
        }

        currentState = State.SalesActive;
    }

    function assign(address to, uint256 tokenId) external {
        // Logic to assign NFT to a specific address
        emit MintComplete(to, tokenId);
    }

    function setBaseURI(string calldata baseURI) external {
        _rootURI = baseURI;
    }

    function withdraw() external {
        payable(msg.sender).transfer(address(this).balance);
    }

    function getBaseURI() external view returns (string memory) {
        return _rootURI;
    }
}

