contract DefiRangersV2 {
    uint public maxTokenSupply = 10000;
    uint public mintPrice = 0.05 ether;
    bool public saleIsActive = false;
    bool public claimingIsActive = false;

    mapping(address => bool) public hasClaimed;

    event PaymentReleased(address indexed to, uint256 amount);

    modifier onlyOwner() {
        // Placeholder for ownership check
        require(msg.sender == address(this), "Caller is not the owner");
        _;
    }

    function toggleSale() external onlyOwner {
        saleIsActive = !saleIsActive;
    }

    function toggleClaiming() external onlyOwner {
        claimingIsActive = !claimingIsActive;
    }

    function publicMint() external payable {
        require(saleIsActive, "Sale must be active to mint");
        require(msg.value == mintPrice, "Incorrect Ether sent");
        // Logic to mint NFTs goes here
    }

    function mintViaClaim() external {
        require(claimingIsActive, "Claiming must be active to claim");
        require(!hasClaimed[msg.sender], "You have already claimed");
        // Logic to verify ownership of specific tokens from the genesis contract goes here
        hasClaimed[msg.sender] = true;
        // Logic to mint NFT goes here
    }

    function withdraw() external onlyOwner {
        uint balance = address(this).balance;
        payable(msg.sender).transfer(balance);
        emit PaymentReleased(msg.sender, balance);
    }
}

