pragma solidity ^0.8.12;

contract ERC721TokenContract {
    string public baseURIString;
    bool public isFrozen;
    address public metaTriadsTransferExtender;
    address public owner;

    enum State { Active, Frozen, Transfer }
    State public currentState;

    event setBaseURIEvent(string newBaseURI);
    event WithdrawAllEvent(uint256 amount);
    event ReceivedEther(uint256 amount);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    constructor() {
        owner = msg.sender;
        currentState = State.Active;
        isFrozen = false;
        metaTriadsTransferExtender = address(0);
    }

    function mintTo(address to) external {
        require(currentState == State.Active, "Contract is not active");
        // Logic to mint an NFT to 'to'
    }

    function burn(uint256 tokenId) external {
        require(currentState == State.Active, "Contract is not active");
        // Logic to burn the NFT with 'tokenId'
    }

    function setBaseURI(string calldata newBaseURI) external onlyOwner {
        require(!isFrozen, "Contract is frozen");
        baseURIString = newBaseURI;
        emit setBaseURIEvent(newBaseURI);
    }

    function freeze() external onlyOwner {
        isFrozen = true;
        currentState = State.Frozen;
    }

    function unfreeze() external onlyOwner {
        isFrozen = false;
        currentState = State.Active;
    }

    function extendTransfer() external {
        require(currentState == State.Active, "Contract is not active");
        // Logic for extending transfers
        currentState = State.Transfer;
    }

    function executeTransfer() external {
        require(currentState == State.Transfer, "Not in Transfer state");
        // Logic to complete the transfer
    }

    function returnToActive() external {
        require(currentState == State.Transfer, "Not in Transfer state");
        currentState = State.Active;
    }

    function withdrawAll() external onlyOwner {
        // Logic to withdraw all funds
        uint256 amount = address(this).balance;
        payable(owner).transfer(amount);
        emit WithdrawAllEvent(amount);
    }

    receive() external payable {
        emit ReceivedEther(msg.value);
    }
}

