// SPDX-License-Identifier: MIT
pragma solidity ^0.8.10;

contract TokenContract {
    struct TokenAttributes {
        uint256 burnPrice;
        uint256 mintPrice;
        uint256 supply;
    }

    enum State { TokenCreation, MintingActive, BurningActive }
    State public currentState;

    TokenAttributes[] public tokens;
    mapping(uint => TokenAttributes) public tokenAttributes;
    mapping(address => bool) public creators;

    event TokenURIUpdated(uint indexed tokenId);
    event TokenMinted(address indexed to, uint256 amount);

    constructor() {
        currentState = State.TokenCreation;
    }

    modifier onlyCreator() {
        require(creators[msg.sender] == true, "Not a creator");
        _;
    }

    // Function to create a new token
    function createToken(uint256 _burnPrice, uint256 _mintPrice, uint256 _supply) external {
        require(currentState == State.TokenCreation, "Not in TokenCreation state");
        TokenAttributes memory newToken = TokenAttributes(_burnPrice, _mintPrice, _supply);
        tokens.push(newToken);
        tokenAttributes[tokens.length - 1] = newToken;
        creators[msg.sender] = true;
        currentState = State.MintingActive; // Move to MintingActive state
    }

    // Function to mint tokens
    function mintToken(uint256 tokenId, uint256 amount) external {
        require(currentState == State.MintingActive, "Not in MintingActive state");
        require(tokenId < tokens.length, "Invalid tokenId");
        emit TokenMinted(msg.sender, amount);
        // Minting logic goes here
    }

    // Function to burn tokens
    function burnToken(uint256 tokenId, uint256 amount) external {
        require(currentState == State.BurningActive, "Not in BurningActive state");
        // Burning logic goes here
    }

    // Function to set token attributes
    function setTokenAttributes(uint256 tokenId, uint256 _burnPrice, uint256 _mintPrice, uint256 _supply) external onlyCreator {
        require(tokenId < tokens.length, "Invalid tokenId");
        tokenAttributes[tokenId] = TokenAttributes(_burnPrice, _mintPrice, _supply);
        emit TokenURIUpdated(tokenId);
    }

