        uint fee = (amount * liquidityFees) / 100;
        uint amountAfterFee = amount - fee;

        reflectionBalances[msg.sender] -= amount;
        reflectionBalances[to] += amountAfterFee;
        emit Transfer(msg.sender, to, amountAfterFee);

