    modifier onlyOwner() {
        require(msg.sender == address(this), "Not the contract owner");
        _;
    }

    modifier validAmount(uint amount) {
        require(amount > 0 && amount <= balances[msg.sender], "Invalid amount");
        _;
    }

    constructor(uint _totalSupply) {
        totalSupply = _totalSupply;
        balances[msg.sender] = _totalSupply; // Assign total supply to contract creator
    }

    function initializeAddresses(address _welfareAddress, address _warehouseAddress) external onlyOwner {
        welfareAddress = _welfareAddress;
        warehouseAddress = _warehouseAddress;
    }

    function transferToWelfare(uint amount) external validAmount(amount) {
        balances[msg.sender] -= amount;
        publicWelfareFund += amount;
        emit Transfer(msg.sender, welfareAddress, amount);
    }

    function transferToWarehouse(uint amount) external validAmount(amount) {
        balances[msg.sender] -= amount;
        publicWarehouse += amount;
        emit Transfer(msg.sender, warehouseAddress, amount);
    }

    function performTransfer(address to, uint amount) external validAmount(amount) {
        balances[msg.sender] -= amount;
        balances[to] += amount;
        emit Transfer(msg.sender, to, amount);
    }

    function grantApproval(address spender, uint amount) external {
        allowances[msg.sender][spender] = amount;
        emit Approval(msg.sender, spender, amount);
    }

    function executeTransferFrom(address from, address to, uint amount) external {
        require(allowances[from][msg.sender] >= amount, "Allowance exceeded");
        allowances[from][msg.sender] -= amount;
        balances[from] -= amount;
        balances[to] += amount;
        emit Transfer(from, to, amount);
    }

    function updateWelfareFund() external {
        // Logic for updating welfare fund (not defined in the original FSM)
    }

    function updateWarehouseBalance() external {
        // Logic for updating warehouse balance (not defined in the original FSM)
    }
}

