//SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract SwordsOfDestiny {
    bytes32 public merkleRoot;
    uint public maxSwords = 10000;
    uint public teamReserved = 1000;
    uint public price = 0.05 ether;
    uint public maxPerTx = 5;
    uint public totalSupply;
    uint public mintingStartTime;
    bool public saleActive;

    enum State { Inactive, Presale, ActiveSale }
    State public currentState;

    event PresaleStarted();
    event SaleActivated();
    event TokensMinted(address indexed to, uint amount);
    event TokensClaimed(address indexed user, uint amount);
    event TeamMinted(address indexed teamMember, uint amount);

    constructor() {
        currentState = State.Inactive;
    }

    modifier onlyInactive() {
        require(currentState == State.Inactive, "Not in inactive state");
        _;
    }

    modifier onlyPresale() {
        require(currentState == State.Presale, "Not in presale state");
        _;
    }

    modifier onlyActiveSale() {
        require(currentState == State.ActiveSale, "Not in active sale state");
        _;
    }

    function setPresaleStart(uint startTime) external onlyInactive {
        mintingStartTime = startTime;
        currentState = State.Presale;
        emit PresaleStarted();
    }

    function activateSale() external onlyPresale {
        currentState = State.ActiveSale;
        emit SaleActivated();
    }

    function claim() external onlyPresale {
        // Logic for claiming tokens via merkle tree
        emit TokensClaimed(msg.sender, 1); // Example
    }

    function mint(uint amount) external payable onlyActiveSale {
        require(amount <= maxPerTx, "Exceeds max per transaction");
        require(totalSupply + amount <= maxSwords, "Exceeds max supply");
        require(msg.value >= price * amount, "Insufficient Ether sent");

        totalSupply += amount;
        emit TokensMinted(msg.sender, amount);
    }

    function teamMint(uint amount) external onlyActiveSale {
        require(amount <= teamReserved, "Exceeds team reserved amount");
        teamReserved -= amount;
        totalSupply += amount;
        emit TeamMinted(msg.sender, amount);
    }

    function toggleSaleState() external {
        if (currentState == State.ActiveSale) {
            currentState = State.Inactive;
        } else {
            currentState = State.ActiveSale;
        }
    }
}

