// SPDX-License-Identifier: MIT
pragma solidity ^0.8.6;

contract MultivisasToken {
    enum State { Inactive, Active, Giveaway }
    State public currentState;

    uint[] public tokenIDs;
    mapping(address => bool) public whitelisted;
    mapping(address => uint) public mintCounts;
    uint public itemPrice = 0;
    uint public maxMintLimit = 5;

    address public owner;

    event TokenMinted(address indexed to, uint tokenId);
    event SaleStatusChanged(State newState);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    modifier validPrice() {
        require(msg.value >= itemPrice, "Insufficient payment");
        _;
    }

    modifier isWhitelisted() {
        require(whitelisted[msg.sender], "Not whitelisted");
        _;
    }

    constructor() {
        owner = msg.sender;
        currentState = State.Inactive;
    }

    function activateMinting() external onlyOwner {
        currentState = State.Active;
        emit SaleStatusChanged(currentState);
    }

    function deactivateMinting() external onlyOwner {
        currentState = State.Inactive;
        emit SaleStatusChanged(currentState);
    }

    function startGiveaway() external onlyOwner {
        currentState = State.Giveaway;
        emit SaleStatusChanged(currentState);
    }

    function endGiveaway() external onlyOwner {
        currentState = State.Active;
        emit SaleStatusChanged(currentState);
    }

    function mint() external payable validPrice isWhitelisted {
        require(currentState == State.Active, "Minting is not active");
        require(mintCounts[msg.sender] < maxMintLimit, "Mint limit exceeded");

        uint tokenId = tokenIDs.length;
        tokenIDs.push(tokenId);
        mintCounts[msg.sender]++;

        emit TokenMinted(msg.sender, tokenId);
    }

    function mintGiveAway() external onlyOwner {
        require(currentState == State.Giveaway, "Not in giveaway mode");

        uint tokenId = tokenIDs.length;
        tokenIDs.push(tokenId);

        emit TokenMinted(msg.sender, tokenId);
    }

    function setNewSaleAmount(uint _itemPrice) external onlyOwner {
        itemPrice = _itemPrice;
    }

    function setURI(string memory uri) external onlyOwner {
        // Functionality to set URI would be implemented here
    }

    function withdraw() external onlyOwner {
        payable(owner).transfer(address(this).balance);
    }
}

