pragma solidity ^0.8.11;

contract NFTMintingContract {
    uint public maxTokenSupply = 10000;
    uint public mintPrice = 0.05 ether;
    bool public mintingIsActive = true;
    bool public isLocked = false;
    string public baseURI = "";
    string public provenance = "";

    uint public currentSupply;
    address public owner;

    enum State { MintingActive, MintingPaused, Locked }
    State public state;

    event MintedToken(address indexed to, uint tokenId);
    event EvolvedToken(uint tokenId);

    constructor() {
        owner = msg.sender;
        state = State.MintingActive;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    modifier whenMintingActive() {
        require(mintingIsActive && state == State.MintingActive, "Minting is not active");
        _;
    }

    function mint() external payable whenMintingActive {
        require(msg.value >= mintPrice, "Insufficient funds");
        require(currentSupply < maxTokenSupply, "Max token supply reached");

        currentSupply++;
        emit MintedToken(msg.sender, currentSupply);
    }

    function setMaxTokenSupply(uint _maxTokenSupply) external onlyOwner {
        maxTokenSupply = _maxTokenSupply;
    }

    function reserveMint() external onlyOwner {
        // Logic to reserve tokens (not implemented here)
    }

    function flipMintingState() external onlyOwner {
        if (state == State.MintingActive) {
            state = State.MintingPaused;
        } else {
            state = State.MintingActive;
        }
    }

    function lockProvenance() external onlyOwner {
        require(!isLocked, "Provenance is already locked");
        isLocked = true;
        state = State.Locked;
    }

    function setBaseURI(string calldata _baseURI) external onlyOwner {
        require(!isLocked, "Base URI is locked");
        baseURI = _baseURI;
    }
}

