// SPDX-License-Identifier: MIT
pragma solidity ^0.8.11;

contract NFTMintingContract {
    string public baseURI;
    uint public cost;
    uint public preSaleCost;
    uint public maxSupply;
    uint public maxMintAmount;
    bool public paused = true;
    bool public preSaleActive = false;

    enum State {Paused, PresaleActive, SaleActive}
    State public currentState;

    mapping(address => bool) public whitelisted;
    uint public totalMinted;

    event MintingCompleted(address indexed user, uint amount);
    event SaleActivated();

    constructor(string memory _baseURI, uint _maxSupply) {
        baseURI = _baseURI;
        maxSupply = _maxSupply;
        currentState = State.Paused;
    }

    modifier onlyIfPaused() {
        require(currentState == State.Paused, "Contract is not paused.");
        _;
    }

    modifier onlyIfPresaleActive() {
        require(currentState == State.PresaleActive, "Presale is not active.");
        _;
    }

    modifier onlyIfSaleActive() {
        require(currentState == State.SaleActive, "Sale is not active.");
        _;
    }

    modifier checkCost(uint _amount) {
        require(msg.value >= (currentState == State.PresaleActive ? preSaleCost : cost) * _amount, "Insufficient payment.");
        _;
    }

    function actionMint(uint _amount) public payable {
        require(_amount > 0 && _amount <= maxMintAmount, "Invalid mint amount.");
        require(totalMinted + _amount <= maxSupply, "Exceeds max supply.");

        if (currentState == State.PresaleActive) {
            require(whitelisted[msg.sender], "Not whitelisted for presale.");
        }

        totalMinted += _amount;
        emit MintingCompleted(msg.sender, _amount);
    }

    function actionPreSaleActivate() public onlyIfPaused {
        preSaleActive = true;
        currentState = State.PresaleActive;
    }

    function actionEndPresale() public onlyIfPresaleActive {
        preSaleActive = false;
        currentState = State.SaleActive;
        emit SaleActivated();
    }

    function setCost(uint _cost) public {
        cost = _cost;
    }

    function setPreSaleCost(uint _preSaleCost) public {
        preSaleCost = _preSaleCost;
    }

    function pause() public onlyIfPaused {
        paused = true;
    }

    function whitelistUser(address _user) public {
        whitelisted[_user] = true;
    }

    function withdraw() public {
        // Function to withdraw funds
    }
}

