    mapping(address => uint) public mintingLimits;

    enum State { FreeClaimActive, PreSaleActive, PublicSaleActive }
    State public currentState;

    event MintingAction(address indexed user, uint amount);
    event StateChange(State newState);

    constructor(address _signatureVerifier) {
        signatureVerifier = _signatureVerifier;
        currentState = State.FreeClaimActive;
    }

    modifier onlyInState(State state) {
        require(currentState == state, "Invalid state for this action");
        _;
    }

    function hashMessage(bytes32 message) internal pure returns (bytes32) {
        return keccak256(abi.encodePacked(message));
    }

    function freeMint() external onlyInState(State.FreeClaimActive) {
        // Implementation for free minting
        emit MintingAction(msg.sender, 1);
    }

    function allowListMint() external onlyInState(State.PreSaleActive) {
        // Implementation for allowlist minting
        emit MintingAction(msg.sender, 1);
    }

    function publicMint() external payable onlyInState(State.PublicSaleActive) {
        // Implementation for public minting
        emit MintingAction(msg.sender, 1);
    }

    function enablePreSale() external {
        require(currentState == State.FreeClaimActive, "Pre-sale can only be enabled from FreeClaimActive");
        preSaleStatus = true;
        currentState = State.PreSaleActive;
        emit StateChange(currentState);
    }

    function enablePublicSale() external {
        require(currentState == State.PreSaleActive, "Public sale can only be enabled from PreSaleActive");
        publicSaleStatus = true;
        currentState = State.PublicSaleActive;
