// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract TokenContract {
    string public name = "Token";
    string public symbol = "TKN";
    uint8 public decimals = 18;
    uint256 public totalSupply;
    mapping(address => uint) public balances;

    uint public taxFee;
    uint public developmentFee;
    bool public tradingEnabled;

    address public owner;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event FeesUpdated(uint newTaxFee, uint newDevelopmentFee);

    modifier onlyOwner {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    constructor() {
        owner = msg.sender;
        totalSupply = 1000000 * (10 ** uint256(decimals));
        balances[owner] = totalSupply;
        taxFee = 5; // Initial tax fee
        developmentFee = 3; // Initial development fee
    }

    function initializeToken() external {
        require(totalSupply > 0, "Total supply must be greater than zero");
        tradingEnabled = false; // Trading is initially disabled
    }

    function transferTokens(address _to, uint256 _value) external returns (bool) {
        require(tradingEnabled, "Trading is not enabled");
        require(balances[msg.sender] >= _value, "Insufficient balance");

        balances[msg.sender] -= _value;
        balances[_to] += _value;

        emit Transfer(msg.sender, _to, _value);
        return true;
    }

    function approveAllowance(address _spender, uint256 _value) external returns (bool) {
        emit Approval(msg.sender, _spender, _value);
        return true;
    }

    function updateFees(uint _newTaxFee, uint _newDevelopmentFee) external onlyOwner {
        taxFee = _newTaxFee;
        developmentFee = _newDevelopmentFee;
        emit FeesUpdated(_newTaxFee, _newDevelopmentFee);
    }

    function enableTrading() external onlyOwner {
        tradingEnabled = true;
    }

    function disableTrading() external onlyOwner {
        tradingEnabled = false;
    }

    function startManagingFees() external onlyOwner {
        // implementation for fee management initialization (if needed)
    }
}

