// SPDX-License-Identifier: MIT
pragma solidity ^0.8.10;

interface IERC20 {
    function approve(address spender, uint256 amount) external returns (bool);
    function transfer(address recipient, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
}

contract ERC20CompoundPCVDeposit {
    enum State { FundsAwaitingDeposit, FundsSuccessfullyDeposited }
    State public currentState;

    IERC20 public token;
    IERC20 public cToken;

    event Deposit();

    constructor(address _token, address _cToken) {
        token = IERC20(_token);
        cToken = IERC20(_cToken);
        currentState = State.FundsAwaitingDeposit;
    }

    modifier onlyInState(State _state) {
        require(currentState == _state, "Invalid state for this operation.");
        _;
    }

    function approveAndDeposit(uint256 amount) external onlyInState(State.FundsAwaitingDeposit) {
