pragma solidity ^0.8.7;

contract NFTMintingContract {
    string public baseURI;
    uint public mintPrice;
    uint public maxSupply;
    bool public isMintable;
    uint public currentSupply;

    event Minted(address indexed to, uint tokenId);
    event BaseURISet(string newBaseURI);
    event LastMinted();

    constructor(string memory _baseURI, uint _mintPrice, uint _maxSupply) {
        baseURI = _baseURI;
        mintPrice = _mintPrice;
        maxSupply = _maxSupply;
        isMintable = true;
        currentSupply = 0;
    }

    function mint() external payable {
        require(isMintable, "Minting is not allowed");
        require(currentSupply < maxSupply, "Max supply reached");
        require(msg.value >= mintPrice, "Insufficient payment");

        currentSupply++;
        emit Minted(msg.sender, currentSupply);
    }

    function setMintableStatus(bool _status) external {
        isMintable = _status;
    }

    function setBaseURI(string calldata _newBaseURI) external {
        baseURI = _newBaseURI;
        emit BaseURISet(_newBaseURI);
    }

    function setMintPrice(uint _newMintPrice) external {
        mintPrice = _newMintPrice;
    }

    function lastMinted() external {
        require(currentSupply >= maxSupply, "Max supply not reached");
        emit LastMinted();
    }
}

