contract PotatoPals {
    enum State { OFF, ALLOWLIST, PUBLIC }
    State public currentState;

    string public potatoUrl;
    address public farm;
    uint public batch;
    uint public water;
    mapping(address => bool) public allowlist;

    event NFTMinted(address indexed to);
    event FundsHarvested(address indexed owner, uint amount);
    event SproutStatusChanged(State newState);

    constructor() {
        currentState = State.OFF;
    }

    modifier onlyInState(State _state) {
        require(currentState == _state, "Invalid state for this operation");
        _;
    }

    function actionStartAllowlistMinting() external {
        currentState = State.ALLOWLIST;
        emit SproutStatusChanged(currentState);
    }

    function actionStartPublicMinting() external onlyInState(State.ALLOWLIST) {
        currentState = State.PUBLIC;
        emit SproutStatusChanged(currentState);
    }

    function actionMintAllowlistNFT() external onlyInState(State.ALLOWLIST) {
        require(allowlist[msg.sender], "Not on allowlist");
        emit NFTMinted(msg.sender);
    }

    function actionMintPublicNFT() external onlyInState(State.PUBLIC) {
        emit NFTMinted(msg.sender);
    }

    function actionStopMinting() external onlyInState(State.PUBLIC) {
        currentState = State.OFF;
        emit SproutStatusChanged(currentState);
    }

    function setPotatoUrl(string calldata _url) external {
        potatoUrl = _url;
    }

    function setFarm(address _farm) external {
        farm = _farm;
    }

    function setBatch(uint _batch) external {
        batch = _batch;
    }

    function setWater(uint _water) external {
        water = _water;
    }

    function updateAllowlist(address _user, bool _status) external {
        allowlist[_user] = _status;
    }

    function harvestFunds() external {
        uint amount = address(this).balance; 
        payable(farm).transfer(amount);
        emit FundsHarvested(farm, amount);
    }
}

