// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract NFA_Token_Contract {
    string public name = "Not Financial Advice Token";
    string public symbol = "NFA";
    uint256 public totalSupply;

    mapping(address => uint256) public accountBalances;
    mapping(address => bool) public blacklistedAccounts;

    uint256 public taxFee;
    uint256 public developmentFee;

    enum State { Contract_Initialization, Trading_Disabled, Trading_Enabled }
    State public currentState;

    event TokenTransfer(address indexed from, address indexed to, uint256 value);
    event FeeUpdate(uint256 taxFee, uint256 developmentFee);
    event LiquidityManagement(uint256 amountIn, uint256 amountOut);

    constructor() {
        totalSupply = 1000000 * 10 ** 18; // Initial supply
        accountBalances[msg.sender] = totalSupply; // Assign all tokens to the deployer
        currentState = State.Contract_Initialization;
        taxFee = 5; // 5%
        developmentFee = 2; // 2%
    }

    function initializeTokenSupply() public {
        require(currentState == State.Contract_Initialization, "Contract not in initialization state.");
        currentState = State.Trading_Disabled;
    }

    function enableTrading() public {
        require(currentState == State.Trading_Disabled, "Trading already enabled.");
        currentState = State.Trading_Enabled;
    }

    function transferTokens(address to, uint256 amount) public {
        require(currentState == State.Trading_Enabled, "Trading is disabled.");
        require(accountBalances[msg.sender] >= amount, "Insufficient balance.");
        require(!blacklistedAccounts[msg.sender] && !blacklistedAccounts[to], "Account is blacklisted.");
        require(amount <= (totalSupply * 5) / 100, "Amount exceeds max transaction limit."); // Example limit: 5% of total supply

        accountBalances[msg.sender] -= amount;
        accountBalances[to] += amount;

        emit TokenTransfer(msg.sender, to, amount);
    }

    function setFees(uint256 _taxFee, uint256 _developmentFee) public {
        require(currentState == State.Trading_Enabled, "Trading is not enabled.");
        taxFee = _taxFee;
        developmentFee = _developmentFee;

        emit FeeUpdate(taxFee, developmentFee);
    }

    function swapTokensForETH(uint256 tokenAmount) public {
        require(currentState == State.Trading_Enabled, "Trading is not enabled.");
        // Swap logic would go here. For illustration, just emitted event.
        emit LiquidityManagement(tokenAmount, tokenAmount / 2); // Mocking the swap result.
    }
}

