pragma solidity ^0.8.10;

contract NFTMintingContract {
    enum MintPhase { DevPhase, PublicPhase, ClosedPhase }

    MintPhase public mintPhase;
    uint public publicPrice;
    uint public expiryDate;
    string public jsonAddress;

    address public owner;

    event MintingAction(address indexed minter, uint amount);
    event BalanceWithdrawn(address indexed owner, uint amount);

    modifier ownerOnly() {
        require(msg.sender == owner, "Only owner can perform this action");
        _;
    }

    modifier paymentReceived() {
        require(msg.value >= publicPrice, "Insufficient payment");
        _;
    }

    constructor(uint _publicPrice) {
        publicPrice = _publicPrice;
        mintPhase = MintPhase.DevPhase;
        owner = msg.sender;
    }

    function devMint() external ownerOnly {
        // Logic for owner minting NFTs
        emit MintingAction(msg.sender, 1); // Example action
    }

    function mint() external payable paymentReceived {
        require(mintPhase == MintPhase.PublicPhase, "Minting is not allowed in the current phase");
        // Logic for users minting NFTs
        emit MintingAction(msg.sender, 1); // Example action
    }

    function setJsonAddress(string calldata _jsonAddress) external ownerOnly {
        jsonAddress = _jsonAddress;
    }

    function setExpiryDate(uint _expiryDate) external ownerOnly {
        expiryDate = _expiryDate;
    }

    function changeMintPhase() external ownerOnly {
        if (mintPhase == MintPhase.DevPhase) {
            mintPhase = MintPhase.PublicPhase;
        } else if (mintPhase == MintPhase.PublicPhase) {
            mintPhase = MintPhase.ClosedPhase;
        } else {
            revert("Cannot change from Closed Phase");
        }
    }

    function withdrawBalance() external ownerOnly {
        uint balance = address(this).balance;
        payable(owner).transfer(balance);
        emit BalanceWithdrawn(owner, balance);
    }
}

