    State public currentState;

    event SwapAndLiquifyUpdated(uint256 tokensSwapped, uint256 ethReceived, uint256 tokensIntoLiqudity);

    constructor() ERC20("META HORNET DAO", "HORN") {
        _mint(msg.sender, totalSupply);
        currentState = State.PreTrade;
    }

    modifier onlyWhenTrading() {
        require(tradingAllowed, "Trading is not allowed yet.");
        require(!botDetected[msg.sender], "Bot transactions are blocked.");
        _;
    }

    function allowTrading() external onlyOwner {
        require(currentState == State.PreTrade, "Cannot enable trading from current state.");
        tradingAllowed = true;
        currentState = State.Trading;
    }

    function swapAndLiquify(uint256 amount) external onlyOwner {
        require(liquidityEnabled, "Liquidity is disabled.");
        // Logic for swapping and liquifying tokens
        emit SwapAndLiquifyUpdated(amount, 0, amount); // Placeholder values
    }

    function _transfer(address sender, address recipient, uint256 amount) internal override onlyWhenTrading {
        uint256 taxAmount = (amount * taxFee) / 100;
        uint256 liquidityAmount = (amount * liquidityFee) / 100;
        uint256 transferAmount = amount - taxAmount - liquidityAmount;

        super._transfer(sender, recipient, transferAmount);
        // Logic to handle tax and liquidity (send to marketing wallet or liquidity pool)
    }

    function approve(address spender, uint256 amount) public virtual override returns (bool) {
        return super.approve(spender, amount);
    }

    function airdrop(address[] calldata recipients, uint256 amount) external onlyOwner {
        for (uint256 i = 0; i < recipients.length; i++) {
            _transfer(msg.sender, recipients[i], amount);
        }
    }

    function setBotStatus(address bot, bool status) external onlyOwner {
        botDetected[bot] = status;
    }

    function setLiquidityEnabled(bool status) external onlyOwner {
        liquidityEnabled = status;
    }
}

