pragma solidity ^0.8.7;

contract TieDyeNinjas {
    uint public totalTokensToMint = 1000;
    bool public isMintingActive = true;
    uint public rewardEndingTime = 0;
    mapping(address => bool) public claimedPerID;

    address public owner;

    event BuyNFT(address indexed buyer, uint amount);
    event ClaimReward(address indexed claimant);
    event CustomThing();

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function buy(uint amount) external {
        require(isMintingActive, "Minting is not active");
        require(totalTokensToMint >= amount, "Not enough tokens to mint");

        totalTokensToMint -= amount;
        emit BuyNFT(msg.sender, amount);
    }

    function getReward() external {
        require(block.timestamp <= rewardEndingTime, "Reward claiming period has ended");
        require(!claimedPerID[msg.sender], "Reward already claimed");

        claimedPerID[msg.sender] = true;
        emit ClaimReward(msg.sender);
    }

    function adminMint(uint amount) external onlyOwner {
        require(totalTokensToMint > 0, "No tokens to mint");

        totalTokensToMint += amount;
    }

    function startRewardClaiming(uint duration) external onlyOwner {
        rewardEndingTime = block.timestamp + duration;
    }

    function endMinting() external onlyOwner {
        isMintingActive = false;
    }

    function endRewardClaiming() external onlyOwner {
        rewardEndingTime = 0;
    }

    function resetContract() external onlyOwner {
        isMintingActive = true;
        totalTokensToMint = 1000;
        rewardEndingTime = 0;
        for (uint i = 0; i < 10; i++) { // Assuming a fix or limit, could be optimized
            // Resetting is done manually, for demo purposes (mapping cannot be reset in bulk)
        }
    }

    function emitCustomThing() external {
        emit CustomThing();
    }
}

