pragma solidity ^0.8.6;

contract TokenSwapContract {
    mapping(address => bool) public owner;
    address public uniswapRouter;
    address public WETH;
    address public token;

    enum State { Initialization, Swapping, Withdrawal }
    State public currentState;

    event ApproveTokensEvent();
    event SwapETHforTokensEvent();
    event SwapTokensforETHEvent();
    event EmergencyWithdrawEvent();
    event WithdrawCompleteEvent();

    modifier onlyOwner() {
        require(owner[msg.sender], "Not authorized");
        _;
    }

    constructor(address _uniswapRouter, address _WETH, address _token) {
        owner[msg.sender] = true; // Set deployer as owner
        uniswapRouter = _uniswapRouter;
        WETH = _WETH;
        token = _token;
        currentState = State.Initialization;
    }

    function approveTokens() external onlyOwner {
        // Logic for approving tokens
        emit ApproveTokensEvent();
        currentState = State.Swapping;
    }

    function swapETHforTokens() external payable {
        require(currentState == State.Swapping, "Not in swapping state");
        // Logic for swapping ETH for tokens
        emit SwapETHforTokensEvent();
    }

    function swapTokensforETH(uint256 tokenAmount) external {
        require(currentState == State.Swapping, "Not in swapping state");
        // Logic for swapping tokens for ETH
        emit SwapTokensforETHEvent();
    }

    function withdrawTokens() external onlyOwner {
        // Logic for emergency token or ETH withdrawal
        emit EmergencyWithdrawEvent();
        currentState = State.Withdrawal;
    }

    function completeWithdrawal() external onlyOwner {
        // Logic to complete withdrawal
        emit WithdrawCompleteEvent();
        currentState = State.Initialization;
    }
}

