    event MetadataRevealed(string baseURI);

    modifier onlyWhenNotPaused() {
        require(!paused, "Contract is paused");
        _;
    }

    constructor() {
        currentState = State.Paused;
    }

    function mintToken() external onlyWhenNotPaused {
        // Minting logic here

        emit TokenMinted(msg.sender, /* tokenId */ 0); // Placeholder tokenId
    }

    function revealTokenMetadata() external {
        require(currentState == State.MintingOpen, "Metadata can only be revealed during minting");
        revealed = true;
        currentState = State.Revealed;
        emit MetadataRevealed(baseURI);
    }

    function setPaused(bool _paused) external {
        paused = _paused;
        if (_paused) {
            currentState = State.Paused;
        } else {
            currentState = State.MintingOpen;
        }
    }

    function updateBaseURI(string calldata _baseURI) external {
        require(currentState == State.Revealed, "Can only update URI when revealed");
        baseURI = _baseURI;
    }
}

