pragma solidity ^0.8.9;

contract NFTSaleContract {
    enum State { Inactive, PresaleLive, SaleLive, Locked }
    State public currentState;

    uint public tokenLimitPresale = 100;
    uint public tokenLimitSale = 500;
    mapping(address => uint) public presalePurchaseLimits;

    event Purchase(address indexed buyer, uint indexed tokenId);
    event NFTMinted(address indexed to, uint indexed tokenId);
    event MetadataUpdated(string newMetadata);

    constructor() {
        currentState = State.Inactive;
    }

    modifier onlyInState(State _state) {
        require(currentState == _state, "Invalid contract state for this action.");
        _;
    }

    function togglePresale() external onlyInState(State.Inactive) {
        currentState = State.PresaleLive;
    }

    function toggleSale() external onlyInState(State.PresaleLive) {
        currentState = State.SaleLive;
    }

    function presaleBuy(uint tokenId) external onlyInState(State.PresaleLive) {
        require(presalePurchaseLimits[msg.sender] < tokenLimitPresale, "Exceeded presale limit.");
        presalePurchaseLimits[msg.sender]++;
        emit Purchase(msg.sender, tokenId);
        emit NFTMinted(msg.sender, tokenId);
    }

    function buy(uint tokenId) external onlyInState(State.SaleLive) {
        emit Purchase(msg.sender, tokenId);
        emit NFTMinted(msg.sender, tokenId);
    }

    function giftList(address recipient, uint tokenId) external onlyInState(State.SaleLive) {
        emit NFTMinted(recipient, tokenId);
    }

    function lockSale() external onlyInState(State.SaleLive) {
        currentState = State.Locked;
    }

    function updateMetadata(string calldata newMetadata) external onlyInState(State.Locked) {
        emit MetadataUpdated(newMetadata);
    }
}

