pragma solidity ^0.8.7;

contract NFTContract {
    string public baseURI;
    uint256 public Price;
    uint256 public maximumSupply;
    uint256 public maxMintTokens;
    bool public paused = true;
    bool public revealed = false;

    mapping(address => bool) public whitelisted;
    uint256 public totalSupply;

    enum SaleState { Paused, WhitelistSale, PublicSale }
    SaleState public currentState;

    event TokenMinted(address indexed to, uint256 tokenId);
    event SaleStateChanged(SaleState newState);
    event FundsWithdrawn(address indexed to, uint256 amount);

    modifier onlyOwner() {
        // Replace with actual owner check
        require(msg.sender == address(this), "Not the owner");
        _;
    }

    modifier onlyWhitelisted() {
        require(whitelisted[msg.sender], "Not whitelisted");
        _;
    }

    constructor() {
        currentState = SaleState.Paused;
    }

    function startWhitelistSale() external onlyOwner {
        currentState = SaleState.WhitelistSale;
        emit SaleStateChanged(currentState);
    }

    function startPublicSale() external onlyOwner {
        currentState = SaleState.PublicSale;
        emit SaleStateChanged(currentState);
    }

    function mint() external payable {
        require(!paused, "Contract is paused");
        require(totalSupply < maximumSupply, "Maximum supply reached");

        if (currentState == SaleState.WhitelistSale) {
            require(whitelisted[msg.sender], "You are not whitelisted");
        }

        // Minting logic here...

        totalSupply++;
        emit TokenMinted(msg.sender, totalSupply);
    }

    function reveal() external {
        require(totalSupply > 0, "No tokens minted");
        revealed = true;
    }

    function whitelistUser(address user) external onlyOwner {
        whitelisted[user] = true;
    }

    function withdraw() external onlyOwner {
        // Withdrawal logic (transfer to owner)...
        emit FundsWithdrawn(msg.sender, address(this).balance);
    }
}

