pragma solidity ^0.8.4;

contract ERC721TokenContract {
    enum State { Paused, Unpaused }
    State public state = State.Paused;

    uint public tokenID = 0;
    uint public ethPrice = 0;
    uint public maxSupply = 10000;
    address public withdrawalWallet;

    mapping(address => uint) public balances;
    mapping(uint => address) public tokenOwner;

    modifier onlyManager() {
        require(msg.sender == withdrawalWallet, "Not authorized");
        _;
    }

    event WithdrawEvent(address indexed wallet, uint amount);
    event UnpauseEvent();
    event MintEvent(address indexed to, uint tokenId);
    event PauseEvent();
    event ArtistMintEvent(address indexed artist, uint tokenId);
    event UpdateMetadataEvent();

    constructor(address _withdrawalWallet) {
        withdrawalWallet = _withdrawalWallet;
    }

    function mintNFT(address to) external {
        require(state == State.Unpaused, "Contract is paused");
        require(tokenID < maxSupply, "Max supply reached");

        tokenID++;
        tokenOwner[tokenID] = to;
        emit MintEvent(to, tokenID);
    }

    function withdrawFunds(uint amount) external onlyManager {
        payable(withdrawalWallet).transfer(amount);
        emit WithdrawEvent(withdrawalWallet, amount);
    }

    function pause() external onlyManager {
        state = State.Paused;
        emit PauseEvent();
    }

    function unpause() external onlyManager {
        state = State.Unpaused;
        emit UnpauseEvent();
    }

    function artistMint(address artist) external onlyManager {
        require(state == State.Paused, "Contract is not paused");

        tokenID++;
        tokenOwner[tokenID] = artist;
        emit ArtistMintEvent(artist, tokenID);
    }

    function updateMetadata() external onlyManager {
        emit UpdateMetadataEvent();
    }

    receive() external payable {}
}

