// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract NFTMintingContract {
    string public baseURI;
    uint public cost;
    uint public maxSupply;
    bool public paused = true;

    enum State { Paused, MintingActive, Revealed }
    State public currentState;

    event NFTMinted(address indexed owner, uint tokenId);
    event OwnershipVerified(address indexed owner);
    event MetadataUpdated(string newURI);

    constructor(string memory _baseURI, uint _cost, uint _maxSupply) {
        baseURI = _baseURI;
        cost = _cost;
        maxSupply = _maxSupply;
        currentState = State.Paused;
    }

    modifier whenNotPaused() {
        require(!paused, "Minting is paused");
        _;
    }

    modifier onlyDuringMinting() {
        require(currentState == State.MintingActive, "Not in minting state");
        _;
    }

    function startMinting() external {
        require(currentState == State.Paused, "Already in minting state");
        paused = false;
        currentState = State.MintingActive;
    }

    function mintNFT(uint tokenId) external whenNotPaused onlyDuringMinting {
        require(tokenId < maxSupply, "Exceeds max supply");
        // Logic for minting the NFT
        emit NFTMinted(msg.sender, tokenId);
    }

    function completeMinting() external onlyDuringMinting {
        currentState = State.Revealed;
    }

    function updateMetadata(string calldata newURI) external {
        require(currentState == State.Revealed, "Metadata can only be updated after revealing");
        baseURI = newURI;
        emit MetadataUpdated(newURI);
    }
}

