pragma solidity ^0.8.0;

/// @author Hammad Ghazi
contract LoveTSUBAME is ERC721Enumerable, Ownable {
    using Counters for Counters.Counter;
    Counters.Counter private _tokenId;

    uint256 public constant MAX_TSUBAME = 10000;
    uint256 public price = 80000000000000000; //0.08 Ether
    string baseTokenURI;
    bool public saleOpen = false;
    bool public presaleOpen = false;
    mapping(address => bool) public whitelistAddr;

    event LoveTsubameMinted(uint256 totalMinted);

    constructor(string memory baseURI) ERC721("Love TSUBAME", "TSUBAME") {
        setBaseURI(baseURI);
    }

    function setPrice(uint256 _newPrice) external onlyOwner {
        price = _newPrice;
    }

    //Close sale if open, open sale if closed
    function flipSaleState() external onlyOwner {
        saleOpen = !saleOpen;
    }

    function flipPresaleState() external onlyOwner {
        presaleOpen = !presaleOpen;
    }

    function withdrawAll() external onlyOwner {
        (bool success, ) = msg.sender.call{value: address(this).balance}("");
        require(success, "Transfer failed.");
    }

    function whitelistAddress(address[] calldata users) external onlyOwner {
        for (uint256 i = 0; i < users.length; i++) {
            whitelistAddr[users[i]] = true;
        }
    }

    function presaleMint(uint256 _count) external payable {
        require(
            whitelistAddr[msg.sender] == true,
            "Address not eligible for presale mint"
        );
        require(presaleOpen, "Presale is not open yet");
        require(
            _count > 0 && _count <= 5,
            "Minimum 1 and Maximum 5 LoveTSUBAME can be minted per address in presale"
        );
        require(
            5 >= walletOfOwner(msg.sender).length + _count,
            "Purchase will exceed max presale mint amount per address"
        );
        require(
            msg.value >= price * _count,
            "Ether sent with this transaction is not correct"
        );

        if (walletOfOwner(msg.sender).length + _count == 5) {
            whitelistAddr[msg.sender] = false;
        }
        address to = msg.sender;
        for (uint256 i = 0; i < _count; i++) {
            _mint(to);
        }
    }

    //mint LoveTSUBAME
    function mintLoveTsubame(address _to, uint256 _count) external payable {
        require(
            totalSupply() + _count <= MAX_TSUBAME,
            "Exceeds maximum supply of LoveTSUBAME"
        );
        require(
            _count > 0,
            "Minimum 1 LoveTSUBAME has to be minted per transaction"
        );
        if (msg.sender != owner()) {
            require(saleOpen, "Sale is not open yet");
            require(
                _count <= 20,
                "Maximum 20 LoveTSUBAME can be minted per transaction"
            );
            require(
                msg.value >= price * _count,
                "Ether sent with this transaction is not correct"
            );
        }

        for (uint256 i = 0; i < _count; i++) {
            _mint(_to);
        }
    }

    //Get token Ids of all tokens owned by _owner
    function walletOfOwner(address _owner)
        public
        view
        returns (uint256[] memory)
    {
        uint256 tokenCount = balanceOf(_owner);

        uint256[] memory tokensId = new uint256[](tokenCount);
        for (uint256 i = 0; i < tokenCount; i++) {
            tokensId[i] = tokenOfOwnerByIndex(_owner, i);
        }

        return tokensId;
    }

    function setBaseURI(string memory baseURI) public onlyOwner {
        baseTokenURI = baseURI;
    }

    function _mint(address _to) private {
        _tokenId.increment();
        uint256 tokenId = _tokenId.current();
        _safeMint(_to, tokenId);
        emit LoveTsubameMinted(tokenId);
    }

    function _baseURI() internal view virtual override returns (string memory) {
        return baseTokenURI;
    }
}

