    constructor(bytes32 _merkleRoot) {
        merkleRoot = _merkleRoot;
        saleState = SaleState.PresaleNotStarted;
    }

    function toggleSaleStarted() external onlyOwner {
        if (saleState == SaleState.PresaleNotStarted) {
            saleState = SaleState.PresaleOpen;
        } else if (saleState == SaleState.PresaleOpen) {
            saleState = SaleState.SaleNotStarted;
        } else if (saleState == SaleState.SaleNotStarted) {
            saleState = SaleState.SaleOpen;
        } else {
            saleState = SaleState.SaleNotStarted;
        }
    }

    function presaleMint(bytes32[] calldata merkleProof) external {
        require(saleState == SaleState.PresaleOpen, "Presale is not open");
        // Add Merkle proof verification logic here
        presaleCount++;
        emit PresaleMinted(msg.sender, currentMintId);
        currentMintId++;
    }

    function mint() external payable {
        require(saleState == SaleState.SaleOpen, "Sale is not open");
        require(msg.value >= _price, "Insufficient Ether sent");
        emit Minted(msg.sender, currentMintId);
        currentMintId++;
    }

    function claimReserved() external onlyOwner {
        // Add logic for the owner to claim reserved tokens here
    }
}

