// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract NFTTokenContract {
    uint[] private _tokenIds;
    uint private _mintCost;
    uint private _maxSupply;
    bool private _isPublicMintEnabled;

    enum SaleState { SaleActive, SalePaused, Minting }
    SaleState public saleState;

    event EventSalePaused();
    event EventSaleActive();
    event EventMintTokens(address indexed to, uint tokenId);
    event EventMintComplete(address indexed to, uint tokenId);

    constructor(uint mintCost, uint maxSupply) {
        _mintCost = mintCost;
        _maxSupply = maxSupply;
        _isPublicMintEnabled = false;
        saleState = SaleState.SaleActive;
    }

    modifier whenSaleActive() {
        require(saleState == SaleState.SaleActive, "Sale is not active");
        _;
    }

    modifier whenSalePaused() {
        require(saleState == SaleState.SalePaused, "Sale is not paused");
        _;
    }

    function mintTokens() external payable whenSaleActive {
        require(_isPublicMintEnabled, "Public minting is not enabled");
        require(_tokenIds.length < _maxSupply, "Max supply reached");
        require(msg.value >= _mintCost, "Insufficient payment");

        uint tokenId = _tokenIds.length + 1;
        _tokenIds.push(tokenId);

        emit EventMintTokens(msg.sender, tokenId);
    }

    function flipSaleState() external {
        if (saleState == SaleState.SaleActive) {
            saleState = SaleState.SalePaused;
            emit EventSalePaused();
        } else {
            saleState = SaleState.SaleActive;
            emit EventSaleActive();
        }
    }

    function setCost(uint newCost) external {
        _mintCost = newCost;
    }

    function setMaxSupply(uint newMaxSupply) external {
        _maxSupply = newMaxSupply;
    }

    function setBaseTokenURI(string calldata baseURI) external {
        // Implementation for setting the base URI for tokens.
    }

    function enablePublicMint() external {
        _isPublicMintEnabled = true;
    }

    function completeMinting() external whenSaleActive {
        // Logic to finalize the minting process.
        emit EventMintComplete(msg.sender, _tokenIds[_tokenIds.length - 1]);
    }
}

