    State public currentState;

    event LeafEscrowFunded();
    event RoleUpdated();

    constructor() {
        PRICE_RATE = 0;
        openSupply = 1000000;
        START_TIME = block.timestamp;
        currentState = State.OpenSupply;
    }

    modifier onlyInState(State expectedState) {
        require(currentState == expectedState, "Invalid state");
        _;
    }

    function mint() external onlyInState(State.OpenSupply) {
        require(openSupply > 0, "Open supply limit reached");
        // Logic to mint tokens
        // Deduct from openSupply
        openSupply--;
        if (openSupply == 0) {
            currentState = State.TokenPurchase;
        }
    }

    function spendCoins(address contractAddress) external onlyInState(State.TokenPurchase) {
        require(approvedContracts[contractAddress], "Contract not approved");
        // Logic for spending tokens
    }

    function adjustRate(uint newRate) external onlyInState(State.RoleManagement) {
        PRICE_RATE = newRate;
        // Emit an event if needed
    }

    function updateRole(address user, bool isApproved) external onlyInState(State.RoleManagement) {
        approvedContracts[user] = isApproved;
        emit RoleUpdated();
    }

    function enterRoleManagement() external onlyInState(State.TokenPurchase) {
        currentState = State.RoleManagement;
    }

    function enterOpenSupply() external onlyInState(State.RoleManagement) {
        currentState = State.OpenSupply;
    }
}

