pragma solidity ^0.8.9;

contract USDTDAOContract {
    enum State { ClaimPeriodActive, ClaimPeriodEnded }
    State public currentState;

    uint public claimPeriodStart;
    uint public claimPeriodEnd;
    uint public totalUsersClaimed;
    mapping(address => bool) public claimed;

    event Claim(address indexed user);

    constructor(uint _claimPeriodStart, uint _claimPeriodEnd) {
        require(_claimPeriodStart < _claimPeriodEnd, "Invalid claim period");
        claimPeriodStart = _claimPeriodStart;
        claimPeriodEnd = _claimPeriodEnd;
        currentState = State.ClaimPeriodActive;
    }

    modifier onlyDuringClaimPeriod() {
        require(currentState == State.ClaimPeriodActive, "Claim period has ended");
        require(block.timestamp >= claimPeriodStart && block.timestamp <= claimPeriodEnd, "Not within claim period");
        _;
    }

    modifier onlyOwner() {
        require(msg.sender == address(this), "Not the owner");
        _;
    }

    function claimTokens() external onlyDuringClaimPeriod {
        require(!claimed[msg.sender], "You have already claimed tokens");
        claimed[msg.sender] = true;
        totalUsersClaimed++;
        emit Claim(msg.sender);
        // Token transfer logic can be implemented here
    }

    function withdrawTokens() external onlyOwner {
        require(currentState == State.ClaimPeriodEnded, "Claim period is still active");
        // Withdraw logic can be implemented here
    }

    function endClaimPeriod() external onlyOwner {
        require(currentState == State.ClaimPeriodActive, "Claim period already ended");
        currentState = State.ClaimPeriodEnded;
    }

    function hasClaimed(address user) external view returns (bool) {
        return claimed[user];
    }

    function getTotalUsersClaimed() external view returns (uint) {
        return totalUsersClaimed;
    }
}

