import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract TokenContract is ERC20, Ownable {
    enum State { PreTrading, TradingActive, TokenSwaps }
    State public currentState;

    uint public totalSupply = 1000000 * (10 ** decimals());
    mapping(address => uint) public balances;
    mapping(address => mapping(address => uint)) public allowances;
    uint public fees = 5; // 5 percent fee
    address[] public walletAddresses;

    event FeeModified(uint newFee);
    event Transfer(address indexed from, address indexed to, uint value);
    event WalletAddressUpdated(address indexed wallet);

    constructor() ERC20("Token", "TKN") {
        currentState = State.PreTrading;
        balances[msg.sender] = totalSupply;
    }

    function activateTrading() external onlyOwner {
        require(currentState == State.PreTrading, "Trading is already active.");
        currentState = State.TradingActive;
    }

    function executeTransfer(address to, uint amount) external {
        require(currentState == State.TradingActive || currentState == State.TokenSwaps, "Transfers are not allowed currently.");
        require(balances[msg.sender] >= amount, "Insufficient balance.");

        uint feeAmount = (amount * fees) / 100;
        uint transferAmount = amount - feeAmount;

        balances[msg.sender] -= amount;
        balances[to] += transferAmount;

        emit Transfer(msg.sender, to, transferAmount);
    }

    function updateFees(uint newFee) external onlyOwner {
        fees = newFee;
        emit FeeModified(newFee);
    }

    function processTransaction(address buyer, address seller, uint amount) external {
        require(currentState == State.TokenSwaps, "Token swaps are not allowed currently.");
        // Implementation for buy/sell logic here
    }
}

