        require(saleStatus == SaleStatus.MAINSALE || (saleStatus == SaleStatus.PRESALE && isAllowed(msg.sender)), "Minting not allowed.");
        _mint(msg.sender, tokenId);
        emit MintRequest(msg.sender, tokenId);
        emit MintFulfilled(msg.sender, tokenId);
    }

    function configureCategory(string memory categoryName, uint price, uint supply) external onlyOwner {
        categories[categoryName] = Category(price, supply);
