pragma solidity ^0.8.7;

contract FuzzyPenguins {
    uint public constant MAX_SUPPLY = 10000;
    uint public constant AIRDROP_QUANTITY = 1000;

    bool public isPublicSaleOpen = false;
    bool public isPreSaleOpen = false;

    mapping(address => bool) public presaleWallets;

    event PreSaleToggled(bool isOpen);
    event PublicSaleToggled(bool isOpen);
    event MintSuccessful(address to, uint quantity);

    modifier onlyOwner() {
        // Assume the owner is the deployer for demonstration purpose
        require(msg.sender == address(this), "Not the contract owner");
        _;
    }

    function actionTogglePreSale() external onlyOwner {
        isPreSaleOpen = !isPreSaleOpen;
        emit PreSaleToggled(isPreSaleOpen);
    }

    function actionTogglePublicSale() external onlyOwner {
        isPublicSaleOpen = !isPublicSaleOpen;
        emit PublicSaleToggled(isPublicSaleOpen);
    }

    function actionStartPublicSale() external onlyOwner {
        require(isPreSaleOpen == false, "Pre-sale must be closed to start public sale");
        isPublicSaleOpen = true;
        emit PublicSaleToggled(isPublicSaleOpen);
    }

    function actionMintAirdrop() external {
        require(isPublicSaleOpen == false && isPreSaleOpen == false, "Airdrop can only be minted when both sales are closed");
        // Mint logic for airdrop
        emit MintSuccessful(msg.sender, AIRDROP_QUANTITY);
    }

    function actionMintPresale() external {
        require(isPreSaleOpen, "Pre-sale is not open");
        require(presaleWallets[msg.sender], "Address not whitelisted for pre-sale");
        // Mint logic for pre-sale
        emit MintSuccessful(msg.sender, 1); // example quantity
    }

    function actionMintPublic() external {
        require(isPublicSaleOpen, "Public sale is not open");
        // Mint logic for public sale
        emit MintSuccessful(msg.sender, 1); // example quantity
    }

    function addPresaleWallet(address _wallet) external onlyOwner {
        presaleWallets[_wallet] = true;
    }

    function removePresaleWallet(address _wallet) external onlyOwner {
        presaleWallets[_wallet] = false;
    }
}

