pragma solidity ^0.8.3;

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721Enumerable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract ERC721TokenContract is ERC721Enumerable, Ownable {
    uint public tokenId;
    mapping(uint => string) public attributes;
    uint public pricing;

    enum State { TokenMinting, AttributeChanging, TokenManagement }
    State public currentState = State.TokenMinting;

    event NameChange(uint indexed tokenId, string newName);
    event MessageChange(uint indexed tokenId, string newMessage);
    event MultiplierChange(uint indexed tokenId, uint newMultiplier);

    constructor() ERC721("MyNFT", "NFT") {
        pricing = 0.01 ether; // example pricing
    }

    modifier maxSupplyNotReached() {
        require(totalSupply() < 10000, "Maximum supply reached");
        _;
    }

    modifier isOwner(uint _tokenId) {
        require(ownerOf(_tokenId) == msg.sender, "Not the token owner");
        _;
    }

    modifier isOwnerAndPaidFee(uint _fee) {
        require(ownerOf(tokenId) == msg.sender, "Not the token owner");
        require(msg.value >= _fee, "Insufficient payment");
        _;
    }

    function mintToken() external payable maxSupplyNotReached {
        tokenId++;
        _mint(msg.sender, tokenId);
        currentState = State.TokenManagement;
    }

    function changeName(uint _tokenId, string calldata newName) external isOwner(_tokenId) {
        attributes[_tokenId] = newName;
        emit NameChange(_tokenId, newName);
        currentState = State.TokenManagement;
    }

    function changeMessage(uint _tokenId, string calldata newMessage) external isOwner(_tokenId) {
        attributes[_tokenId] = newMessage;
        emit MessageChange(_tokenId, newMessage);
        currentState = State.TokenManagement;
    }

    function upgradeMultiplier(uint _tokenId, uint newMultiplier) external payable isOwnerAndPaidFee(pricing) {
        // Logic to upgrade multiplier
        emit MultiplierChange(_tokenId, newMultiplier);
    }

    receive() external payable {}
}

