contract TokenContract {
    uint public MIN_TOKEN_ID = 1;
    uint public MAX_TOKEN_ID = 10000;
    bool public MINT_IS_ACTIVE = false;
    uint public TOTEM_MINT_PRICE = 0.05 ether;

    event Mint(address indexed owner, uint tokenId);
    event TotemMintPriceUpdate(uint newPrice);
    event MintFlagUpdate(bool isActive);

    modifier onlyOwner() {
        require(msg.sender == address(this), "Not the contract owner");
        _;
    }

    function flipMintFlag() public onlyOwner {
        MINT_IS_ACTIVE = !MINT_IS_ACTIVE;
        emit MintFlagUpdate(MINT_IS_ACTIVE);
    }

    function setNewMintPrice(uint _newPrice) public onlyOwner {
        TOTEM_MINT_PRICE = _newPrice;
        emit TotemMintPriceUpdate(_newPrice);
    }

    function mint(uint tokenId) public payable {
        require(MINT_IS_ACTIVE, "Minting is not active");
        require(tokenId >= MIN_TOKEN_ID && tokenId <= MAX_TOKEN_ID, "Invalid token ID");
        require(msg.value >= TOTEM_MINT_PRICE, "Insufficient payment");

        // Logic to mint the NFT would go here
        emit Mint(msg.sender, tokenId);
    }

    function burn(uint tokenId) public onlyOwner {
        // Logic to burn the NFT would go here
    }
}

