contract TokenContract {
    uint public minSupply;
    address public beneficiary;
    bool public feesEnabled;
    mapping(address => bool) public isExcludedFromFee;

    event MinSupplyUpdated(uint newMinSupply);
    event BeneficiaryUpdated(address newBeneficiary);
    event FeesEnabledUpdated(bool enabled);
    event ExcludedFromFeeUpdated(address account, bool isExcluded);

    constructor(uint _minSupply, address _beneficiary) {
        minSupply = _minSupply;
        beneficiary = _beneficiary;
        feesEnabled = false;
    }

    function handleTransfer(address sender, address recipient, uint amount) external {
        if (feesEnabled && !isExcludedFromFee[sender]) {
            uint fee = calculateFee(amount);
            transfer(beneficiary, fee);
            transfer(recipient, amount - fee);
        } else {
            transfer(recipient, amount);
        }
    }

    function burnTokens(uint amount) external {
        require(totalSupply() > minSupply, "Cannot burn below min supply");
        _burn(msg.sender, amount);
    }

    function updateFeesEnabled(bool _enabled) external {
        feesEnabled = _enabled;
        emit FeesEnabledUpdated(_enabled);
    }

    function updateBeneficiary(address _beneficiary) external {
        beneficiary = _beneficiary;
        emit BeneficiaryUpdated(_beneficiary);
    }

    function excludeAccountFromFee(address account, bool _isExcluded) external {
        isExcludedFromFee[account] = _isExcluded;
        emit ExcludedFromFeeUpdated(account, _isExcluded);
    }

    function updateMinSupply(uint _minSupply) external {
        minSupply = _minSupply;
        emit MinSupplyUpdated(_minSupply);
