pragma solidity ^0.8.0;

contract TokenContract {
    // State variables
    uint public INITIAL_SUPPLY = 1000000;
    bytes32 public constant BURNER_ROLE = keccak256("BURNER_ROLE");
    mapping(address => bytes32) public accountRoles;
    mapping(address => uint) public balances;

    enum State { Initialized, Active }
    State public currentState;

    event Transfer(address indexed from, address indexed to, uint256 value);

    constructor() {
        currentState = State.Initialized;
        mintTokens(msg.sender, INITIAL_SUPPLY);
    }

    modifier onlyBurner() {
        require(accountRoles[msg.sender] == BURNER_ROLE, "Caller is not a burner");
        _;
    }

    function mintTokens(address to, uint amount) internal {
        require(currentState == State.Initialized, "Contract is not in Initialized state");
        balances[to] += amount;
        emit Transfer(address(0), to, amount);
        currentState = State.Active;
    }

    function burnTokens(uint amount) external onlyBurner {
        require(currentState == State.Active, "Contract is not in Active state");
        require(balances[msg.sender] >= amount, "Insufficient balance to burn");

        balances[msg.sender] -= amount;
        emit Transfer(msg.sender, address(0), amount);
    }

    function createSnapshot() external {
        require(currentState == State.Active, "Contract is not in Active state");
        // Implement snapshot logic
    }

    function transferAndCall(address to, uint amount, bytes calldata data) external {
        require(currentState == State.Active, "Contract is not in Active state");
        require(balances[msg.sender] >= amount, "Insufficient balance to transfer");

        balances[msg.sender] -= amount;
        balances[to] += amount;
        emit Transfer(msg.sender, to, amount);

        // Call the recipient address (if it's a contract)
        (bool success, ) = to.call(data);
        require(success, "Transfer failed");
    }
}

