pragma solidity ^0.8.6;

contract WhalezToken {
    address public diatomDAO;
    address public minter;
    bool public isMinterLocked;
    uint public maxSupply = 10000;
    uint private _currentWhaleId;

    event WhaleCreated(uint indexed whaleId);
    event WhaleBurned(uint indexed whaleId);
    event DiatomDAOUpdated(address indexed newDiatomDAO);
    event MinterUpdated(address indexed newMinter);
    event MinterLocked();

    modifier onlyMinter() {
        require(msg.sender == minter, "Not the minter");
        _;
    }

    modifier onlyOwner() {
        require(msg.sender == diatomDAO, "Not the owner");
        _;
    }

    constructor(address _diatomDAO) {
        diatomDAO = _diatomDAO;
        isMinterLocked = false;
    }

    function setMinter(address _minter) external onlyOwner {
        require(!isMinterLocked, "Minter is locked");
        minter = _minter;
        emit MinterUpdated(_minter);
    }

    function setDiatomDAO(address _dao) external onlyOwner {
        diatomDAO = _dao;
        emit DiatomDAOUpdated(_dao);
    }

    function lockMinter() external onlyOwner {
        isMinterLocked = true;
        emit MinterLocked();
    }

    function mint() external onlyMinter {
        require(_currentWhaleId < maxSupply, "Max supply reached");
        _currentWhaleId++;
        emit WhaleCreated(_currentWhaleId);
    }

    function burn(uint whaleId) external onlyMinter {
        // Logic to burn the token (to be implemented)
        emit WhaleBurned(whaleId);
    }
}

