pragma solidity ^0.8.0;

contract HellHoundsToken {
    bool public presaleActive = false;
    bool public saleActive = false;
    uint public price = 0;
    mapping(address => uint) public claimedVouchers;
    string public baseTokenURI;

    event TokenMinted(address indexed to, uint256 tokenId);
    event SaleStateChanged(string state);

    modifier onlyOwner {
        // In a real contract, you would require a proper ownership mechanism
        require(msg.sender == address(this), "Not the contract owner");
        _;
    }

    function mintHound() public payable {
        require(saleActive, "Sale is not active");
        require(msg.value >= price, "Insufficient funds");
        // Minting logic goes here
        emit TokenMinted(msg.sender, 1); // replace 1 with the minted token ID
    }

    function mintPresale() public payable {
        require(presaleActive, "Presale is not active");
        require(msg.value >= price, "Insufficient funds");
        // Minting logic for presale goes here
        emit TokenMinted(msg.sender, 1); // replace 1 with the minted token ID
    }

    function gift(address recipient) public onlyOwner {
        // Gifting logic goes here
        emit TokenMinted(recipient, 1); // replace 1 with the minted token ID
    }

    function setPrice(uint newPrice) public onlyOwner {
        price = newPrice;
    }

    function setBaseURI(string memory newBaseURI) public onlyOwner {
        baseTokenURI = newBaseURI;
    }

    function setPresaleActive(bool _presaleActive) public onlyOwner {
        presaleActive = _presaleActive;
        emit SaleStateChanged(_presaleActive ? "Presale Active" : "Presale Inactive");
    }

    function setSaleActive(bool _saleActive) public onlyOwner {
        saleActive = _saleActive;
        emit SaleStateChanged(_saleActive ? "Sale Active" : "Sale Inactive");
    }

    function withdraw() public onlyOwner {
        payable(msg.sender).transfer(address(this).balance);
    }
}

