// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract NFTMintingContract {
    uint public tokenSupply;
    uint public cost;
    uint public maxSupply = 10000;
    mapping(address => bool) public whitelistedAddresses;

    enum State { Paused, MintingActive, NFTsRevealed }
    State public currentState;

    event MintedNFT(address user, uint tokenId);
    event NFTsRevealed();

    constructor() {
        currentState = State.Paused;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    function setPaused(bool _paused) external onlyOwner {
        if (_paused) {
            currentState = State.Paused;
        } else {
            currentState = State.MintingActive;
        }
    }

    function startMinting() internal {
        currentState = State.MintingActive;
    }

    function isWhitelisted(address user) internal view returns (bool) {
        return whitelistedAddresses[user];
    }

    function isWhitelistingDisabled() internal view returns (bool) {
        return totalSupply() == 0; // Assumed to represent whitelisting disabled
    }

    function mintNFT(address user) external {
        require(currentState == State.MintingActive, "Minting is not active");
        require(tokenSupply < maxSupply, "Max supply reached");
        require(isWhitelisted(user) || isWhitelistingDisabled(), "Not whitelisted");

        tokenSupply++;
        emit MintedNFT(user, tokenSupply); // Emit event for minted NFT
    }

    function endMinting() external onlyOwner {
        currentState = State.NFTsRevealed;
    }

    function revealNFTs() external {
        require(currentState == State.NFTsRevealed, "NFTs are not revealed");
        emit NFTsRevealed(); // Emit event for revealing NFTs
    }

    function setCost(uint _cost) external onlyOwner {
        cost = _cost;
    }

    function whitelistUsers(address[] calldata users) external onlyOwner {
        for (uint i = 0; i < users.length; i++) {
            whitelistedAddresses[users[i]] = true;
        }
    }

    function withdraw() external onlyOwner {
        payable(owner).transfer(address(this).balance);
    }
}

