        require(isTradingEnabled, "Trading is disabled");
        require(balanceOf[msg.sender] >= amount, "Insufficient balance");
        balanceOf[msg.sender] -= amount;
        balanceOf[to] += amount;
        emit TransferEvent(msg.sender, to, amount);
    }

    function approve(address spender, uint amount) external withinLimits(amount) {
        allowance[msg.sender][spender] = amount;
        emit ApprovalEvent(msg.sender, spender, amount);
    }

    function swapTokensForETH(uint amount) external withinLimits(amount) {
        require(isTradingEnabled, "Trading is disabled");
        // Implementation of token swap logic here...
