    }

    function updateFees(uint256 newBuyFee, uint256 newSellFee) external onlyOwner {
        buyFee = newBuyFee;
        sellFee = newSellFee;
        emit FeeUpdateEvent(newBuyFee, newSellFee);
    }
}

