// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract NFTMintingContract {
    enum State { Paused, MintingOpen, Revealed }
    State public state;

    uint public tokenIdCounter = 0;
    string public baseURI = "";
    uint public currentPrice = 0;
    bool public revealed = false;

    address public owner;

    event NFTMinted(address minter, uint tokenId);
    event SalePaused();
    event SaleResumed();
    event MetadataRevealed(string baseURI);

    modifier onlyOwner {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    constructor() {
        owner = msg.sender;
        state = State.Paused;
    }

    function pause() external onlyOwner {
        state = State.Paused;
        emit SalePaused();
    }

    function resumeMinting() external onlyOwner {
        state = State.MintingOpen;
        emit SaleResumed();
    }

    function freeVape() external {
        require(state == State.MintingOpen, "Minting is not open");
        tokenIdCounter++;
        emit NFTMinted(msg.sender, tokenIdCounter);
    }

    function blazeVape() external payable {
        require(state == State.MintingOpen, "Minting is not open");
        require(msg.value >= currentPrice, "Insufficient payment");
        tokenIdCounter++;
        emit NFTMinted(msg.sender, tokenIdCounter);
    }

    function reveal() external onlyOwner {
        revealed = true;
        emit MetadataRevealed(baseURI);
    }

    function setBaseURI(string calldata _baseURI) external onlyOwner {
        baseURI = _baseURI;
    }

    function setPrice(uint _price) external onlyOwner {
        currentPrice = _price;
    }

    function withdraw() external {
        require(revealed, "NFTs are not revealed yet");
        // Logic for users to withdraw their NFTs
    }
}

