// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

contract PoolMetadataContract {
    address[] public factoryAddresses;
    address public GYSRToken;
    address public treasury;
    uint public fee;
    mapping(address => bool) public bannedPools;

    enum State { ActiveMetadataSubmission, MetadataCleared, PoolBanned }
    State public currentState;

    event MetadataUpdate(address indexed pool);
    event FeeUpdate(uint newFee);
    event TreasuryUpdate(address indexed newTreasury);
    event Banning(address indexed pool);

    constructor(address _GYSRToken, address _treasury, uint _fee) {
        GYSRToken = _GYSRToken;
        treasury = _treasury;
        fee = _fee;
        currentState = State.ActiveMetadataSubmission;
    }

    modifier onlyActive() {
        require(currentState == State.ActiveMetadataSubmission, "Not in active state");
        _;
    }

    modifier onlyBanned() {
        require(currentState == State.PoolBanned, "Pool is not banned");
        _;
    }

    function definePoolMetadata(address pool) external onlyActive {
        // Logic to define metadata
        emit MetadataUpdate(pool);
    }

    function clearPoolMetadata(address pool) external onlyActive {
        currentState = State.MetadataCleared;
        // Logic to clear metadata
        emit MetadataUpdate(pool);
    }

    function banPool(address pool) external onlyActive {
        bannedPools[pool] = true;
        currentState = State.PoolBanned;
        emit Banning(pool);
    }

    function unbanPool(address pool) external onlyBanned {
        bannedPools[pool] = false;
        currentState = State.ActiveMetadataSubmission;
    }

    function updateTreasury(address newTreasury) external onlyActive {
        treasury = newTreasury;
        emit TreasuryUpdate(newTreasury);
    }

    function updateFee(uint newFee) external onlyActive {
        fee = newFee;
        emit FeeUpdate(newFee);
    }
}

