pragma solidity ^0.8.10;

contract BangBangClubNFT {
    uint public nftPrice = 0.05 ether;
    address[] public developerAddresses;
    uint public maxSupply = 10000;
    mapping(address => uint) public userPurchases;

    enum SaleState { Inactive, Active }
    SaleState public currentSaleState = SaleState.Inactive;

    event NFTMinted(address indexed user, uint amount);
    event SaleStateChanged(SaleState newState);
    event FundsWithdrawn(address indexed to, uint amount);

    modifier onlyOwner() {
        // Assuming the contract deployer is the owner for simplicity
        require(msg.sender == address(this), "Not the contract owner");
        _;
    }

    modifier saleIsActive() {
        require(currentSaleState == SaleState.Active, "Sale is not active");
        _;
    }

    function flipSaleState() external onlyOwner {
        if (currentSaleState == SaleState.Inactive) {
            currentSaleState = SaleState.Active;
        } else {
            currentSaleState = SaleState.Inactive;
        }
        emit SaleStateChanged(currentSaleState);
    }

    function mintBBCard(uint amount) external payable saleIsActive {
        require(amount > 0 && amount <= 10, "You can mint between 1 and 10 NFTs");
        require(msg.value == nftPrice * amount, "Incorrect Ether amount");

        userPurchases[msg.sender] += amount;
        emit NFTMinted(msg.sender, amount);
    }

    function claimOneFreeBBCard() external saleIsActive {
        require(userPurchases[msg.sender] == 0, "You have already claimed a free NFT");

        userPurchases[msg.sender] += 1;
        emit NFTMinted(msg.sender, 1);
    }

    function reserveTokens(address to, uint amount) external onlyOwner {
        // Logic to reserve tokens for developers
    }

    function withdraw() external onlyOwner {
        uint balance = address(this).balance;
        payable(msg.sender).transfer(balance);
        emit FundsWithdrawn(msg.sender, balance);
    }
}

