pragma solidity ^0.8.7;

contract VampireNFTContract {

    string public baseTokenURI;
    uint public totalMint;
    uint public totalPledge;
    uint public startPresale;
    uint public endPresale;
    uint public startPledge;
    uint public endPledge;

    enum State { Presale, PledgePeriod, Minting }
    State public currentState = State.Presale;

    mapping(address => bool) public isWhitelisted;
    mapping(address => uint) public pledges;

    event WhitelistedAddressRemoved(address indexed user);
    event BloodThirster(address indexed user);
    event BloodRider(address indexed user);
    event GivenName(string name);
    event StoryOfVampire(string story);

    modifier inState(State expectedState) {
        require(currentState == expectedState, "Invalid state!");
        _;
    }

    function presale() external inState(State.Presale) {
        require(isWhitelisted[msg.sender], "Not a whitelisted address");
        // Presale mint logic
        totalMint++;
        // Move to PledgePeriod
        currentState = State.PledgePeriod;
    }

    function bloodMark() external inState(State.PledgePeriod) {
        // Logic for pledging
        pledges[msg.sender]++;
        totalPledge++;
    }

    function claim() external inState(State.PledgePeriod) {
        // Logic to claim NFTs after the pledge period
        require(block.timestamp > endPledge, "Pledge period not over");
        // Transition to Minting state
        currentState = State.Minting;
    }

    function mintTo() external inState(State.Minting) {
        // Logic for minting remaining tokens
        totalMint++;
    }

    function mint() external inState(State.Minting) {
        // General minting logic can be implemented here
    }

    // Function to manage whitelisting
    function removeWhitelistedAddress(address user) external {
        delete isWhitelisted[user];
        emit WhitelistedAddressRemoved(user);
    }
}

