pragma solidity ^0.8.0;

contract NFTMintingContract {
    enum State { SaleInactive, SaleActive, ReserveActive }
    State public currentState;

    uint public maxSupply = 1000;
    uint public maxReserve = 200;
    uint public commandoPrice = 0.05 ether;
    bool public saleActive = false;

    event NFTMinted(address indexed minter);
    event SaleStateChanged(State newState);
    event PromotionalMintValidated(address indexed user);

    constructor() {
        currentState = State.SaleInactive;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    function toggleSale() external onlyOwner {
        if (currentState == State.SaleInactive) {
            currentState = State.SaleActive;
        } else {
            currentState = State.SaleInactive;
        }
        emit SaleStateChanged(currentState);
    }

    function toggleReserve() external onlyOwner {
        if (currentState == State.ReserveActive) {
            currentState = State.SaleActive;
        } else {
            currentState = State.ReserveActive;
        }
        emit SaleStateChanged(currentState);
    }

    function mintNFT() external payable {
        require(currentState == State.SaleActive, "Sale is not active");
        require(msg.value >= commandoPrice, "Insufficient Ether sent");

        // Minting logic here
        emit NFTMinted(msg.sender);
    }

    function promotionalMint() external {
        require(currentState == State.ReserveActive, "Promotional mint not active");
        // Validation logic for promotional minting
        emit PromotionalMintValidated(msg.sender);
    }
}

