// SPDX-License-Identifier: MIT
pragma solidity ^0.8.9;

contract FosterToken {
    string public name = "Foster Token";
    string public symbol = "FSTR";
    uint256 public totalSupply;

    enum State { TradingClosed, PreTrading, TradingOpen }
    State public currentState;

    mapping(address => uint256) public userBalances;
    mapping(string => uint256) public transactionFees;
    uint256 public transactionLimit;

    event Transfer(address indexed from, address indexed to, uint256 value);
    event Approval(address indexed owner, address indexed spender, uint256 value);
    event MaxTxAmountUpdated(uint256 newLimit);

    constructor() {
        totalSupply = 1000000;
        transactionLimit = 10000;
        currentState = State.TradingClosed;
    }

    modifier inState(State requiredState) {
        require(currentState == requiredState, "Invalid state for this operation");
        _;
    }

    function setTradingOpen() external inState(State.TradingClosed) {
        currentState = State.PreTrading;
    }

    function initializeTrading() external inState(State.PreTrading) {
        currentState = State.TradingOpen;
    }

    function transfer(address to, uint256 amount) external inState(State.TradingOpen) {
        require(amount <= transactionLimit, "Transaction exceeds limit");
        require(userBalances[msg.sender] >= amount, "Insufficient balance");

        userBalances[msg.sender] -= amount;
        userBalances[to] += amount;

        emit Transfer(msg.sender, to, amount);
    }

    function closeTrading() external inState(State.TradingOpen) {
        currentState = State.TradingClosed;
    }

    function approve(address spender, uint256 amount) external {
        emit Approval(msg.sender, spender, amount);
    }

    function transferFrom(address from, address to, uint256 amount) external {
        require(userBalances[from] >= amount, "Insufficient balance");
        userBalances[from] -= amount;
        userBalances[to] += amount;

        emit Transfer(from, to, amount);
    }

    function setFee(string memory feeType, uint256 feeAmount) external {
        transactionFees[feeType] = feeAmount;
    }
}

