// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract NFTMintingContract {
    enum State { Minting, PublicSaleActive, TeamSaleActive }
    State public currentState;

    address public owner;
    uint public TOKEN_LIMIT = 100;
    uint public TREASURE_KEYS_LIMIT = 10;
    uint public _tokenPrice = 0.05 ether;
    uint public _maxTokensAtOnce = 5;

    mapping(address => uint) public teamMembers;

    event TokenMinted(address indexed to, uint amount);
    event SaleToggled(string saleType, bool isActive);
    event TokenPriceUpdated(uint newPrice);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not authorized");
        _;
    }

    modifier inState(State state) {
        require(currentState == state, "Invalid state");
        _;
    }

    constructor() {
        owner = msg.sender;
        currentState = State.Minting;
    }

    function mintPublicMultipleTokens(uint amount) external inState(State.PublicSaleActive) {
        require(amount > 0 && amount <= _maxTokensAtOnce, "Invalid token amount");
        emit TokenMinted(msg.sender, amount);
    }

    function mintTeamMultipleTokens(uint amount) external inState(State.TeamSaleActive) {
        require(teamMembers[msg.sender] + amount <= TOKEN_LIMIT, "Exceeds team limit");
        teamMembers[msg.sender] += amount;
        emit TokenMinted(msg.sender, amount);
    }

    function togglePublicSale() external onlyOwner {
        if (currentState == State.PublicSaleActive) {
            currentState = State.Minting;
        } else {
            currentState = State.PublicSaleActive;
        }
        emit SaleToggled("Public Sale", currentState == State.PublicSaleActive);
    }

    function toggleTeamSale() external onlyOwner {
        if (currentState == State.TeamSaleActive) {
            currentState = State.Minting;
        } else {
            currentState = State.TeamSaleActive;
        }
        emit SaleToggled("Team Sale", currentState == State.TeamSaleActive);
    }

    function setTokenPrice(uint newPrice) external onlyOwner {
        _tokenPrice = newPrice;
        emit TokenPriceUpdated(newPrice);
    }
}

