contract NFTMintingContract {
    string public baseTokenURI;
    uint public dropStart;
    bool public isPaused;
    uint public reserve;
    uint public constant MAXSUPPLY = 10000;
    uint public maxQuantityPerTransaction = 5;
    uint public price;

    enum State { SalePaused, SaleActive, ReservedTokensMinted }
    State public currentState;

    event NFTMinted(address indexed minter, uint quantity);
    event SaleStatusChanged(bool isPaused);
    event ReserveTokensMinted(address indexed reservist, uint quantity);

    modifier onlyWhenSaleActive() {
        require(currentState == State.SaleActive, "Sale is not active");
        require(block.timestamp >= dropStart, "Drop has not started");
        _;
    }

    constructor(string memory _baseTokenURI, uint _dropStart) {
        baseTokenURI = _baseTokenURI;
        dropStart = _dropStart;
        isPaused = true;
        currentState = State.SalePaused;
    }

    function setPrice(uint _price) external {
        price = _price;
    }

    function setMaxQtPerTx(uint _maxQuantity) external {
        maxQuantityPerTransaction = _maxQuantity;
    }

    function flipPauseStatus() external {
        if (currentState == State.SalePaused) {
            currentState = State.SaleActive;
            isPaused = false;
        } else {
            currentState = State.SalePaused;
            isPaused = true;
        }
        emit SaleStatusChanged(isPaused);
    }

    function setBaseURI(string memory _baseTokenURI) external {
        baseTokenURI = _baseTokenURI;
    }

    function mintReserve() external {
        currentState = State.ReservedTokensMinted;
        emit ReserveTokensMinted(msg.sender, reserve);
        // Add code to mint reserved tokens
    }

    function mint(uint quantity) external onlyWhenSaleActive {
        require(quantity <= maxQuantityPerTransaction, "Exceeds max quantity per transaction");
        require(quantity + reserve <= MAXSUPPLY, "Exceeds max supply");

        // Add code to mint NFTs
        emit NFTMinted(msg.sender, quantity);
    }

    function withdraw() external {
        // Add code to withdraw funds from the contract
    }
}

