    uint private _price;
    uint private _reserved;
    mapping(address => bool) private _whiteList;
    uint public maxSupply;

    event WhiteList(address indexed user);
    event TokenClaimed(address indexed user);
    event TokenPurchased(address indexed buyer);

    modifier onlyInState(State state) {
        require(currentState == state, "Invalid state for this operation");
        _;
    }

    constructor(string memory baseTokenURI, uint price, uint reserved, uint maxSupply_) {
        _baseTokenURI = baseTokenURI;
        _price = price;
        _reserved = reserved;
        maxSupply = maxSupply_;
        currentState = State.Paused;
    }

    function actionUnpause() external onlyInState(State.Paused) {
        currentState = State.WhitelistPhase;
    }

    function actionPause() external onlyInState(State.WhitelistPhase) {
        currentState = State.PresalePaused;
    }

    function claimWhitelist() external onlyInState(State.WhitelistPhase) {
        require(isWhitelisted(msg.sender), "You are not whitelisted");
        emit TokenClaimed(msg.sender);
        // Logic for claiming the token
    }

    function getAppa() external payable onlyInState(State.SaleActive) {
        require(msg.value >= _price, "Insufficient funds");
        emit TokenPurchased(msg.sender);
        // Logic for purchasing the token
    }

    function manageWhitelist(address user, bool isWhitelisted) external onlyInState(State.WhitelistPhase) {
        _whiteList[user] = isWhitelisted;
        if (isWhitelisted) {
            emit WhiteList(user);
        }
    }

    function isWhitelisted(address user) public view returns (bool) {
        return _whiteList[user];
    }
}

