    mapping(address => uint) public publicMints;

    event MintedPublic(address indexed to, uint tokenId);
    event MintedWhitelist(address indexed to, uint tokenId);
    event SaleStateUpdated(uint newSaleFlag);

    constructor() ERC721("MallowClubToken", "MCT") {
        saleFlag = 0; // Start in inactive state
    }

    function mint() public {
        require(saleFlag == 2, "Public minting is not active");
        // Implement mint logic with limits
        uint tokenId = totalSupply() + 1; // or use a counter
        _mint(msg.sender, tokenId);
        publicMints[msg.sender]++;
        emit MintedPublic(msg.sender, tokenId);
    }

    function mintWhitelist(bytes32[] calldata proof) public {
        require(saleFlag == 1, "Presale is not active");
        require(isWhitelisted(msg.sender, proof), "Not whitelisted");
        // Implement whitelist mint logic with limits
        uint tokenId = totalSupply() + 1; // or use a counter
        _mint(msg.sender, tokenId);
        whitelistMints[msg.sender]++;
        emit MintedWhitelist(msg.sender, tokenId);
    }

    function isWhitelisted(address account, bytes32[] calldata proof) public view returns (bool) {
        bytes32 leaf = keccak256(abi.encodePacked(account));
        return MerkleProof.verify(proof, merkleRoot, leaf);
    }

    function lockMetadata() external onlyOwner {
        // Lock the baseURI logic here, potentially by setting a flag
    }

    function updateSaleState(uint newSaleFlag) external onlyOwner {
        saleFlag = newSaleFlag;
        emit SaleStateUpdated(newSaleFlag);
    }

    function _baseURI() internal view virtual override returns (string memory) {
        return baseURI;
    }

    function setMerkleRoot(bytes32 _merkleRoot) external onlyOwner {
        merkleRoot = _merkleRoot;
    }

    function setBaseURI(string memory _baseURI) external onlyOwner {
        baseURI = _baseURI;
    }
}

