contract UsernameNFTContract {
    mapping(address => string) public usernamesMapping;
    mapping(string => bool) public usernameExistsMapping;
    uint public total_usernames;
    uint public max_username_supply = 1000;

    enum State { ActiveMinting, MintingEnded }
    State public currentState;

    event UsernameMinted(address indexed user, string username);
    event WithdrawalMade(address indexed user, uint amount);

    constructor() {
        currentState = State.ActiveMinting;
    }

    modifier onlyActiveMinting() {
        require(currentState == State.ActiveMinting, "Minting has ended.");
        _;
    }

    function mintUsername(string memory username) public onlyActiveMinting {
        require(bytes(username).length > 0, "Username cannot be empty.");
        require(!usernameExistsMapping[username], "Username already exists.");
        require(total_usernames < max_username_supply, "Max username supply reached.");

        usernamesMapping[msg.sender] = username;
        usernameExistsMapping[username] = true;
        total_usernames++;

        emit UsernameMinted(msg.sender, username);
    }

    function mintUsernameMulti(string[] memory usernames) public onlyActiveMinting {
        for (uint i = 0; i < usernames.length; i++) {
            mintUsername(usernames[i]);
        }
    }

    function finalizeMinting() public {
        currentState = State.MintingEnded;
    }

    function withdrawFunds() public {
