pragma solidity ^0.8.4;

contract NFTMintingContract {
    uint public presaleSupply = 1000;
    uint public saleSupply = 5000;
    uint public alPrice = 0.05 ether;
    uint public maxPurchase = 5;

    enum SaleState { PresaleNotStarted, PresaleActive, PublicSaleNotStarted, PublicSaleActive }
    SaleState public currentState = SaleState.PresaleNotStarted;

    mapping(address => bool) public accessList;

    event NFTMinted(address indexed minter, uint amount);
    event SaleStateChanged(SaleState newState);
    event AccessGranted(address indexed user);

    modifier onlyDuringPresale() {
        require(currentState == SaleState.PresaleActive, "Presale not active");
        _;
    }

    modifier onlyDuringPublicSale() {
        require(currentState == SaleState.PublicSaleActive, "Public sale not active");
        _;
    }

    function toggleSaleState() external {
        if (currentState == SaleState.PresaleNotStarted) {
            currentState = SaleState.PresaleActive;
        } else if (currentState == SaleState.PresaleActive) {
            currentState = SaleState.PublicSaleNotStarted;
        } else if (currentState == SaleState.PublicSaleNotStarted) {
            currentState = SaleState.PublicSaleActive;
        } else {
            currentState = SaleState.PresaleNotStarted;
        }
        emit SaleStateChanged(currentState);
    }

    function freeClaim() external onlyDuringPresale {
        require(accessList[msg.sender], "Not in access list");
        // Logic to mint NFT for free goes here

        emit NFTMinted(msg.sender, 1); // Adjust as necessary.
    }

    function claim(uint amount) external payable onlyDuringPublicSale {
        require(amount <= maxPurchase, "Exceeds max purchase limit");
        require(msg.value >= amount * alPrice, "Insufficient payment");

        // Logic to mint NFTs goes here

        emit NFTMinted(msg.sender, amount);
    }

    function adminClaim(uint amount) external {
        // Logic for admin to mint NFTs directly goes here

        emit NFTMinted(msg.sender, amount);
    }

    function grantAccess(address user) external {
        accessList[user] = true;
        emit AccessGranted(user);
    }
}

