// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract NFTMintingContract {
    uint public pricePerWL;
    uint public pricePerPublic;
    bool public presaleLive;
    bool public publicLive;
    uint public WLminted;
    uint public WLlimit = 100; // Example limit for whitelisted mints

    event NFTminted(address indexed minter, uint amount);
    event PresaleStatusChanged(bool status);
    event PublicSaleStatusChanged(bool status);

    constructor(uint _pricePerWL, uint _pricePerPublic) {
        pricePerWL = _pricePerWL;
        pricePerPublic = _pricePerPublic;
        presaleLive = false;
        publicLive = false;
        WLminted = 0;
    }

    modifier onlyDuringPresale() {
        require(presaleLive == true, "Presale is not live");
        _;
    }

    modifier onlyDuringPublicSale() {
        require(publicLive == true, "Public sale is not live");
        _;
    }

    function mintWL() external payable onlyDuringPresale {
        require(WLminted < WLlimit, "Whitelist limit reached");
        require(msg.value >= pricePerWL, "Insufficient payment");

        WLminted++;
        emit NFTminted(msg.sender, 1);
    }

    function mint() external payable onlyDuringPublicSale {
        require(msg.value >= pricePerPublic, "Insufficient payment");

        emit NFTminted(msg.sender, 1);
    }

    function setPreSale(bool status) external {
        presaleLive = status;
        emit PresaleStatusChanged(status);
    }

    function setPublicSale(bool status) external {
        publicLive = status;
        emit PublicSaleStatusChanged(status);
    }

    function withdrawMoney() external {
        payable(msg.sender).transfer(address(this).balance);
    }

    function checkSoldOut() internal {
        if (WLminted >= WLlimit) {
            presaleLive = false;
            publicLive = false;
            emit PresaleStatusChanged(false);
            emit PublicSaleStatusChanged(false);
        }
    }
}

