// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract TokenContract {
    enum State { Paused, MintingActive, Revealed }
    State public currentState;

    string public baseURI;
    uint256 public cost;
    uint256 public maxSupply;
    mapping(address => bool) public whitelistedAddresses;

    event NFTMinted(address indexed minter);
    event NFTRevealed(string baseURI);
    event WhitelistUpdated(address indexed user, bool status);

    constructor(string memory _baseURI, uint256 _cost, uint256 _maxSupply) {
        baseURI = _baseURI;
        cost = _cost;
        maxSupply = _maxSupply;
        currentState = State.Paused;
    }

    modifier onlyWhenMintingActive() {
        require(currentState == State.MintingActive, "Minting is not active");
        _;
    }

    modifier onlyWhenPaused() {
        require(currentState == State.Paused, "Contract is not paused");
        _;
    }

    function unpauseContract() external onlyWhenPaused {
        currentState = State.MintingActive;
    }

    function mintNFT() external payable onlyWhenMintingActive {
        require(msg.value == cost, "Incorrect Ether value");
        require(maxSupply > 0, "Max supply reached");
        require(whitelistedAddresses[msg.sender], "Not whitelisted");

        maxSupply--;
        emit NFTMinted(msg.sender);
    }

    function completeMinting() external {
        currentState = State.Revealed;
    }

    function revealMetadata() external {
        require(currentState == State.Revealed, "Metadata not revealed yet");
        emit NFTRevealed(baseURI);
    }

    function updateWhitelist(address user, bool status) external {
        whitelistedAddresses[user] = status;
        emit WhitelistUpdated(user, status);
    }
}

