pragma solidity ^0.8.0;
contract ECN_NewYear_NFT is ERC721, Ownable {
    using Counters for Counters.Counter;
    Counters.Counter internal tokenCounter;

    uint8 public maxAmount;

    string public tigerURI;

    constructor (
        address[] memory _receivers,
        uint8 _maxAmount,
        string memory _tigerURI
        ) ERC721("Ethtigher", "ETHGifts") {
            maxAmount = _maxAmount;
            tigerURI = _tigerURI;

            for(uint8 i = 0; i < _receivers.length; i++ ) {
                _tigerMint(_receivers[i]);
            }
        }

    /** ========== main functions - onlyOwner ========== */

    function giveaway(address receiver) external onlyOwner {
        _tigerMint(receiver);
    }

    function resetTigerUri(string memory newUri) external onlyOwner {
        tigerURI = newUri;
    }

    /** ========== public view functions ========== */
    function tokenURI(uint256 tokenId) public view override returns (string memory) {
        require(_exists(tokenId), "ERC721Metadata: URI query for nonexistent token");
        
        return tigerURI;
    }

    function totalSupply() public view returns (uint) {
        return tokenCounter.current();
    }

    /** ========== internal functions ========== */
    function _tigerMint(address _receivers) internal returns (uint256) {
        uint256 nextTokenId = tokenCounter.current();
        require(nextTokenId < maxAmount, "_tigerMint: All NFTs have been minted");

        tokenCounter.increment();

        _mint(_receivers, nextTokenId);
        
        emit tigerMinted(_receivers, nextTokenId);

        return nextTokenId;
    }

    /** ========== event ========== */
    event tigerMinted(address indexed receiver, uint256 indexed tokenId);
}

