contract NFTMintingContract {
    enum State { Active, Paused, Minting }
    State public currentState;

    uint256 public tokenPrice;
    uint256 public maxPerMint;
    uint256 public maxSupply;
    string public baseURI;

    event TokenMinted(address indexed to, uint256 tokenId);
    event MaxSupplyChanged(uint256 newMaxSupply);
    event MaxPerMintChanged(uint256 newMaxPerMint);

    modifier onlyActive() {
        require(currentState == State.Active, "Contract is not active");
        _;
    }

    modifier onlyPaused() {
        require(currentState == State.Paused, "Contract is not paused");
        _;
    }

    constructor() {
        currentState = State.Active;
        maxPerMint = 1;
        maxSupply = 10000;
    }

    function safeMint(uint256 numberOfTokens) external onlyActive {
        require(numberOfTokens <= maxPerMint, "Exceeds max per mint");
        // Minting logic here
        emit TokenMinted(msg.sender, numberOfTokens);
        if (/* Check if minting is complete */) {
            currentState = State.Active; // return to Active after minting
        } else {
            currentState = State.Minting; // enter Minting state
        }
    }

    function pauseContract() external onlyActive {
        currentState = State.Paused;
    }

    function resumeContract() external onlyPaused {
        currentState = State.Active;
    }

    function setMaxSupply(uint256 newMaxSupply) external {
        maxSupply = newMaxSupply;
        emit MaxSupplyChanged(newMaxSupply);
    }

    function setMaxPerMint(uint256 newMaxPerMint) external {
        maxPerMint = newMaxPerMint;
        emit MaxPerMintChanged(newMaxPerMint);
    }

    function withdrawAll() external {
        // Withdrawal logic here
    }
}

