pragma solidity ^0.8.6;

contract PoiPuppyColony {
    uint public salePrice;
    uint public maxSupply;
    uint public reserveQuantity;
    uint[] public tokenIDs;
    bool public isActive;

    event PuppyRescued(uint tokenId);

    enum State { Inactive, Active, FinalizedBaseURI }
    State public currentState;

    constructor(uint _salePrice, uint _maxSupply, uint _reserveQuantity) {
        salePrice = _salePrice;
        maxSupply = _maxSupply;
        reserveQuantity = _reserveQuantity;
        currentState = State.Inactive;
        isActive = false;
    }

    modifier onlyActive() {
        require(currentState == State.Active, "Not active");
        _;
    }

    function markAsActive() external {
        require(currentState == State.Inactive, "Already active");
        isActive = true;
        currentState = State.Active;
    }

    function mintPuppy() external payable onlyActive {
        require(msg.value >= salePrice, "Insufficient funds");
        require(tokenIDs.length < maxSupply, "Max supply reached");

        uint tokenId = tokenIDs.length + 1;
        tokenIDs.push(tokenId);
        emit PuppyRescued(tokenId);
    }

    function setBaseURI() external {
        require(currentState == State.Active, "Cannot finalize base URI");
        currentState = State.FinalizedBaseURI;
    }

    function distributeFromReserve() external {
        // Logic for distributing tokens from reserve
    }
}

