pragma solidity ^0.8.4;

contract FundraiserContract {
    mapping(address => uint) public balances;
    mapping(address => mapping(address => uint)) public allowances;
    uint public fundingCapCurrentState = 1000000;
    uint public totalFundsRaised;

    event Transfer(address indexed from, address indexed to, uint value);
    event Approval(address indexed owner, address indexed spender, uint value);
    event DelegateChanged(address indexed delegate, address indexed newDelegate);
    event DelegateVotesChanged(address indexed delegate, uint previousBalance, uint newBalance);

    modifier fundingCapNotReached() {
        require(totalFundsRaised < fundingCapCurrentState, "Funding cap reached");
        _;
    }

    function fundViaUSDT(uint amount) external fundingCapNotReached {
        // Logic for funding via USDT goes here
        totalFundsRaised += amount;
        balances[msg.sender] += amount;
        emit Transfer(address(0), msg.sender, amount);
    }

    function transfer(address to, uint amount) external {
        require(balances[msg.sender] >= amount, "Insufficient balance");
        balances[msg.sender] -= amount;
        balances[to] += amount;
        emit Transfer(msg.sender, to, amount);
    }

    function delegate(address newDelegate) external {
        // Logic for delegating votes goes here
        emit DelegateChanged(msg.sender, newDelegate);
    }

    // Additional functions for approval and delegate votes would go here
}

