        PRICE = price;
        MAX_SUPPLY = maxSupply;
        currentState = State.SaleOngoing;
    }

    function mint(uint amount) external {
        require(currentState == State.SaleOngoing, "Sale has not started or has ended");
        require(totalSupply + amount <= MAX_SUPPLY, "Exceeds max supply");
        require(walletMints[msg.sender] + amount <= MAX_SUPPLY_WALLET, "Exceeds wallet limit");

        totalSupply += amount;
        walletMints[msg.sender] += amount;

        emit NFTMinted(msg.sender, amount);
    }

    function reserve(address recipient, uint amount) external onlyAdmin {
        // Implement your reservation logic here
