    bytes32 public whitelistMerkleRoot;

    enum State { Paused, WhitelistSaleActive, PublicSaleActive }
    State public currentState;

    event URIChanged(string newURI);
    event WhitelistStateChanged(State newState);

    modifier onlyInState(State _state) {
        require(currentState == _state, "Invalid state");
        _;
    }

    constructor() ERC721A("Token", "TOK") {
        currentState = State.Paused;
        maxSupply = 10000;
    }

    function activateWhitelistSale() external onlyOwner {
        require(currentState == State.Paused, "Cannot activate whitelist sale from current state");
        currentState = State.WhitelistSaleActive;
        emit WhitelistStateChanged(currentState);
    }

    function endWhitelistSale() external onlyOwner onlyInState(State.WhitelistSaleActive) {
        currentState = State.PublicSaleActive;
        emit WhitelistStateChanged(currentState);
    }

    function mintCosmiq(uint _amount, bytes32[] calldata _merkleProof) external payable onlyInState(State.WhitelistSaleActive) {
        require(isWhitelisted(msg.sender, _merkleProof), "Not whitelisted");
        require(msg.value >= mintPrice * _amount, "Insufficient Ether");
        require(amountMinted + _amount <= maxSupply, "Exceeds max supply");

        amountMinted += _amount;
        _safeMint(msg.sender, _amount);
    }

    function mintIncubator(uint _amount) external payable onlyInState(State.PublicSaleActive) {
        require(msg.value >= mintPrice * _amount, "Insufficient Ether");
        require(amountMinted + _amount <= maxSupply, "Exceeds max supply");

        amountMinted += _amount;
        _safeMint(msg.sender, _amount);
    }

    function setWhitelistMerkleRoot(bytes32 _merkleRoot) external onlyOwner {
        whitelistMerkleRoot = _merkleRoot;
    }

    function setURI(string calldata _newURI) external onlyOwner {
        baseURI = _newURI;
        emit URIChanged(_newURI);
    }

    function _baseURI() internal view virtual override returns (string memory) {
        return baseURI;
    }

    function isWhitelisted(address _account, bytes32[] calldata _merkleProof) internal view returns (bool) {
        // Implement the logic to verify if the address is whitelisted using Merkle proof
    }
}

