import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract RarePepe is ERC721, Ownable {
    uint public maxTokens;
    string private _contractURI;
    mapping(uint256 => bool) private frozenMetadataByTokenId;
    mapping(address => bool) private minters;
    uint256 public totalSupply;

    event PermanentURI(string _value, uint256 indexed _id);

    constructor(string memory name, string memory symbol, uint _maxTokens) ERC721(name, symbol) {
        maxTokens = _maxTokens;
    }

    modifier onlyMinter() {
        require(minters[msg.sender], "Not an authorized minter");
        _;
    }

    function mint(address to, uint256 tokenId) external onlyMinter {
        require(totalSupply < maxTokens, "Max tokens exceeded");
        _mint(to, tokenId);
        totalSupply++;
    }

    function setTokenURI(uint256 tokenId, string memory _tokenURI) external onlyMinter {
        require(!frozenMetadataByTokenId[tokenId], "Metadata is frozen");
        _setTokenURI(tokenId, _tokenURI);
    }

    function freezeMetadata(uint256 tokenId) external onlyMinter {
        require(_exists(tokenId), "Token does not exist");
        frozenMetadataByTokenId[tokenId] = true;
        emit PermanentURI(tokenURI(tokenId), tokenId);
    }

    function addMinter(address minter) external onlyOwner {
        minters[minter] = true;
    }

    function removeMinter(address minter) external onlyOwner {
        minters[minter] = false;
    }

    function setContractURI(string memory contractURI) external onlyOwner {
        _contractURI = contractURI;
    }

    function getContractURI() external view returns (string memory) {
        return _contractURI;
    }

    function _setTokenURI(uint256 tokenId, string memory _tokenURI) internal {
        // Implementation of setting the token URI
    }

    function tokenURI(uint256 tokenId) public view virtual override returns (string memory) {
        // Implementation of returning the token URI
    }
}

