// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract NFTMintingContract {
    enum State { Before, Presale, Sale, SoldOut, Reveal }
    State public workflowStatus = State.Before;

    uint public tokenIdCounter = 0;
    uint public giftCount = 0;
    string public baseURI;

    event PresaleStarted();
    event Minted(address indexed buyer, uint indexed tokenId);
    event SaleEnded();
    event NFTsRevealed(string baseURI);

    modifier onlyOwner() {
        require(msg.sender == owner, "Caller is not the owner");
        _;
    }

    address public owner;

    constructor() {
        owner = msg.sender;
    }

    function setupPresale() external onlyOwner {
        workflowStatus = State.Presale;
        emit PresaleStarted();
    }

    function presaleMint() external {
        require(workflowStatus == State.Presale, "Presale has not started or has ended");
        // Minting logic here
        tokenIdCounter++;
        emit Minted(msg.sender, tokenIdCounter);
    }

    function endPresale() external onlyOwner {
        require(workflowStatus == State.Presale, "Not in presale state");
        workflowStatus = State.Sale;
    }

    function publicSaleMint() external {
        require(workflowStatus == State.Sale, "Public sale has not started or has ended");
        // Minting logic here
        tokenIdCounter++;
        emit Minted(msg.sender, tokenIdCounter);
        // Check sold out logic
        if (tokenIdCounter >= MAX_SUPPLY) {
            workflowStatus = State.SoldOut;
            emit SaleEnded();
        }
    }

    function checkSoldOut() internal {
        // Logic to check if all NFTs are sold out
    }

    function revealNFTs() external onlyOwner {
        require(workflowStatus == State.SoldOut, "NFTs cannot be revealed yet");
        workflowStatus = State.Reveal;
        emit NFTsRevealed(baseURI);
    }
}

