// SPDX-License-Identifier: MIT
pragma solidity 0.8.7;

import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/access/AccessControl.sol";

contract ARTCOIN is ERC20, AccessControl {
    bytes32 public constant SNAPSHOT_ROLE = keccak256("SNAPSHOT_ROLE");
    bytes32 public constant MINTER_ROLE = keccak256("MINTER_ROLE");

    enum State { InitialSetup, MintingPhase, SnapshotPhase }
    State public currentState;

    event TokenMinted(address indexed to, uint256 amount);
    event SnapshotCreated(uint256 snapshotId);

    constructor() ERC20("ARTCOIN", "ART") {
        _setupRole(DEFAULT_ADMIN_ROLE, msg.sender);
        currentState = State.InitialSetup;
        _mint(msg.sender, 1000000 * (10 ** decimals())); // Initial supply
    }

    modifier onlyMinter() {
        require(hasRole(MINTER_ROLE, msg.sender), "Caller is not a minter");
        _;
    }

    modifier onlySnapshotter() {
        require(hasRole(SNAPSHOT_ROLE, msg.sender), "Caller is not a snapshotter");
        _;
    }

    function initializeRoles() public onlyRole(DEFAULT_ADMIN_ROLE) {
        currentState = State.MintingPhase;
    }

    function mintTokens(address to, uint256 amount) public onlyMinter {
        require(currentState == State.MintingPhase, "Not in minting phase");
        _mint(to, amount);
        emit TokenMinted(to, amount);
    }

    function takeSnapshot() public onlySnapshotter {
        require(currentState == State.SnapshotPhase, "Not in snapshot phase");
        // Logic for taking snapshot goes here
        emit SnapshotCreated(block.timestamp); // Replace with actual snapshot ID logic
    }

    function finalizeMinting() public onlyRole(DEFAULT_ADMIN_ROLE) {
        require(currentState == State.MintingPhase, "Not in minting phase");
        currentState = State.SnapshotPhase;
    }

    function resetContract() public onlyRole(DEFAULT_ADMIN_ROLE) {
        currentState = State.InitialSetup;
    }

    function startMintingPhase() public onlyRole(DEFAULT_ADMIN_ROLE) {
        currentState = State.MintingPhase;
    }

    function startSnapshotPhase() public onlyRole(DEFAULT_ADMIN_ROLE) {
        currentState = State.SnapshotPhase;
    }
}

