// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract PugNFTToken {
    address public yieldToken;
    bool public presaleActive = false;
    bool public saleActive = false;
    uint public maxMintPerAccount = 5;
    uint public price = 0.05 ether;
    string public bio;
    string public tokenName;

    enum State { PresaleActive, SaleActive, SaleFinished }
    State public currentState;

    event Mint(address indexed to, uint amount);
    event NameChange(address indexed owner, string newName);
    event BioChange(address indexed owner, string newBio);

    constructor(address _yieldToken) {
        yieldToken = _yieldToken;
        currentState = State.PresaleActive;
    }

    modifier onlyInState(State _state) {
        require(currentState == _state, "Operation not allowed in current state.");
        _;
    }

    function togglePresale() external onlyInState(State.PresaleActive) {
        presaleActive = !presaleActive;
    }

    function toggleSale() external onlyInState(State.SaleActive) {
        saleActive = !saleActive;
    }

    function presaleMint() external payable onlyInState(State.PresaleActive) {
        require(presaleActive, "Presale is not active.");
        require(msg.value >= price, "Insufficient payment.");
        emit Mint(msg.sender, 1);
    }

    function regularMint() external payable onlyInState(State.SaleActive) {
        require(saleActive, "Sale is not active.");
        require(msg.value >= price, "Insufficient payment.");
        emit Mint(msg.sender, 1);
    }

    function resetSale() external onlyInState(State.SaleFinished) {
        currentState = State.PresaleActive;
        presaleActive = false;
        saleActive = false;
    }

    function changeName(string calldata newName) external {
        tokenName = newName;
        emit NameChange(msg.sender, newName);
    }

    function changeBio(string calldata newBio) external {
        bio = newBio;
        emit BioChange(msg.sender, newBio);
    }
}

