pragma solidity ^0.8.7;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract BeanBagFrens is ERC721, Ownable {
    bytes32 public LINK_KEY_HASH;
    uint256 public LINK_FEE;
    uint256 public TOKEN_OFFSET;
    uint256 public MAX_SUPPLY = 10000;
    uint256 public totalSupply;

    enum State {
        TokenOffsetNotSet,
        TokenOffsetSet,
        RevealingTokens,
        MintingPhase
    }

    State public currentState;

    event TokenMinted(address indexed to, uint256 tokenId);
    event MetadataRevealed(string metadata);
    event FunctionLocked();

    constructor() ERC721("BeanBagFrens", "BBF") {
        currentState = State.TokenOffsetNotSet;
    }

    function setProvenanceHash(bytes32 _provenanceHash) external onlyOwner {
        LINK_KEY_HASH = _provenanceHash;
        currentState = State.TokenOffsetSet;
    }

    function revealMetadata(string memory _metadata) external onlyOwner {
        require(currentState == State.TokenOffsetSet, "State not valid for revealing");
        emit MetadataRevealed(_metadata);
        currentState = State.RevealingTokens;
    }

    function startMinting() external onlyOwner {
        require(currentState == State.TokenOffsetSet, "State not valid for starting minting");
        currentState = State.MintingPhase;
    }

    function completeReveal() external onlyOwner {
        require(currentState == State.RevealingTokens, "State not valid for completing reveal");
        currentState = State.MintingPhase;
    }

    function mintToken(address to) external payable {
        require(currentState == State.MintingPhase, "Minting is not active");
        require(totalSupply < MAX_SUPPLY, "Exceeds max supply");

        totalSupply++;
        uint256 tokenId = totalSupply;  // Assume tokenId starts from 1
        _mint(to, tokenId);
        emit TokenMinted(to, tokenId);
    }

    function withdraw() external onlyOwner {
        // Withdrawal logic, e.g., transferring funds to owner
    }
}

