// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract CreatureToadz {
    uint public publicPrice;
    uint public holderPrice;
    uint public maxSupply;
    string public mintPhase; // "DevelopmentMint", "HolderMint", "PublicMint", "Closed"
    mapping(address => bool) public mintlist;

    event MintingAction(address indexed participant);
    event PhaseChanged(string newPhase);

    constructor(uint _publicPrice, uint _holderPrice, uint _maxSupply) {
        publicPrice = _publicPrice;
        holderPrice = _holderPrice;
        maxSupply = _maxSupply;
        mintPhase = "DevelopmentMint";
    }

    modifier onlyInPhase(string memory phase) {
        require(keccak256(abi.encodePacked(mintPhase)) == keccak256(abi.encodePacked(phase)), "Not in the correct phase");
        _;
    }

    function mint() public payable onlyInPhase("PublicMint") {
