    event SaleStateUpdated(State newState);

    constructor() {
        currentState = State.PreSaleSetup;
    }

    modifier inState(State state) {
        require(currentState == state, "Invalid state for this operation");
        _;
    }

    function setSaleTime(uint saleTime) external inState(State.PreSaleSetup) {
        _saleTime = saleTime;
        currentState = State.SaleOpen;
        emit SaleStateUpdated(currentState);
    }

    function isSaleOpen() public view returns (bool) {
        return currentState == State.SaleOpen && block.timestamp >= _saleTime;
    }

    function mint(uint tokenId) external inState(State.SaleOpen) {
        require(isSaleOpen(), "Sale is not open");
        // Minting logic goes here
        emit TokenMinted(msg.sender, tokenId);
    }

    function closeSale() external inState(State.SaleOpen) {
        currentState = State.SaleClosed;
        emit SaleStateUpdated(currentState);
    }

    function withdrawAll() external inState(State.SaleClosed) {
        // Withdrawal logic goes here
    }
}

