// SPDX-License-Identifier: MIT
pragma solidity ^0.8.11;

import "@openzeppelin/contracts/token/ERC721/ERC721.sol";

contract ERC721RentalContract is ERC721 {
    address public rentable;
    string public PREFIX;

    enum State { Initialization, RentableSet, TokenManagement }
    State public currentState;

    event InitEvent();
    event SetRentableEvent(address indexed newRentable);
    event GetRentableEvent(address indexed rentableAddress);
    event OwnerOfEvent(address indexed owner);
    event ExistsEvent();

    constructor() ERC721("ERC721Rental", "RENT") {
        currentState = State.Initialization;
    }

    modifier onlyOwner() {
        require(msg.sender == owner(), "Not the contract owner");
        _;
    }

    function init() external onlyOwner {
        require(currentState == State.Initialization, "Already initialized");
        emit InitEvent();
        currentState = State.RentableSet;
    }

    function setRentable(address _rentable) external onlyOwner {
        rentable = _rentable;
        emit SetRentableEvent(rentable);
        currentState = State.TokenManagement;
    }

    function getRentable() external {
        emit GetRentableEvent(rentable);
    }

    function ownerOf(uint256 tokenId) public view override returns (address) {
        address owner = super.ownerOf(tokenId);
        emit OwnerOfEvent(owner);
        return owner;
    }

    function exists(uint256 tokenId) public view returns (bool) {
        bool tokenExists = _exists(tokenId);
        if (tokenExists) {
            emit ExistsEvent();
        }
        return tokenExists;
    }
}

