// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract ToonsOGTokenContract {
    enum State { Paused, WhitelistingSaleActive, PublicSaleActive }
    State public currentState;

    uint public cost;
    uint public maxSupply = 10000;
    mapping(address => uint) public whitelistedMints;

    event TokenMinted(address indexed to, uint amount);
    event OwnershipChanged(address indexed previousOwner, address indexed newOwner);

    constructor(uint _cost) {
        cost = _cost;
        currentState = State.Paused;
    }

    modifier inState(State _state) {
        require(currentState == _state, "Invalid state for this action");
        _;
    }

    function setupWhitelist(address[] calldata _whitelist) external inState(State.Paused) {
        for (uint i = 0; i < _whitelist.length; i++) {
            whitelistedMints[_whitelist[i]] = 0; // Initialize whitelist
        }
        currentState = State.WhitelistingSaleActive;
    }

    function mintToken(uint amount) external payable inState(State.WhitelistingSaleActive) {
        require(whitelistedMints[msg.sender] < amount, "Exceeds whitelisted mint allowance");
        require(msg.value >= cost * amount, "Insufficient funds");

        whitelistedMints[msg.sender] += amount;
        emit TokenMinted(msg.sender, amount);
    }

    function openPublicSale() external inState(State.WhitelistingSaleActive) {
        currentState = State.PublicSaleActive;
    }

    function mintTokenPublic(uint amount) external payable inState(State.PublicSaleActive) {
        require(msg.value >= cost * amount, "Insufficient funds");

        emit TokenMinted(msg.sender, amount);
    }

    function pauseMinting() external {
        currentState = State.Paused;
    }
}

