    State public currentState;

    event Burned(address indexed owner, uint256 tokenId);

    constructor(string memory baseTokenURI, uint256 price, uint256 reserved) {
        _baseTokenURI = baseTokenURI;
        multiPassPrice = price;
        multiPassesReserved = reserved;
        currentState = State.MintingActive;
    }

    modifier onlyInState(State expectedState) {
        require(currentState == expectedState, "Action not allowed in current state.");
        _;
    }

    function mintMultiPass() public payable onlyInState(State.MintingActive) {
        require(msg.value >= multiPassPrice, "Insufficient funds to mint.");
        // Minting logic here
    }

    function burn(uint256 tokenId) public onlyInState(State.BurningAllowed) {
        // Burn logic here
        emit Burned(msg.sender, tokenId);
    }

    function setMintAllowed(bool allowed) public {
        if (allowed) {
            currentState = State.MintingActive;
        } else {
            currentState = State.MintingPaused;
        }
    }

    function allowBurning() public {
        currentState = State.BurningAllowed;
    }

    function updateBaseTokenURI(string memory newBaseTokenURI) public {
        _baseTokenURI = newBaseTokenURI;
    }
}

