pragma solidity ^0.8.10;

contract NFTMintingContract {
    uint public maxSupply = 1000;
    uint public mintingLimit = 5;
    bool public presaleStatus = false;
    string public baseURI;

    enum State { Paused, PresaleActive, PublicSaleActive, Revealed }
    State public state;

    event MintingEvent(address indexed user, uint256 quantity);
    event URIUpdate(string newURI);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    constructor() {
        state = State.Paused;
    }

    function activatePresale() external onlyOwner {
        state = State.PresaleActive;
        presaleStatus = true;
    }

    function endPresale() external onlyOwner {
        state = State.PublicSaleActive;
        presaleStatus = false;
    }

    function pause() external onlyOwner {
        state = State.Paused;
    }

    function revealNFTs() external onlyOwner {
        state = State.Revealed;
    }

    function whitelistMint(uint256 quantity) external {
        require(state == State.PresaleActive, "Presale is not active");
        require(quantity <= mintingLimit, "Exceeds minting limit");
        // Mint logic for whitelisted users
        emit MintingEvent(msg.sender, quantity);
    }

    function publicMint(uint256 quantity) external {
        require(state == State.PublicSaleActive, "Public sale is not active");
        require(quantity <= mintingLimit, "Exceeds minting limit");
        // Mint logic for public users
        emit MintingEvent(msg.sender, quantity);
    }

    function teamLegendariesMint(uint256 quantity) external onlyOwner {
        // Mint logic for team legendary NFTs
        emit MintingEvent(msg.sender, quantity);
    }

    function teamReserveMint(uint256 quantity) external onlyOwner {
        // Mint logic for team reserved NFTs
        emit MintingEvent(msg.sender, quantity);
    }

    function updateBaseURI(string memory newURI) external onlyOwner {
        baseURI = newURI;
        emit URIUpdate(newURI);
    }
}

