    uint public cost;
    uint public maxSupply;
    bool public paused = true;

    enum State { Paused, MintingActive, Revealed }
    State public currentState;

    event NFTMinted(address indexed owner);
    event MetadataRevealed(string baseURI);
    event ContractPausedUnpaused(bool paused);

    constructor(string memory _baseURI, uint _cost, uint _maxSupply) {
        baseURI = _baseURI;
        cost = _cost;
        maxSupply = _maxSupply;
        currentState = State.Paused;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    modifier stateTransition(State _state) {
        require(currentState == _state, "Invalid state transition");
        _;
    }

    function actionUnpause() external onlyOwner stateTransition(State.Paused) {
        paused = false;
        currentState = State.MintingActive;
        emit ContractPausedUnpaused(paused);
    }

    function actionMint() external payable stateTransition(State.MintingActive) {
        require(!paused, "Minting is paused");
        require(msg.value >= cost, "Insufficient funds");
        // Logic for minting NFT
        emit NFTMinted(msg.sender);
    }

    function actionCompleteMinting() external onlyOwner stateTransition(State.MintingActive) {
        currentState = State.Revealed;
    }

    function actionRevealMetadata() external onlyOwner stateTransition(State.Revealed) {
        // Logic to reveal metadata
        emit MetadataRevealed(baseURI);
    }

    function setBaseURI(string calldata _baseURI) external onlyOwner {
        baseURI = _baseURI;
    }

    function setCost(uint _cost) external onlyOwner {
        cost = _cost;
    }

    function setMaxSupply(uint _maxSupply) external onlyOwner {
        maxSupply = _maxSupply;
    }

    // Additional necessary functions such as withdraw funds can be added here
}

