pragma solidity ^0.8.0;

contract SneakyCheetahAdoption {

    uint public cheetahPrice;
    bool public saleIsActive;
    string public baseTokenURI;
    uint public constant MAX_CHEETAHS = 100;
    uint public CurrentSupply;

    event CheetahAdopted(address indexed adopter, uint amount);
    event CheetahReserved(address indexed reserver, uint amount);
    event SaleStateChanged(bool newState);

    constructor() {
        cheetahPrice = 0; // Set initial price
        saleIsActive = false; // Sale starts inactive
        baseTokenURI = ""; // Set initial base URI
        CurrentSupply = 0; // Set initial supply
    }

    function adoptSneakyCheetah(uint amount) public payable {
        require(saleIsActive, "Sale is not active.");
        require(CurrentSupply + amount <= MAX_CHEETAHS, "Not enough sneaky cheetahs left.");
        require(msg.value >= cheetahPrice * amount, "Insufficient funds.");

        CurrentSupply += amount;
        emit CheetahAdopted(msg.sender, amount);

        if (CurrentSupply == MAX_CHEETAHS) {
            saleIsActive = false;
            emit SaleStateChanged(saleIsActive);
        }
    }

    function reserveCheetahs(uint amount) public {
        require(saleIsActive, "Sale is not active.");
        // Implement reservation logic
        emit CheetahReserved(msg.sender, amount);
    }

    function flipSaleState() public {
        saleIsActive = !saleIsActive;
        emit SaleStateChanged(saleIsActive);
    }

    function withdrawAll() public {
        // Implement withdrawal logic
    }

}

