pragma solidity ^0.8.9;

contract TokenContract {
    uint public totalSupply = 1000000;
    mapping(address => uint) public ownershipMapping;
    mapping(address => bool) public blacklist;

    uint public buyFee = 2; // 2%
    uint public sellFee = 3; // 3%

    enum State { TradingClosed, TradingOpen }
    State public state = State.TradingClosed;

    event Transfer(address indexed from, address indexed to, uint value);
    event Approval(address indexed owner, address indexed spender, uint value);

    modifier onlyOwner() {
        require(msg.sender == address(this), "Not the contract owner");
        _;
    }

    modifier whenTradingOpen() {
        require(state == State.TradingOpen, "Trading is closed");
        _;
    }

    function openTrading() external onlyOwner {
        state = State.TradingOpen;
    }

    function closeTrading() external onlyOwner {
        state = State.TradingClosed;
    }

    function transfer(address to, uint amount) external whenTradingOpen {
        require(!blacklist[msg.sender], "Sender is blacklisted");
        require(ownershipMapping[msg.sender] >= amount, "Insufficient balance");

        ownershipMapping[msg.sender] -= amount;
        ownershipMapping[to] += amount;

        uint fee = (amount * buyFee) / 100;
        ownershipMapping[address(this)] += fee; // Collect fees

        emit Transfer(msg.sender, to, amount);
    }

    function approve(address spender, uint amount) external {
        emit Approval(msg.sender, spender, amount);
    }

    function swapTokensForEth(uint amount) external whenTradingOpen {
        require(!blacklist[msg.sender], "Sender is blacklisted");
        // Token swap logic would go here
    }

    function manageTradingSettings(uint newBuyFee, uint newSellFee) external onlyOwner {
        buyFee = newBuyFee;
        sellFee = newSellFee;
    }
}

