        _proposalThreshold = proposalThreshold;
    }

    function proposeAction(string calldata message) public onlyInState(State.ProposalCreation) {
        proposals.push(Proposal({
            proposer: msg.sender,
            message: message,
            executed: false,
            votesFor: 0,
            votesAgainst: 0
        }));
        emit Shout(msg.sender, message);
        currentState = State.Voting;
    }

    function vote(uint proposalIndex, bool support) public onlyInState(State.Voting) {
        require(proposalIndex < proposals.length, "Invalid proposal index");
