        require(!proposal.executed, "Proposal already executed");

        if (proposal.votesFor > proposal.votesAgainst && proposal.votesFor >= _proposalThreshold) {
            // Execute the proposed action (implementation depends on the context)
        }

        proposal.executed = true;
        currentState = State.ProposalCreation;
    }

    function handleDeposits() public payable {
