pragma solidity ^0.8.7;

contract NFTContract {
    string public baseURI;
    string public notRevealedUri;
    uint public cost;
    uint public maxSupply;
    bool public paused;

    enum State { Paused, MintingActive, Revealed }
    State public currentState;

    event TokenMinted(address sender, uint tokenId);
    event RevealEvent(string baseURI);
    event ContractStateChanged(State newState);

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner can call this");
        _;
    }

    modifier validMintingConditions() {
        require(currentState == State.MintingActive, "Minting is not active");
        require(totalSupply < maxSupply, "Max supply reached");
        require(msg.value >= cost, "Insufficient payment");
        _;
    }

    constructor(string memory _baseURI, string memory _notRevealedUri, uint _cost, uint _maxSupply) {
        baseURI = _baseURI;
        notRevealedUri = _notRevealedUri;
        cost = _cost;
        maxSupply = _maxSupply;
        paused = true;
        currentState = State.Paused;
    }

    function activateMinting() external onlyOwner {
        currentState = State.MintingActive;
        paused = false;
        emit ContractStateChanged(currentState);
    }

    function deactivateMinting() external onlyOwner {
        currentState = State.Paused;
        paused = true;
        emit ContractStateChanged(currentState);
    }

    function mintToken() external payable validMintingConditions {
        // Mint token logic here
        emit TokenMinted(msg.sender, tokenId);
    }

    function revealMetadata() external onlyOwner {
        require(currentState == State.MintingActive, "Minting not active");
        currentState = State.Revealed;
        emit RevealEvent(baseURI);
    }

    function resetContract() external onlyOwner {
        currentState = State.Paused;
        paused = true;
        emit ContractStateChanged(currentState);
    }
}

