// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract HeartzNFTContract {
    uint public nftPrice;
    uint public maxSupply;
    bool public saleIsActive;
    mapping(address => bool) public whitelistAddresses;

    enum SaleState { InactiveSale, ActiveSale, WhitelistOnly }
    SaleState public currentState;

    event MintingCompleted(address indexed minter);
    event WhitelistStatusChanged(address indexed user, bool isWhitelisted);

    constructor(uint _nftPrice, uint _maxSupply) {
        nftPrice = _nftPrice;
        maxSupply = _maxSupply;
        currentState = SaleState.InactiveSale;
    }

    modifier onlyWhenSaleActive() {
        require(saleIsActive, "Sale is not active");
        _;
    }

    function mint() external payable onlyWhenSaleActive {
        require(msg.value == nftPrice, "Incorrect NFT price");
        if (currentState == SaleState.WhitelistOnly) {
            require(isWhitelisted(msg.sender), "Address is not whitelisted");
        }
        emit MintingCompleted(msg.sender);
    }

    function setBaseURI(string memory baseURI) external {
        // Implementation for setting the base URI
    }

    function flipSaleState() external {
        if (currentState == SaleState.InactiveSale) {
            currentState = SaleState.ActiveSale;
            saleIsActive = true;
        } else if (currentState == SaleState.ActiveSale) {
            currentState = SaleState.WhitelistOnly;
        } else if (currentState == SaleState.WhitelistOnly) {
            currentState = SaleState.ActiveSale;
        }
    }

    function isWhitelisted(address user) public view returns (bool) {
        return whitelistAddresses[user];
    }

    function addToWhitelist(address user) external {
        whitelistAddresses[user] = true;
        emit WhitelistStatusChanged(user, true);
    }

    function removeFromWhitelist(address user) external {
        whitelistAddresses[user] = false;
        emit WhitelistStatusChanged(user, false);
    }
}

