pragma solidity ^0.8.12;

contract MetaBotSocietyPresale {
    address public nftAddress;
    mapping(address => uint) public mintingLimits;
    mapping(uint => uint) public prices;
    uint public totalSupply;

    enum SalePhase { PhaseOneSale, PhaseTwoSale, OpenSale }
    SalePhase public currentPhase;

    event PurchaseAction(address buyer, uint amount);
    event SetAdjustments();
    event WithdrawFunds(address recipient, uint amount);

    constructor(address _nftAddress) {
        nftAddress = _nftAddress;
        totalSupply = 10000;
        prices[1] = 0.05 ether; // Phase One price
        prices[2] = 0.1 ether;  // Phase Two price
        currentPhase = SalePhase.PhaseOneSale;
    }

    function initializePhaseOne() external {
        require(currentPhase == SalePhase.PhaseOneSale, "Not in Phase One Sale");
        // Set up Phase One parameters
    }

    function initializePhaseTwo() external {
        require(currentPhase == SalePhase.PhaseTwoSale, "Not in Phase Two Sale");
        // Set up Phase Two parameters
    }

    function buyNFT(uint amount) external payable {
        require(totalSupply >= amount, "Not enough supply");
        if (currentPhase == SalePhase.PhaseOneSale) {
            validatePurchasePhaseOne(amount);
        } else if (currentPhase == SalePhase.PhaseTwoSale) {
            validatePurchasePhaseTwo(amount);
        } else if (currentPhase == SalePhase.OpenSale) {
            validatePurchaseOpenSale(amount);
        }

        totalSupply -= amount;
        emit PurchaseAction(msg.sender, amount);
    }

    function validatePurchasePhaseOne(uint amount) internal {
        require(msg.value == prices[1] * amount, "Incorrect payment");
        mintingLimits[msg.sender] += amount; // Add limit-specific logic as needed
    }

    function validatePurchasePhaseTwo(uint amount) internal {
        require(msg.value == prices[2] * amount, "Incorrect payment");
        mintingLimits[msg.sender] += amount; // Add limit-specific logic as needed
    }

    function validatePurchaseOpenSale(uint amount) internal {
        require(msg.value >= prices[2] * amount, "Incorrect payment for open sale");
        // Additional logic for open sale can be added here
    }

    function finalizeSales() external {
        require(currentPhase != SalePhase.OpenSale, "Sales still ongoing");
        // Logic to finalize or reset the sale
    }
}

