// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract TokenContract {
    string public baseURI;
    uint public cost;
    uint public maxSupply;
    uint public maxMintAmount;
    bool public paused;
    bool public revealed;
    string public notRevealedUri;

    enum State { Active, Paused, Revealed }
    State public currentState;

    event TokenMinted(address indexed to, uint256 tokenId);
    event TokensRevealed(string uri);
    event ContractPaused();
    event ContractUnpaused();

    constructor(string memory _baseURI, uint _cost, uint _maxSupply, uint _maxMintAmount, string memory _notRevealedUri) {
        baseURI = _baseURI;
        cost = _cost;
        maxSupply = _maxSupply;
        maxMintAmount = _maxMintAmount;
        notRevealedUri = _notRevealedUri;
        currentState = State.Active;
    }

    modifier onlyWhenActive() {
        require(currentState == State.Active, "Contract is paused");
        _;
    }

    modifier onlyWhenPaused() {
        require(currentState == State.Paused, "Contract is not paused");
        _;
    }

    function mintToken() external onlyWhenActive {
        // Mint logic here, using sender's address and keeping track of minted tokens.
        emit TokenMinted(msg.sender, /* tokenId */);
    }

    function pauseContract() external onlyWhenActive {
        currentState = State.Paused;
        paused = true;
        emit ContractPaused();
    }

    function unpauseContract() external onlyWhenPaused {
        currentState = State.Active;
        paused = false;
        emit ContractUnpaused();
    }

    function revealMetadata() external onlyWhenActive {
        currentState = State.Revealed;
        revealed = true;
        emit TokensRevealed(baseURI);
    }

    function updateSettings(uint _cost, uint _maxMintAmount) external {
        cost = _cost;
        maxMintAmount = _maxMintAmount;
    }
}

