pragma solidity ^0.8.10;

contract NFTMintingContract {
    string public baseURI;
    uint public price;
    uint public maxSupply = 1000;
    uint public reserved = 10;
    mapping(address => uint) public whitelistPurchases;

    enum SaleState { SaleNotStarted, WhitelistPhaseActive, PublicSaleActive, SalePaused }
    SaleState public currentState;

    event NFTMinted(address indexed buyer, uint amount);
    event WhitelistVerification(address indexed buyer);
    event SaleStateChange(SaleState newState);

    modifier inState(SaleState state) {
        require(currentState == state, "Invalid state for this operation.");
        _;
    }

    constructor() {
        currentState = SaleState.SaleNotStarted;
    }

    function startSale() external inState(SaleState.SaleNotStarted) {
        currentState = SaleState.WhitelistPhaseActive;
        emit SaleStateChange(currentState);
    }

    function endWhitelistPhase() external inState(SaleState.WhitelistPhaseActive) {
        currentState = SaleState.PublicSaleActive;
        emit SaleStateChange(currentState);
    }

    function pauseSale() external {
        currentState = SaleState.SalePaused;
        emit SaleStateChange(currentState);
    }

    function resumeSale() external inState(SaleState.SalePaused) {
        currentState = SaleState.PublicSaleActive;
        emit SaleStateChange(currentState);
    }

    function endSale() external inState(SaleState.PublicSaleActive) {
        currentState = SaleState.SaleNotStarted;
        emit SaleStateChange(currentState);
    }

    function mintNFT() external payable inState(SaleState.PublicSaleActive) {
        require(msg.value >= price, "Insufficient payment.");
        // Logic to mint NFT goes here
        emit NFTMinted(msg.sender, 1);
    }

    function whitelistMintNFT() external payable inState(SaleState.WhitelistPhaseActive) {
        require(msg.value >= price, "Insufficient payment.");
        // Logic to verify whitelist and mint NFT goes here
        emit WhitelistVerification(msg.sender);
        emit NFTMinted(msg.sender, 1);
    }

    function giftNFT(address to) external {
        require(reserved > 0, "No reserved NFTs available.");
        reserved--;
        // Logic to mint NFT to the address 'to' goes here
        emit NFTMinted(to, 1);
    }

    function setPrice(uint newPrice) external {
        price = newPrice;
    }

    function withdraw() external {
        // Logic to withdraw funds goes here
    }
}

