    enum State { OpenForSale, MintingPeriod, SaleEnded }
    State public currentState;

    event CreateMerge();

    constructor() {
        currentState = State.OpenForSale;
        _tokenIdTracker = 0;
    }

    modifier isOpenForSale() {
        require(currentState == State.OpenForSale, "Sale is not open");
        _;
    }

    modifier isMintingPeriod() {
        require(currentState == State.MintingPeriod, "Not in minting period");
        _;
    }

    modifier onlyOwner() {
        // Assuming only the owner can set the base URI or perform certain actions
        require(msg.sender == address(this), "Not the contract owner");
        _;
    }

    function mint() external payable isOpenForSale {
        require(msg.value >= MINT_PRICE, "Insufficient funds");
        require(_tokenIdTracker < MAX_ELEMENTS, "Max supply reached");

        _tokenIdTracker++;
        emit CreateMerge();

        if (_tokenIdTracker == MAX_ELEMENTS) {
            currentState = State.SaleEnded;
        }
    }

    function setBaseURI(string calldata _baseTokenURI) external onlyOwner {
        baseTokenURI = _baseTokenURI;
    }

    function refund() external isMintingPeriod {
