    event WithdrawalEvent(address indexed to, uint amount);

    constructor() {
        state = State.MainsaleInactive;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    modifier inState(State _state) {
        require(state == _state, "Invalid state for this operation");
        _;
    }

    function setActive() external onlyOwner {
        state = State.MainsaleActive;
    }

    function mint() external payable inState(State.MainsaleActive) {
        require(msg.value == PRICE, "Incorrect ether sent");
        // Logic for minting NFT
        emit Transfer(address(0), msg.sender, nextTokenId);
    }

    function mintTo(address _to) external payable onlyOwner inState(State.MainsaleActive) {
        require(msg.value == PRICE, "Incorrect ether sent");
        // Logic for minting NFT to specific address
        emit Transfer(address(0), _to, nextTokenId);
    }

    function withdrawFunds() external onlyOwner inState(State.MainsaleInactive) {
        uint amount = address(this).balance;
        payable(msg.sender).transfer(amount);
        emit WithdrawalEvent(msg.sender, amount);
    }

    function emergencyWithdraw() external inState(State.MainsaleInactive) {
        // Logic for emergency withdrawal
        state = State.EmergencyState;
    }

    function resolveEmergency() external onlyOwner inState(State.EmergencyState) {
        // Logic to resolve emergency
        state = State.MainsaleInactive;
    }
}

