contract DegenDwarfNFT {
    uint public maxSupply = 10000;
    uint public mintPrice = 0.05 ether;
    uint public whitelistStart = 1633036800;
    mapping(address => bool) private _whitelist;
    uint public totalMinted;

    enum State { WhitelistMintingActive, PublicMintingActive, MintingFinalized }
    State public currentState;

    event ClaimNFT(address indexed user, uint amount);
    event MaxSupplyReached();

    constructor() {
        currentState = State.WhitelistMintingActive;
    }

    modifier onlyWhitelisted() {
        require(_whitelist[msg.sender], "Not whitelisted");
        _;
    }

    modifier onlyWhileMintingActive() {
        require(currentState != State.MintingFinalized, "Minting has been finalized");
        _;
    }

    function claim() external payable onlyWhileMintingActive {
        require(msg.value >= mintPrice, "Insufficient funds to claim NFT");

        if (currentState == State.WhitelistMintingActive) {
            require(_whitelist[msg.sender], "Not whitelisted for minting");
        } else if (currentState == State.PublicMintingActive) {
            require(totalMinted < maxSupply, "Max supply reached");
        }

        totalMinted++;
        emit ClaimNFT(msg.sender, 1);

        if (totalMinted >= maxSupply) {
            currentState = State.MintingFinalized;
            emit MaxSupplyReached();
        }
    }

    function addWhitelist(address user) external {
        _whitelist[user] = true;
    }

    function addDiscounts(address user) external {
        // Add logic for discounts
    }

    function discount() external {
        // Add logic for applying discounts
    }

    function finalizeMinting() external {
        currentState = State.MintingFinalized;
    }
}

