    enum State { SaleInactive, SaleActive, MintingComplete }
    State public currentState = State.SaleInactive;

    modifier onlyOwner() {
        // Placeholder for owner check
        require(msg.sender == address(this), "Not the owner");
        _;
    }

    modifier onlyDuringSale() {
        require(saleIsActive, "Sale is not active");
        _;
    }

    function switchSaleIsActive() public onlyOwner {
        saleIsActive = !saleIsActive;

        if (saleIsActive) {
            currentState = State.SaleActive;
        } else {
            currentState = State.SaleInactive;
        }
    }

    function mintSergsTo(uint amount) public payable onlyDuringSale {
        require(msg.value >= sergPrice * amount, "Insufficient ETH sent");
        require(amount <= MAX_PURCHASE, "Exceeds maximum purchase limit");

        // Logic to mint tokens would go here
        emit SergMinted(msg.sender, amount);

        currentState = State.MintingComplete;
    }

    function resetMinting() public onlyOwner {
        require(currentState == State.MintingComplete, "Minting is not complete");
        currentState = State.SaleActive;
    }

    function migrate(address to, uint amount) public {
        // Logic to migrate tokens would go here
        emit SergMigrated(msg.sender, to, amount);
    }
}

