        admin = _admin;
    }

    function addTimeDeposit(uint _time) external {
        require(currentState == State.DepositManagement, "Invalid state");
        timeDepositPerAddress[msg.sender] = _time;
    }

    function addAmountDeposit(uint _amount) external {
        require(currentState == State.DepositManagement, "Invalid state");
        amountDepositPerAddress[msg.sender] += _amount;
        emit DepositAdded(msg.sender, _amount);
    }

    function mint(address to, uint amount) internal {
        // Implementation of minting logic here
    }

    function burn(address from, uint amount) internal {
        // Implementation of burning logic here
    }

    function CheckWithdrawalRequest() internal {
        // Logic to check withdrawal conditions
        bool approved = true; // Placeholder for condition check
        emit WithdrawalRequested(msg.sender, approved);

        if (approved) {
            currentState = State.WithdrawalProcessing;
            burn(msg.sender, amountDepositPerAddress[msg.sender]);
            amountDepositPerAddress[msg.sender] = 0; // Reset after withdrawal
            currentState = State.DepositManagement; // Transition back
        } else {
            currentState = State.DepositManagement; // Transition back
        }
    }

    function requestWithdrawal() external {
