pragma solidity ^0.8.4;

contract SimplyShibas {
    uint public TOTAL_SUPPLY;
    uint public price;
    bool public is_locked;
    string private _baseTokenURI;

    enum State { SaleActive, SaleLocked, TokensMinted }
    State public currentState;

    event TokenMinted(address to, uint tokenId);
    event TokenGifted(address to, uint tokenId);
    event SaleStateChanged(State newState);
    event FundsWithdrawn(address to, uint amount);

    constructor(uint initialPrice, string memory baseTokenURI) {
        price = initialPrice;
        _baseTokenURI = baseTokenURI;
        currentState = State.SaleActive;
        TOTAL_SUPPLY = 0;
        is_locked = false;
    }

    modifier onlyWhenActive() {
        require(currentState == State.SaleActive, "Sale is not active.");
        _;
    }

    modifier onlyWhenLocked() {
        require(currentState == State.SaleLocked, "Sale is not locked.");
        _;
    }

    function mint() external payable onlyWhenActive {
        require(msg.value >= price, "Insufficient payment.");
        require(TOTAL_SUPPLY < 10000, "Max supply reached.");

        // Minting logic here (for demonstration purposes, we'll just increment TOTAL_SUPPLY)
        TOTAL_SUPPLY += 1;
        emit TokenMinted(msg.sender, TOTAL_SUPPLY);
    }

    function gift(address to) external onlyWhenActive {
        // Gifting logic here (for demonstration purposes)
        TOTAL_SUPPLY += 1;
        emit TokenGifted(to, TOTAL_SUPPLY);
    }

    function setLocked(bool locked) external {
        is_locked = locked;
        if (locked) {
            currentState = State.SaleLocked;
        } else {
            currentState = State.SaleActive;
        }
        emit SaleStateChanged(currentState);
    }

    function setMaxSupply(uint newSupply) external onlyWhenLocked {
        // Set maximum supply logic here (update logic as needed)
    }

    function setPrice(uint newPrice) external onlyWhenLocked {
        price = newPrice;
    }

    function withdraw() external {
        uint amount = address(this).balance;
        payable(msg.sender).transfer(amount);
        emit FundsWithdrawn(msg.sender, amount);
    }
}

