        _;
    }

    modifier isNamingAllowed() {
        require(saleState == SaleState.NamingAllowed, "Naming is not allowed");
        _;
    }

    function actionToggleSale() external onlyOwner {
        if (saleState == SaleState.Inactive) {
            saleState = SaleState.Active;
        } else {
            saleState = SaleState.Inactive;
        }
        emit SaleStateChanged(saleState);
    }

    function actionToggleNaming() external onlyOwner {
        if (saleState == SaleState.Active) {
            saleState = SaleState.NamingAllowed;
        } else if (saleState == SaleState.NamingAllowed) {
            saleState = SaleState.Active;
        }
        emit SaleStateChanged(saleState);
    }

    function actionBuyPizza() external payable isSaleActive {
        require(msg.value >= mintPrice, "Insufficient funds");
        require(totalSupply < supplyLimit, "Supply limit reached");

        totalSupply += 1;
        emit PizzaMinted(msg.sender, 1);
