// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

contract ETHDonuts {
    enum State { MintingClosed, MintingOpen, AssetsMinted }
    State public currentState = State.MintingClosed;

    struct AssetMetadata {
        string name;
        string metadata;
    }

    AssetMetadata[] public assets;
    mapping(uint256 => address) public assetToOwner;
    mapping(address => uint256) public ownerAssetCount;

    event NewAsset(uint256 indexed assetId, address indexed owner);
    event Approval(address indexed owner, address indexed approved, uint256 indexed tokenId);

    address public owner;
    mapping(address => bool) public teamMembers;

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    modifier onlyTeamMember() {
        require(teamMembers[msg.sender], "Not a team member");
        _;
    }

    modifier isPublicEligible() {
        // Add your public eligibility condition
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function openMinting() external onlyOwner {
        currentState = State.MintingOpen;
    }

    function mintForTeam(string memory _name, string memory _metadata) external onlyTeamMember {
        require(currentState == State.MintingOpen, "Minting is not open");
        uint256 assetId = assets.length;
        assets.push(AssetMetadata(_name, _metadata));
        assetToOwner[assetId] = msg.sender;
        ownerAssetCount[msg.sender]++;
        emit NewAsset(assetId, msg.sender);
    }

    function mintForPublic(string memory _name, string memory _metadata) external isPublicEligible {
        require(currentState == State.MintingOpen, "Minting is not open");
        uint256 assetId = assets.length;
        assets.push(AssetMetadata(_name, _metadata));
        assetToOwner[assetId] = msg.sender;
        ownerAssetCount[msg.sender]++;
        emit NewAsset(assetId, msg.sender);
        currentState = State.AssetsMinted;
    }

    function transferAsset(address _to, uint256 _assetId) external {
        require(assetToOwner[_assetId] == msg.sender, "Not the asset owner");
        assetToOwner[_assetId] = _to;
        ownerAssetCount[msg.sender]--;
        ownerAssetCount[_to]++;
    }

    function approveAssetTransfer(address _approved, uint256 _assetId) external {
        require(assetToOwner[_assetId] == msg.sender, "Not the asset owner");
        emit Approval(msg.sender, _approved, _assetId);
    }

    function addTeamMember(address _member) external onlyOwner {
        teamMembers[_member] = true;
    }
}

