// SPDX-License-Identifier: MIT
pragma solidity ^0.8.7;

contract NFTMintingContract {
    string public baseURI;
    uint public cost;
    uint public maxSupply = 10000;
    uint public maxMintAmount = 5;
    bool public paused = true;
    bool public revealed = false;
    address public owner;
    uint public totalSupply;

    event NFTMinted(address indexed to, uint256 tokenId);
    event MetadataRevealed(string baseURI);

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the contract owner");
        _;
    }

    modifier whenNotPaused() {
        require(!paused, "Contract is paused");
        _;
    }

    constructor() {
        owner = msg.sender;
    }

    function actionUnpause() external onlyOwner {
        paused = false;
    }

    function actionMintNFT(uint256 amount) external payable whenNotPaused {
        require(amount > 0 && amount <= maxMintAmount, "Invalid mint amount");
        require(msg.value >= cost * amount, "Insufficient funds");
        require(totalSupply + amount <= maxSupply, "Max supply exceeded");

        for (uint256 i = 0; i < amount; i++) {
            totalSupply++;
            emit NFTMinted(msg.sender, totalSupply);
        }
    }

    function actionCompleteMinting() external onlyOwner {
        // Optionally implement logic for completing minting
    }

    function actionRevealMetadata(string memory _baseURI) external onlyOwner {
        baseURI = _baseURI;
        revealed = true;
        emit MetadataRevealed(baseURI);
    }

    function setCost(uint256 _cost) external onlyOwner {
        cost = _cost;
    }

    function setBaseURI(string memory _baseURI) external onlyOwner {
        baseURI = _baseURI;
    }

    function withdraw() external onlyOwner {
        payable(owner).transfer(address(this).balance);
    }
}

